-- Poems batch 444
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-115','別張起居','錢起','唐','御定全唐诗','yuding','','[]','有別時留恨，銷魂況在今。風濤初振海，鵷鷺各辭林。',48,'御定全唐詩/json/237.json','["有別時留恨，銷魂況在今。風濤初振海，鵷鷺各辭林。", "舊國關河絕，新秋草露深。陸機嬰世網，應負故山心。"]'),
('yuding-116','郭司徒廳夜宴','錢起','唐','御定全唐诗','yuding','','[]','秋堂複夜闌，舉目盡悲端。霜堞鳥聲苦，更樓月色寒。',48,'御定全唐詩/json/237.json','["秋堂複夜闌，舉目盡悲端。霜堞鳥聲苦，更樓月色寒。", "美人深別意，鬥酒少留歡。明發將何贈，平生雙玉盤。"]'),
('yuding-117','初至京口示諸弟','錢起','唐','御定全唐诗','yuding','','[]','還家百戰後，訪故幾人存。兄弟得相見，榮枯何處論。',48,'御定全唐詩/json/237.json','["還家百戰後，訪故幾人存。兄弟得相見，榮枯何處論。", "新詩添卷軸，舊業見兒孫。點檢平生事，焉能出蓽門。"]'),
('yuding-118','月下洗藥','錢起','唐','御定全唐诗','yuding','','[]','汲井向新月，分流入眾芳。濕花低桂影，翻葉靜泉光。',48,'御定全唐詩/json/237.json','["汲井向新月，分流入眾芳。濕花低桂影，翻葉靜泉光。", "露下添餘潤，蜂驚引暗香。寄言養生客，來此共提筐。"]'),
('yuding-119','晚春永寧墅小園獨坐，寄上王相公','錢起','唐','御定全唐诗','yuding','','[]','東閣一何靜，鶯聲落日愁。夔龍暫為別，昏旦思兼秋。',48,'御定全唐詩/json/237.json','["東閣一何靜，鶯聲落日愁。夔龍暫為別，昏旦思兼秋。", "蕙草出籬外，花枝寄竹幽。上方傳雅頌，七夕讓風流。"]'),
('yuding-120','歲暇題茅茨','錢起','唐','御定全唐诗','yuding','','[]','穀口逃名客，歸來遂野心。薄田供歲酒，喬木待新禽。',48,'御定全唐詩/json/237.json','["穀口逃名客，歸來遂野心。薄田供歲酒，喬木待新禽。", "溪路春雲重，山廚夜火深。桃源應漸好，仙客許相尋。"]'),
('yuding-121','九日登玉山','錢起','唐','御定全唐诗','yuding','','[]','霞景青山上，誰知此勝遊。龍沙傳往事，菊酒對今秋。',48,'御定全唐詩/json/237.json','["霞景青山上，誰知此勝遊。龍沙傳往事，菊酒對今秋。", "步石隨雲起，題詩向水流。忘歸更有處，松下片雲幽。"]'),
('yuding-122','宴崔駙馬玉山別業','錢起','唐','御定全唐诗','yuding','','[]','金榜開青瑣，驕奢半隱淪。玉簫惟送酒，羅袖愛留賓。',48,'御定全唐詩/json/237.json','["金榜開青瑣，驕奢半隱淪。玉簫惟送酒，羅袖愛留賓。", "竹館煙催暝，梅園雪誤春。滿朝辭賦客，儘是入林人。"]'),
('yuding-123','春谷幽居','錢起','唐','御定全唐诗','yuding','','[]','黃鳥鳴園柳，新陽改舊陰。春來此幽興，宛是謝公心。',48,'御定全唐詩/json/237.json','["黃鳥鳴園柳，新陽改舊陰。春來此幽興，宛是謝公心。", "掃徑蘭芽出，添池山影深。虛名隨振鷺，安得久棲林。"]'),
('yuding-124','賦得池上雙丁香樹','錢起','唐','御定全唐诗','yuding','','[]','得地移根遠，交柯繞指柔。露香濃結桂，池影鬥蟠虯。',48,'御定全唐詩/json/237.json','["得地移根遠，交柯繞指柔。露香濃結桂，池影鬥蟠虯。", "黛葉輕筠綠，金花笑菊秋。何如南海外，雨露隔炎洲。"]'),
('yuding-125','題樊川杜相公別業','錢起','唐','御定全唐诗','yuding','','[]','數畝園林好，人知賢相家。結茅書閣儉，帶水槿籬斜。',48,'御定全唐詩/json/237.json','["數畝園林好，人知賢相家。結茅書閣儉，帶水槿籬斜。", "古樹生春蘚，新荷卷落花。聖恩加玉鉉，安得臥青霞。"]'),
('yuding-126','酬盧十一過宿','錢起','唐','御定全唐诗','yuding','','[]','乞還方未遂，日夕望雲林。況複逢青草，何妨問此心。',48,'御定全唐詩/json/237.json','["乞還方未遂，日夕望雲林。況複逢青草，何妨問此心。", "閉門公務散，枉策故情深。遙夜他鄉宿，同君梁甫吟。"]'),
('yuding-127','崔十四宅問候','錢起','唐','御定全唐诗','yuding','','[]','曉日早鶯啼，江城旅思迷。微官同寄傲，移疾阻招攜。',48,'御定全唐詩/json/237.json','["曉日早鶯啼，江城旅思迷。微官同寄傲，移疾阻招攜。", "遠水閭閻內，青山雉堞西。王孫莫久臥，春草欲萋萋。"]'),
('yuding-128','山路見梅，感而有作','錢起','唐','御定全唐诗','yuding','','[]','莫言山路僻，還被好風催。行客淒涼過，村籬冷落開。',48,'御定全唐詩/json/237.json','["莫言山路僻，還被好風催。行客淒涼過，村籬冷落開。", "晚溪寒水照，晴日數蜂來。重憶江南酒，何因把一杯。"]'),
('yuding-129','詠門上畫松，上元、王、杜三相公','錢起','唐','御定全唐诗','yuding','','[]','昔聞生澗底，今見起毫端。眾草此時沒，何人知歲寒。',48,'御定全唐詩/json/237.json','["昔聞生澗底，今見起毫端。眾草此時沒，何人知歲寒。", "豈能裨棟宇，且欲出門闌。只在丹青筆，淩雲也不難。"]'),
('yuding-130','早發東陽','錢起','唐','御定全唐诗','yuding','','[]','信風催過客，早發梅花橋。數雁起前渚，千艘爭便潮。',48,'御定全唐詩/json/237.json','["信風催過客，早發梅花橋。數雁起前渚，千艘爭便潮。", "將隨浮雲去，日惜故山遙。惆悵煙波末，佳期在碧霄。"]'),
('yuding-131','舟中寄李起居','錢起','唐','御定全唐诗','yuding','','[]','南行風景好，昏旦水皋閑。春色郢中樹，晴霞湖上山。',48,'御定全唐詩/json/237.json','["南行風景好，昏旦水皋閑。春色郢中樹，晴霞湖上山。", "去家旅帆遠，回首暮潮還。蕙草知何贈，故人雲漢間。"]'),
('yuding-132','夜雨寄寇校書','錢起','唐','御定全唐诗','yuding','','[]','秋館煙雨合，重城鐘漏深。佳期阻清夜，孤興發離心。',48,'御定全唐詩/json/237.json','["秋館煙雨合，重城鐘漏深。佳期阻清夜，孤興發離心。", "燭影出綃幕，蟲聲連素琴。此時蓬閣友，應念昔同衾。"]'),
('yuding-133','喜李侍禦拜郎官入省','錢起','唐','御定全唐诗','yuding','','[]','粉署花驄入，丹霄紫誥垂。直廬驚漏近，賜被覺霜移。',48,'御定全唐詩/json/237.json','["粉署花驄入，丹霄紫誥垂。直廬驚漏近，賜被覺霜移。", "漢主前瑤席，穰侯許鳳池。應憐後行雁，空羨上林枝。"]'),
('yuding-134','蘇端林亭對酒喜雨','錢起','唐','御定全唐诗','yuding','','[]','小雨飛林頂，浮涼入晚多。能知留客處，偏與好風過。',48,'御定全唐詩/json/237.json','["小雨飛林頂，浮涼入晚多。能知留客處，偏與好風過。", "濯錦翻紅蕊，跳珠亂碧荷。芳尊深幾許，此興可酣歌。"]'),
('yuding-135','見上林春雁翔青雲，寄楊起居、李員外','錢起','唐','御定全唐诗','yuding','','[]','上林春更好，賓雁不知歸。顧影憐青籞，傳聲入紫微。',48,'御定全唐詩/json/237.json','["上林春更好，賓雁不知歸。顧影憐青籞，傳聲入紫微。", "夜陪池鷺宿，朝出苑花飛。寧憶寒鄉侶，鸞凰一見稀。"]'),
('yuding-136','偶成','錢起','唐','御定全唐诗','yuding','','[]','含毫意不淺，微月上簾櫳。門靜吏人息，心閑囹圄空。',48,'御定全唐詩/json/237.json','["含毫意不淺，微月上簾櫳。門靜吏人息，心閑囹圄空。", "繁星入疏樹，驚鵲倦秋風。始覺牽卑劇，宵眠亦在公。"]'),
('yuding-137','漁潭值雨','錢起','唐','御定全唐诗','yuding','','[]','日入林島異，鶴鳴風草間。孤帆泊枉渚，飛雨來前山。',48,'御定全唐詩/json/237.json','["日入林島異，鶴鳴風草間。孤帆泊枉渚，飛雨來前山。", "客意念留滯，川途忽阻艱。赤亭仍數裏，夜待安流還。"]'),
('yuding-138','題蕭丞小池','錢起','唐','御定全唐诗','yuding','','[]','鶯鳴蕙草綠，朝與情人期。林沼忘言處，鴛鴻養翮時。',48,'御定全唐詩/json/237.json','["鶯鳴蕙草綠，朝與情人期。林沼忘言處，鴛鴻養翮時。", "春泉滋藥暖，晴日度花遲。此會無辭醉，良辰難再追。"]'),
('yuding-0','送集賢崔八叔承恩括圖書','錢起','唐','御定全唐诗','yuding','','[]','雨露滿儒服，天心知子虛。還勞五經笥，更訪百家書。',60,'御定全唐詩/json/238.json','["雨露滿儒服，天心知子虛。還勞五經笥，更訪百家書。", "贈別傾文苑，光華比使車。晚雲隨客散，寒樹出關疏。", "相見應朝夕，歸期在玉除。"]'),
('yuding-1','送張五員外東歸楚州','錢起','唐','御定全唐诗','yuding','','[]','纓佩不為美，人群寧免辭。杳然黃鵠去，未負白雲期。',60,'御定全唐詩/json/238.json','["纓佩不為美，人群寧免辭。杳然黃鵠去，未負白雲期。", "此別清興盡，高秋臨水時。好山枉帆僻，浪跡到家遲。", "他日詔書下，梁鴻安可追。"]'),
('yuding-2','閒居寄包何','錢起','唐','御定全唐诗','yuding','','[]','去名即棲遁，何必歸滄浪。種藥幽不淺，杜門喧自忘。',60,'御定全唐詩/json/238.json','["去名即棲遁，何必歸滄浪。種藥幽不淺，杜門喧自忘。", "林眠多曉夢，鴉散驚初陽。片雪幽雲至，回風鄰果香。", "佳期碧天末，惆悵紫蘭芳。"]'),
('yuding-3','津梁寺尋李侍禦','錢起','唐','御定全唐诗','yuding','','[]','禪林絕過客，柱史正焚香。馴鴿不猜隼，慈雲能護霜。',60,'御定全唐詩/json/238.json','["禪林絕過客，柱史正焚香。馴鴿不猜隼，慈雲能護霜。", "驄聲隔暗竹，吏事散空廊。霄漢期鴛鷺，狐狸避憲章。", "繞階春色至，屈草待君芳。"]'),
('yuding-4','山園秋晚寄杜黃裳少府','錢起','唐','御定全唐诗','yuding','','[]','惆悵佳期阻，園林秋景閑。終朝碧雲外，唯見暮禽還。',60,'御定全唐詩/json/238.json','["惆悵佳期阻，園林秋景閑。終朝碧雲外，唯見暮禽還。", "泉石思攜手，煙霞不閉關。杖藜仍把菊，對卷也看山。", "望望離心起，非君誰解顏。"]'),
('yuding-5','東溪杜野人致酒','錢起','唐','御定全唐诗','yuding','','[]','萬重雲樹下，數畝子平居。野院羅泉石，荊扉背裏閭。',60,'御定全唐詩/json/238.json','["萬重雲樹下，數畝子平居。野院羅泉石，荊扉背裏閭。", "早冬耕鑿暇，弋雁複烹魚。靜掃寒花徑，唯邀傲吏車。", "晚來留客好，小雪下山初。"]'),
('yuding-6','憶山中寄舊友','錢起','唐','御定全唐诗','yuding','','[]','數歲白雲裏，與君同采薇。樹深煙不散，溪靜鷺忘飛。',60,'御定全唐詩/json/238.json','["數歲白雲裏，與君同采薇。樹深煙不散，溪靜鷺忘飛。", "更憶東岩趣，殘陽破翠微。脫巾花下醉，洗藥月前歸。", "風景今還好，如何與世違。"]'),
('yuding-7','東皋早春寄郎四校書','錢起','唐','御定全唐诗','yuding','','[]','祿微賴學稼，歲起歸衡茅。窮達戀明主，耕桑亦近郊。',60,'御定全唐詩/json/238.json','["祿微賴學稼，歲起歸衡茅。窮達戀明主，耕桑亦近郊。", "夜來霽山雪，陽氣動林梢。蘭蕙暖初吐，春鳩鳴欲巢。", "蓬萊時入夢，知子憶貧交。"]'),
('yuding-8','玉山東溪題李叟屋壁','錢起','唐','御定全唐诗','yuding','','[]','霞景已斜照，煙溪方暝投。山家歸路僻，轍跡亂泉流。',60,'御定全唐詩/json/238.json','["霞景已斜照，煙溪方暝投。山家歸路僻，轍跡亂泉流。", "野老采薇暇，蝸廬招客幽。麏麚突荒院，鸕鵲步閑疇。", "偶此愜真性，令人輕宦遊。"]'),
('yuding-9','溫泉宮禮見','錢起','唐','御定全唐诗','yuding','','[]','新豐佳氣滿，聖主在溫泉。雲曖龍行處，山明日馭前。',60,'御定全唐詩/json/238.json','["新豐佳氣滿，聖主在溫泉。雲曖龍行處，山明日馭前。", "順風求至道，側席問遺賢。靈雪瑤墀降，晨霞彩仗懸。", "滄溟不讓水，疵賤也朝天。"]'),
('yuding-10','游襄陽泉石晚歸','錢起','唐','御定全唐诗','yuding','','[]','遊目隨山勝，回橈愛浦長。往來幽不淺，昏旦興難忘。',60,'御定全唐詩/json/238.json','["遊目隨山勝，回橈愛浦長。往來幽不淺，昏旦興難忘。", "木末看歸翼，蓮西失夕陽。人聲指閭井，野趣惜林塘。", "稍近垂楊路，菱舟擁岸香。"]'),
('yuding-11','夏日陪史郎中宴杜郎中果園','錢起','唐','御定全唐诗','yuding','','[]','何事重逢迎，春醪晚更清。林端花自老，池上月初明。',60,'御定全唐詩/json/238.json','["何事重逢迎，春醪晚更清。林端花自老，池上月初明。", "路入仙郎次，烏連柱史名。竹陰疏柰院，山翠傍蕪城。", "引滿不辭醉，風來待曙更。"]'),
('yuding-12','南溪春耕','錢起','唐','御定全唐诗','yuding','','[]','荷蓑趣南徑，戴勝鳴條枚。溪雨有餘潤，土膏寧厭開。',60,'御定全唐詩/json/238.json','["荷蓑趣南徑，戴勝鳴條枚。溪雨有餘潤，土膏寧厭開。", "溝塍落花盡，耒耜度雲回。誰道耦耕倦，仍兼勝賞催。", "日長農有暇，悔不帶經來。"]'),
('yuding-13','省試湘靈鼓瑟','錢起','唐','御定全唐诗','yuding','','[]','善鼓雲和瑟，常聞帝子靈。馮夷空自舞，楚客不堪聽。',72,'御定全唐詩/json/238.json','["善鼓雲和瑟，常聞帝子靈。馮夷空自舞，楚客不堪聽。", "苦調淒金石，清音入杳冥。蒼梧來怨慕，白芷動芳馨。", "流水傳瀟浦，悲風過洞庭。曲終人不見，江上數峰青。"]'),
('yuding-14','觀法駕自鳳翔回','錢起','唐','御定全唐诗','yuding','','[]','欃搶一掃滅，閶闔九重開。海晏鯨鯢盡，天旋日月來。',72,'御定全唐詩/json/238.json','["欃搶一掃滅，閶闔九重開。海晏鯨鯢盡，天旋日月來。", "聖情蘇品物，龍禦辟雲雷。曉漏移仙仗，朝陽出帝台。", "周慚散馬出，禹讓浚川回。欲識封人願，南山舉酒杯。"]'),
('yuding-15','題玉山村叟屋壁','錢起','唐','御定全唐诗','yuding','','[]','穀口好泉石，居人能陸沈。牛羊下山小，煙火隔雲深。',72,'御定全唐詩/json/238.json','["穀口好泉石，居人能陸沈。牛羊下山小，煙火隔雲深。", "一徑入溪色，數家連竹陰。藏虹辭晚雨，驚隼落殘禽。", "涉趣皆流目，將歸羨在林。卻思黃綬事，辜負紫芝心。"]'),
('yuding-16','縣中池竹言懷','錢起','唐','御定全唐诗','yuding','','[]','官小志已足，時清免負薪。卑棲且得地，榮耀不關身。',72,'御定全唐詩/json/238.json','["官小志已足，時清免負薪。卑棲且得地，榮耀不關身。", "自愛賞心處，叢篁流水濱。荷香度高枕，山色滿南鄰。", "道在即為樂，機忘寧厭貧。卻愁丹鳳詔，來訪漆園人。"]'),
('yuding-17','山園棲隱','錢起','唐','御定全唐诗','yuding','','[]','守靜信推分，灌園樂在茲。且忘堯舜力，甯顧尚書期。',72,'御定全唐詩/json/238.json','["守靜信推分，灌園樂在茲。且忘堯舜力，甯顧尚書期。", "晚景采蘭暇，空林散帙時。卷荷藏露滴，黃口觸蟲絲。", "三徑與囂遠，一瓢常自怡。情人半雲外，風月詎相思。"]'),
('yuding-18','送王諫議任東都居守','錢起','唐','御定全唐诗','yuding','','[]','車徒鳳掖東，去去洛陽宮。暫以青蒲隔，還看紫禁同。',72,'御定全唐詩/json/238.json','["車徒鳳掖東，去去洛陽宮。暫以青蒲隔，還看紫禁同。", "經過乘雨露，瀟灑出鴛鴻。官署名台下，雲山舊苑中。", "暮天雙闕靜，秋月九重空。且喜成周地，詩人播國風。"]'),
('yuding-19','送鄭書記','錢起','唐','御定全唐诗','yuding','','[]','決勝無遺策，辭天便請纓。出身唯殉死，報國且能兵。',72,'御定全唐詩/json/238.json','["決勝無遺策，辭天便請纓。出身唯殉死，報國且能兵。", "受命麒麟殿，參謀驃騎營。短簫催別酒，斜日駐前旌。", "義勇千夫敵，風沙萬里行。幾年丹闕下，侯印錫書生。"]'),
('yuding-20','送族侄赴任','錢起','唐','御定全唐诗','yuding','','[]','林下不成興，仲容微祿牽。客程千里遠，別念一帆懸。',72,'御定全唐詩/json/238.json','["林下不成興，仲容微祿牽。客程千里遠，別念一帆懸。", "欲歎卑棲去，其如勝趣偏。雲山深郡郭，花木淨潮田。", "坐嘯帷應下，離居月複圓。此時知小阮，相憶綠尊前。"]'),
('yuding-21','長安落第作','錢起','唐','御定全唐诗','yuding','','[]','始願今如此，前途複若何。無媒獻詞賦，生事日蹉跎。',72,'御定全唐詩/json/238.json','["始願今如此，前途複若何。無媒獻詞賦，生事日蹉跎。", "不遇張華識，空悲甯戚歌。故山歸夢遠，新歲客愁多。", "刷羽思喬木，登龍恨失波。散才非世用，回首謝雲蘿。"]'),
('yuding-22','酬長孫繹藍溪寄杏','錢起','唐','御定全唐诗','yuding','','[]','愛君藍水上，種杏近成田。拂徑清陰合，臨流彩實懸。',72,'御定全唐詩/json/238.json','["愛君藍水上，種杏近成田。拂徑清陰合，臨流彩實懸。", "清香和宿雨，佳色出晴煙。懿此傾筐贈，想知懷橘年。", "芳馨來滿袖，瓊玖願酬篇。把玩情何極，雲林若眼前。"]'),
('yuding-23','藥堂秋暮','錢起','唐','御定全唐诗','yuding','','[]','隱來未得道，歲去愧雲松。茅屋空山暮，荷衣白露濃。',72,'御定全唐詩/json/238.json','["隱來未得道，歲去愧雲松。茅屋空山暮，荷衣白露濃。", "唯憐石苔色，不染世人蹤。潭靜宜孤鶴，山深絕遠鐘。", "有時丹灶上，數點彩霞重。勉事壺公術，仙期待赤龍。"]'),
('yuding-24','哭常征君','錢起','唐','御定全唐诗','yuding','','[]','萬化一朝盡，窮泉悲此君。如何丹灶術，能誤紫芝焚。',72,'御定全唐詩/json/238.json','["萬化一朝盡，窮泉悲此君。如何丹灶術，能誤紫芝焚。", "不遂蒼生望，空留封禪文。遠年隨逝水，真氣盡浮雲。", "山閉龍蛇蟄，林寒麋鹿群。傷心載酒地，仙菊為誰熏。"]'),
('yuding-25','送鮑中丞赴太原軍營','錢起','唐','御定全唐诗','yuding','','[]','年壯才仍美，時來道易行。寵兼三獨任，威肅貳師營。',72,'御定全唐詩/json/238.json','["年壯才仍美，時來道易行。寵兼三獨任，威肅貳師營。", "將略過南仲，天心寄北京。雲旗臨塞色，龍笛出關聲。", "漢月隨霜去，邊塵計日清。漸知王事好，文武用書生。"]'),
('yuding-26','奉送劉相公江淮催轉運','錢起','唐','御定全唐诗','yuding','','[]','國用資戎事，臣勞為主憂。將征任土貢，更發濟川舟。',72,'御定全唐詩/json/238.json','["國用資戎事，臣勞為主憂。將征任土貢，更發濟川舟。", "擁傳星還去，過池鳳不留。唯高飲水節，稍淺別家愁。", "落葉淮邊雨，孤山海上秋。遙知謝公興，微月上江樓。"]'),
('yuding-27','送李秀才落第游荊楚','錢起','唐','御定全唐诗','yuding','','[]','翠羽雖成夢，遷鶯尚後群。名逃郤詵策，興發謝玄文。',72,'御定全唐詩/json/238.json','["翠羽雖成夢，遷鶯尚後群。名逃郤詵策，興發謝玄文。", "昏旦扁舟去，江山幾路分。上潮吞海日，歸雁出湖雲。", "詩思應須苦，猿聲莫厭聞。離居見新月，那得不思君。"]'),
('yuding-28','奉陪郭常侍宴滻川山池','錢起','唐','御定全唐诗','yuding','','[]','掖垣攜愛客，勝地賞年光。向竹過賓館，尋山到妓堂。',72,'御定全唐詩/json/238.json','["掖垣攜愛客，勝地賞年光。向竹過賓館，尋山到妓堂。", "歌聲掩金穀，舞態出平陽。地滿簪裾影，花添蘭麝香。", "鶯啼春未老，酒冷日猶長。安石風流事，須歸問省郎。"]'),
('yuding-29','寇中送張司馬歸洛','錢起','唐','御定全唐诗','yuding','','[]','戎狄寇周日，衣冠適洛年。客亭新驛騎，歸路舊人煙。',72,'御定全唐詩/json/238.json','["戎狄寇周日，衣冠適洛年。客亭新驛騎，歸路舊人煙。", "吾道將東矣，秋風更颯然。雲愁百戰地，樹隔兩鄉天。", "旅思蓬飄陌，驚魂雁怯弦。今朝一尊酒，莫惜醉離筵。"]'),
('yuding-30','奉和宣城張太守南亭秋夕懷友','錢起','唐','御定全唐诗','yuding','','[]','池館蟪蛄聲，梧桐秋露晴。月臨朱戟靜，河近畫樓明。',72,'御定全唐詩/json/238.json','["池館蟪蛄聲，梧桐秋露晴。月臨朱戟靜，河近畫樓明。", "卷幔浮涼入，聞鐘永夜清。片雲懸曙鬥，數雁過秋城。", "羽扇揚風暇，瑤琴悵別情。江山飛麗藻，謝脁讓前名。"]'),
('yuding-31','過山人所居因寄諸遺補','錢起','唐','御定全唐诗','yuding','','[]','空谷春雲滿，愚公晦跡深。一隨玄豹隱，幾換綠蘿陰。',72,'御定全唐詩/json/238.json','["空谷春雲滿，愚公晦跡深。一隨玄豹隱，幾換綠蘿陰。", "絕徑人稀到，芳蓀我獨尋。廚煙住峭壁，酒氣出重林。", "蝴蝶晴還舞，黃鸝晚暫吟。所思青瑣客，瑤草寄幽心。"]'),
('yuding-32','過鳴皋隱者','錢起','唐','御定全唐诗','yuding','','[]','磻石老紅鮮，征君臥幾年。飛泉出林下，一徑過崖巔。',72,'御定全唐詩/json/238.json','["磻石老紅鮮，征君臥幾年。飛泉出林下，一徑過崖巔。", "雞犬逐人靜，雲霞宜地偏。終朝數峰勝，不遠一壺前。", "仲月霽春雨，香風生藥田。丹溪不可別，瓊草色芊芊。"]'),
('yuding-33','送楊錥歸隱','錢起','唐','御定全唐诗','yuding','','[]','悔作掃門事，還吟招隱詩。今年芳草色，不失故山期。',72,'御定全唐詩/json/238.json','["悔作掃門事，還吟招隱詩。今年芳草色，不失故山期。", "遙想白雲裏，采苓春日遲。溪花藏石徑，岩翠帶茅茨。", "九轉莫飛去，三回良在茲。還嗤茂陵客，貧病老明時。"]'),
('yuding-34','酬劉起居臥病見寄','錢起','唐','御定全唐诗','yuding','','[]','承顏看彩服，不覺別丹墀。味道能忘病，過庭更學詩。',72,'御定全唐詩/json/238.json','["承顏看彩服，不覺別丹墀。味道能忘病，過庭更學詩。", "繚垣多畫戟，遠岫入書帷。竹靜攜琴處，林香讓果時。", "聲同叨眷早，交澹在年衰。更枉兼金贈，難為繼組詞。"]'),
('yuding-35','陪南省諸公宴殿中李監宅','錢起','唐','御定全唐诗','yuding','','[]','將門高勝霍，相子寵過韋。宦貴攀龍後，心傾待士時。',72,'御定全唐詩/json/238.json','["將門高勝霍，相子寵過韋。宦貴攀龍後，心傾待士時。", "壺觴開雅宴，鴛鷺眷相隨。舞退燕姬曲，歌征謝脁詩。", "晚鐘過竹靜，醉客出花遲。莫惜留餘興，良辰不可追。"]'),
('yuding-36','山齋讀書寄時校書杜叟','錢起','唐','御定全唐诗','yuding','','[]','日愛蘅茅下，閑觀山海圖。幽人自守朴，窮穀也名愚。',72,'御定全唐詩/json/238.json','["日愛蘅茅下，閑觀山海圖。幽人自守朴，窮穀也名愚。", "倒嶺和溪雨，新泉到戶樞。叢闌齊稚子，蟠木老潛夫。", "憶戴差過剡，遊仙慣入壺。濠梁時一訪，莊叟亦吾徒。"]'),
('yuding-37','晚歸藍田舊居','錢起','唐','御定全唐诗','yuding','','[]','雲卷東皋下，歸來省故蹊。泉移憐石在，林長覺原低。',72,'御定全唐詩/json/238.json','["雲卷東皋下，歸來省故蹊。泉移憐石在，林長覺原低。", "舊裏情難盡，前山賞未迷。引藤看古木，嘗酒咒春雞。", "興與時髦背，年將野老齊。才微甘引退，應得遂霞棲。"]'),
('yuding-38','寄袁州李嘉佑員外','錢起','唐','御定全唐诗','yuding','','[]','誰謂江山阻，心親夢想偏。容輝常在目，離別任經年。',72,'御定全唐詩/json/238.json','["誰謂江山阻，心親夢想偏。容輝常在目，離別任經年。", "郡國通流水，雲霞共遠天。行春鶯幾囀，遲客月頻圓。", "雁有歸鄉羽，人無訪戴船。願征黃霸入，相見玉階前。"]'),
('yuding-39','禁闈玩雪寄薛左丞','錢起','唐','御定全唐诗','yuding','','[]','玄雲低禁苑，飛雪滿神州。虛白生台榭，寒光入冕旒。',72,'御定全唐詩/json/238.json','["玄雲低禁苑，飛雪滿神州。虛白生台榭，寒光入冕旒。", "粉凝宮壁靜，乳結洞門幽。細繞回風轉，輕隨落羽浮。", "怒濤堆砌石，新月孕簾鉤。為報詩人道，豐年頌聖猷。"]'),
('yuding-40','春暮過石龜谷題溫處士林園','錢起','唐','御定全唐诗','yuding','','[]','隱幾無名老，何年此陸沈。丘園自得性，婚嫁不嬰心。',72,'御定全唐詩/json/238.json','["隱幾無名老，何年此陸沈。丘園自得性，婚嫁不嬰心。", "歲計因山薄，霞棲在穀深。設罝連草色，曬藥背松陰。", "觸興雲生岫，隨耕鳥下林。支頤笑來客，頭上有朝簪。"]'),
('yuding-41','宿畢侍禦宅','錢起','唐','御定全唐诗','yuding','','[]','交情頻更好，子有古人風。晤語清霜裏，平生苦節同。',72,'御定全唐詩/json/238.json','["交情頻更好，子有古人風。晤語清霜裏，平生苦節同。", "心惟二仲合，室乃一瓢空。落葉寄秋菊，愁雲低夜鴻。", "薄寒燈影外，殘漏雨聲中。明發南昌去，回看禦史驄。"]'),
('yuding-42','中書遇雨','錢起','唐','御定全唐诗','yuding','','[]','濟旱惟宸慮，為霖即上臺。雲銜七曜起，雨拂九門來。',72,'御定全唐詩/json/238.json','["濟旱惟宸慮，為霖即上臺。雲銜七曜起，雨拂九門來。", "綸閣飛絲度，龍渠激溜回。色翻池上藻，香裛鼎前杯。", "湘燕皆舒翼，沙鱗豈曝腮。尺波應萬假，虞海載沿洄。"]'),
('yuding-43','適楚次徐城','錢起','唐','御定全唐诗','yuding','','[]','去家隨旅雁，幾日到南荊。行邁改鄉邑，苦辛淹晦明。',72,'御定全唐詩/json/238.json','["去家隨旅雁，幾日到南荊。行邁改鄉邑，苦辛淹晦明。", "畏途在淫雨，未暮息趨程。窮木對秋館，寒鴉愁古城。", "迷津坐為客，對酒默含情。感激念知己，匣中孤劍鳴。"]'),
('yuding-44','經李蒙潁陽舊居','錢起','唐','御定全唐诗','yuding','','[]','同心而早世，天道亦何論。獨有山陽宅，平生永不諼。',72,'御定全唐詩/json/238.json','["同心而早世，天道亦何論。獨有山陽宅，平生永不諼。", "青溪引白鳥，流涕吊芳蓀。蔓草入空室，叢篁深毀垣。", "舊遊還在眼，神理更忘言。唯見東山月，人亡不去門。"]'),
('yuding-45','贈漢陽隱者','錢起','唐','御定全唐诗','yuding','','[]','當年不出世，知子餐霞人。樂道複安土，遺榮長隱身。',72,'御定全唐詩/json/238.json','["當年不出世，知子餐霞人。樂道複安土，遺榮長隱身。", "衡茅古林曲，粳稻清江濱。桂棹為漁暇，荷衣禦暑新。", "款顏行在役，幽興惜今晨。分首天涯去，再來芳杜春。"]'),
('yuding-46','巨魚縱大壑','錢起','唐','御定全唐诗','yuding','','[]','巨魚縱大壑，遂性似乘時。奮躍風生鬣，騰淩浪鼓鰭。',72,'御定全唐詩/json/238.json','["巨魚縱大壑，遂性似乘時。奮躍風生鬣，騰淩浪鼓鰭。", "龍攄回地軸，鯤化想天池。方快吞舟意，尤殊在藻嬉。", "傾危嗟幕燕，隱晦誚泥龜。喻士逢明主，才猷得所施。"]'),
('yuding-47','送李九歸河北','錢起','唐','御定全唐诗','yuding','','[]','文武資人望，謀猷簡聖情。南州初臥鼓，東土複維城。',72,'御定全唐詩/json/238.json','["文武資人望，謀猷簡聖情。南州初臥鼓，東土複維城。", "寄重分符去，威仍出閫行。鬥牛移八座，日月送雙旌。", "別戀瞻天起，仁風應物生。佇聞收組練，鏘玉會承明。"]'),
('yuding-48','送丁著作佐台郡','錢起','唐','御定全唐诗','yuding','','[]','多年金馬客，名遂動歸輪。佐郡紫書下，過門朱綬新。',72,'御定全唐詩/json/238.json','["多年金馬客，名遂動歸輪。佐郡紫書下，過門朱綬新。", "揚舲望海嶽，入境背風塵。水驛偏乘月，梅園別受春。", "帶經臨府吏，鱠鯉待鄉人。始見美高士，逍遙在搢紳。"]'),
('yuding-49','送王使君赴太原行營','錢起','唐','御定全唐诗','yuding','','[]','太白明無象，皇威未戢戈。諸侯持節鉞，千里控山河。',72,'御定全唐詩/json/238.json','["太白明無象，皇威未戢戈。諸侯持節鉞，千里控山河。", "漢驛雙旌度，胡沙七騎過。驚蓬連雁起，牧馬入雲多。", "不賣盧龍塞，能消瀚海波。須傳出師頌，莫奏式微歌。"]'),
('yuding-50','送王使君移鎮淮南','錢起','唐','御定全唐诗','yuding','','[]','共許徐方牧，能臨河內人。郡移棠轉茂，車至鹿還馴。',72,'御定全唐詩/json/238.json','["共許徐方牧，能臨河內人。郡移棠轉茂，車至鹿還馴。", "吏事嘉師旅，鴛行惜搢紳。別心傾祖席，愁望盡征輪。", "紫誥征黃晚，蒼生借寇頻。願言青瑣拜，早及上林春。"]'),
('yuding-51','李四勸為尉氏尉，李七勉為開封尉','錢起','唐','御定全唐诗','yuding','','[]','美政惟兄弟，時人數俊賢。皇枝雙玉樹，吏道二梅仙。',72,'御定全唐詩/json/238.json','["美政惟兄弟，時人數俊賢。皇枝雙玉樹，吏道二梅仙。", "自理堯唐俗，唯將禮讓傳。采蘭花萼聚，就日雁行聯。", "黃綬俄三載，青雲未九遷。廟堂為宰製，幾日試龍泉。"]'),
('yuding-52','春夜宴任六昆季宅','錢起','唐','御定全唐诗','yuding','','[]','際晚綠煙起，入門芳樹深。不才叨下客，喜宴齒諸簪。',72,'御定全唐詩/json/238.json','["際晚綠煙起，入門芳樹深。不才叨下客，喜宴齒諸簪。", "夜月仍攜妓，清風更在林。彩毫揮露色，銀燭動花陰。", "自接通家好，應知待士心。向隅逢故識，茲夕願披襟。"]'),
('yuding-53','閒居酬張起居見贈','錢起','唐','御定全唐诗','yuding','','[]','在林非避世，守拙自離群。弱羽謝風水，窮愁依典墳。',72,'御定全唐詩/json/238.json','["在林非避世，守拙自離群。弱羽謝風水，窮愁依典墳。", "良知不遐棄，新詠獨相聞。能使幽興苦，坐忘清景曛。", "前山帶喬木，暮鳥聯歸雲。向夕野人思，難忘騎省文。"]'),
('yuding-54','奉和王相公秋日戲贈元校書','錢起','唐','御定全唐诗','yuding','','[]','才妙心仍遠，名疏跡可追。清秋聞禮暇，新雨到山時。',72,'御定全唐詩/json/238.json','["才妙心仍遠，名疏跡可追。清秋聞禮暇，新雨到山時。", "勝事唯愁盡，幽尋不厭遲。弄雲憐鶴去，隔水許僧期。", "賢相敦高躅，雕龍憶所思。芙蓉洗清露，願比謝公詩。"]'),
('yuding-55','過楊駙馬亭子','錢起','唐','御定全唐诗','yuding','','[]','衣冠在漢庭，台榭接天成。彩鳳翻簫曲，祥鱣入館名。',72,'御定全唐詩/json/238.json','["衣冠在漢庭，台榭接天成。彩鳳翻簫曲，祥鱣入館名。", "歌鐘芳月曙，林嶂碧雲生。亂水歸潭淨，高花映竹明。", "退朝追宴樂，開閣醉簪纓。長袖留嘉客，棲烏下禁城。"]'),
('yuding-56','山下別杜少府','錢起','唐','御定全唐诗','yuding','','[]','把手意難盡，前山日漸低。情人那忍別，宿鳥尚同棲。',72,'御定全唐詩/json/238.json','["把手意難盡，前山日漸低。情人那忍別，宿鳥尚同棲。", "寸晷戀言笑，佳期欲阻暌。離雲愁出岫，去水咽分溪。", "莊叟幾虛說，楊朱空自迷。傷心獨歸路，秋草更萋萋。"]'),
('yuding-57','晚出青門望終南別業','錢起','唐','御定全唐诗','yuding','','[]','能清謝脁思，暫下承明廬。遠山新水下，寒皋微雨餘。',72,'御定全唐詩/json/238.json','["能清謝脁思，暫下承明廬。遠山新水下，寒皋微雨餘。", "更憐歸鳥去，宛到臥龍居。笑指叢林上，閑雲自卷舒。", "寧心鳴鳳日，卻意釣璜初。處貴有餘興，伊周位不如。"]'),
('yuding-58','送嚴士良侍奉詹事南游','錢起','唐','御定全唐诗','yuding','','[]','疏傅獨知止，曾參善愛親。江山侍行邁，長幼出囂塵。',84,'御定全唐詩/json/238.json','["疏傅獨知止，曾參善愛親。江山侍行邁，長幼出囂塵。", "握手想千古，此心能幾人。風光滿長陌，草色傍征輪。", "日夕望荊楚，鶯鳴芳杜新。漁煙月下淺，花嶼水中春。", "點翰遙相憶，含情向白蘋。"]'),
('yuding-59','題秘書王迪城北池亭','錢起','唐','御定全唐诗','yuding','','[]','子喬來魏闕，明主賜衣簪。從宦辭人事，同塵即道心。',84,'御定全唐詩/json/238.json','["子喬來魏闕，明主賜衣簪。從宦辭人事，同塵即道心。", "還追大隱跡，寄此鳳城陰。昨夜新煙雨，池台清且深。", "伏泉通粉壁，迸筍出花林。晚沐常多暇，春醪時獨斟。", "西南漢宮月，複對綠窗琴。"]'),
('yuding-60','過王舍人宅','錢起','唐','御定全唐诗','yuding','','[]','入門花柳暗，知是近臣居。大隱心何遠，高風物自疏。',84,'御定全唐詩/json/238.json','["入門花柳暗，知是近臣居。大隱心何遠，高風物自疏。", "翛然靜者事，宛得上皇餘。雞犬偷仙藥，兒童授道書。", "清吟送客後，微月上城初。彩筆有新詠，文星垂太虛。", "承恩金殿宿，應薦馬相如。"]'),
('yuding-61','過瑞龍觀道士','錢起','唐','御定全唐诗','yuding','','[]','不知誰氏子，煉魄家洞天。鶴待成丹日，人尋種杏田。',84,'御定全唐詩/json/238.json','["不知誰氏子，煉魄家洞天。鶴待成丹日，人尋種杏田。", "靈山含道氣，物性皆自然。白鹿顧瑞草，驪龍蟠玉泉。", "得茲象外趣，便割區中緣。石竇采雲母，霞堂陪列仙。", "主人善止客，柯爛忘歸年。"]'),
('yuding-62','送沈仲','錢起','唐','御定全唐诗','yuding','','[]','天樸非外假，至人常晏如。心期邈霄漢，詞律響瓊琚。',84,'御定全唐詩/json/238.json','["天樸非外假，至人常晏如。心期邈霄漢，詞律響瓊琚。", "舉酒常歎息，無人達子虛。夜光失隋掌，驥騄伏鹽車。", "考室晉山下，歸田秦歲初。寒雲隨路合，落照下城餘。", "千里還同術，無勞怨索居。"]'),
('yuding-63','和韋侍禦寓直對雨','錢起','唐','御定全唐诗','yuding','','[]','名貴四科首，班宜二妙齊。如何厭白簡，未得步金閨。',84,'御定全唐詩/json/238.json','["名貴四科首，班宜二妙齊。如何厭白簡，未得步金閨。", "寓直晦秋雨，吟餘聞遠雞。漏聲過旦冷，雲色向窗低。", "誰謂霄漢近，翻嗟心事暌。蘭滋人未握，霜曉鶚還棲。", "佇見田郎字，親勞御筆題。"]'),
('yuding-64','奉和聖制登朝元閣','錢起','唐','御定全唐诗','yuding','','[]','六合紆玄覽，重軒啟上清。石林飛棟出，霞頂泰階平。',96,'御定全唐詩/json/238.json','["六合紆玄覽，重軒啟上清。石林飛棟出，霞頂泰階平。", "拂曙鑾輿上，晞陽瑞雪晴。翠微回日馭，丹巘駐天行。", "禦氣升銀漢，垂衣俯錦城。山通玉苑迥，河抱紫關明。", "感物幹文動，凝神道化成。周王陟喬嶽，列辟讓英聲。"]'),
('yuding-65','奉和杜相公移長興宅，奉呈元相公','錢起','唐','御定全唐诗','yuding','','[]','守貴常思儉，平津此意深。能卑丞相宅，何謝故人心。',96,'御定全唐詩/json/238.json','["守貴常思儉，平津此意深。能卑丞相宅，何謝故人心。", "種蕙初抽帶，移篁不改陰。院梅朝助鼎，池鳳夕歸林。", "覺路經中得，滄洲夢裏尋。道高仍濟代，恩重豈投簪。", "報國誰知己，推賢共作霖。興來文雅振，清韻擲雙金。"]'),
('yuding-66','送任先生任唐山丞','錢起','唐','御定全唐诗','yuding','','[]','再命果良願，幾年勤說詩。上公頻握發，才子共垂帷。',96,'御定全唐詩/json/238.json','["再命果良願，幾年勤說詩。上公頻握發，才子共垂帷。", "琢玉成良器，出門偏愴離。腰章佐墨綬，耀錦到茅茨。", "樹老見家日，潮平歸縣時。衣催蓮女織，頌聽海人詞。", "鴻鵠志應在，荃蘭香未衰。金門定回音，雲路有佳期。"]'),
('yuding-67','送外甥懷素上人歸鄉侍奉','錢起','唐','御定全唐诗','yuding','','[]','釋子吾家寶，神清慧有餘。能翻梵王字，妙盡伯英書。',96,'御定全唐詩/json/238.json','["釋子吾家寶，神清慧有餘。能翻梵王字，妙盡伯英書。", "遠鶴無前侶，孤雲寄太虛。狂來輕世界，醉裏得真如。", "飛錫離鄉久，寧親喜臘初。故池殘雪滿，寒柳霽煙疏。", "壽酒還嘗藥，晨餐不薦魚。遙知禪誦外，健筆賦閒居。"]'),
('yuding-68','送張中丞赴桂州','錢起','唐','御定全唐诗','yuding','','[]','出守求人瘼，推賢動聖情。紫台初下詔，皂蓋始專城。',96,'御定全唐詩/json/238.json','["出守求人瘼，推賢動聖情。紫台初下詔，皂蓋始專城。", "寵借飛霜簡，威加卻月營。雲衢降五馬，林木引雙旌。", "夙仰敦詩禮，嘗聞偃甲兵。戍樓雲外靜，訟閣竹間清。", "化佇還珠美，心將片玉貞。寇恂朝望重，計日謁承明。"]'),
('yuding-69','送王相公赴范陽','錢起','唐','御定全唐诗','yuding','','[]','翊聖銜恩重，頻年按節行。安危皆報國，文武不緣名。',96,'御定全唐詩/json/238.json','["翊聖銜恩重，頻年按節行。安危皆報國，文武不緣名。", "受脤仍調鼎，為霖更洗兵。幕開丞相閣，旗總貳師營。", "料敵知無戰，安邊示有征。代雲橫馬首，燕雁拂笳聲。", "去鎮關河靜，歸看日月明。欲知瞻戀切，遲暮一書生。"]'),
('yuding-70','送蔣尚書居守東都','錢起','唐','御定全唐诗','yuding','','[]','鳳輦幸秦久，周人徯帝情。若非君敏德，誰鎮洛陽城。',96,'御定全唐詩/json/238.json','["鳳輦幸秦久，周人徯帝情。若非君敏德，誰鎮洛陽城。", "前席命才彥，舉朝推令名。綸言動北斗，職事守東京。", "鄭履下天去，蘧輪滿路聲。出關秋樹直，對闕遠山明。", "肅肅保厘處，水流宮苑清。長安日西笑，朝夕袞衣迎。"]'),
('yuding-71','送李兵曹赴河中','錢起','唐','御定全唐诗','yuding','','[]','能荷鐘鼎業，不矜紈綺榮。侯門三事後，儒服一書生。',96,'御定全唐詩/json/238.json','["能荷鐘鼎業，不矜紈綺榮。侯門三事後，儒服一書生。", "昔志學文史，立身為士英。驪珠難隱耀，皋鶴會長鳴。", "休命且隨牒，候時常振纓。寒蟬思關柳，匹馬向蒲城。", "秋日黯將暮，黃河如欲清。黎人思坐嘯，知子樹佳聲。"]'),
('yuding-72','罷官後酬元校書見贈','錢起','唐','御定全唐诗','yuding','','[]','心期悵已阻，交道複何如。自我辭丹闕，惟君到故廬。',96,'御定全唐詩/json/238.json','["心期悵已阻，交道複何如。自我辭丹闕，惟君到故廬。", "忘機貧負米，憶戴出無車。憐犬吠初服，家人愁鬥儲。", "秋堂入閑夜，雲月思離居。窮巷聞砧冷，荒枝應鵲疏。", "宦名隨落葉，生事感枯魚。臨水仍揮手，知音未棄余。"]'),
('yuding-73','同鄔戴關中旅寓','錢起','唐','御定全唐诗','yuding','','[]','文士皆求遇，今人誰至公。靈台一寄宿，楊柳再春風。',96,'御定全唐詩/json/238.json','["文士皆求遇，今人誰至公。靈台一寄宿，楊柳再春風。", "更惜忘形友，頻年失志同。羽毛齊燕雀，心事阻鴛鴻。", "留滯慚歸養，飛鳴恨觸籠。橘懷鄉夢裏，書去客愁中。", "殘雪迷歸雁，韶光棄斷蓬。吞悲問唐舉，何路出屯蒙。"]'),
('yuding-74','新豐主人','錢起','唐','御定全唐诗','yuding','','[]','明代少知己，夜光頻暗投。迍邅終薄命，動息盡窮愁。',96,'御定全唐詩/json/238.json','["明代少知己，夜光頻暗投。迍邅終薄命，動息盡窮愁。", "自欲歸飛鷁，當為不系舟。雙垂素絲淚，幾弊皂貂裘。", "暮鳥棲幽樹，孤雲出舊丘。蛩悲衣褐夕，雨暗轉蓬秋。", "客裏馮諼劍，歌中甯戚牛。主人能縱酒，一醉且忘憂。"]'),
('yuding-75','夕游覆釜山道士觀因登玄元廟','錢起','唐','御定全唐诗','yuding','','[]','冥搜過物表，洞府次溪傍。已入瀛洲遠，誰言仙路長。',96,'御定全唐詩/json/238.json','["冥搜過物表，洞府次溪傍。已入瀛洲遠，誰言仙路長。", "孤煙出深竹，道侶正焚香。鳴磬愛山靜，步虛宜夜涼。", "仍同象帝廟，更上紫霞岡。霽月懸琪樹，明星映碧堂。", "傾思丹灶術，願采玉芝芳。儻把浮丘袂，乘雲別舊鄉。"]'),
('yuding-76','陪郭常侍令公東亭宴集','錢起','唐','御定全唐诗','yuding','','[]','盛業山河列，重名劍履榮。珥貂為相子，開閣引時英。',96,'御定全唐詩/json/238.json','["盛業山河列，重名劍履榮。珥貂為相子，開閣引時英。", "美景池台色，佳期宴賞情。詞人載筆至，仙妓出花迎。", "暗竹朱輪轉，回塘玉佩鳴。舞衫招戲蝶，歌扇隔啼鶯。", "飲德心皆醉，披雲興轉清。不愁歡樂盡，積慶在和羹。"]'),
('yuding-77','太子李舍人城東別業與二三文友逃暑','錢起','唐','御定全唐诗','yuding','','[]','下馬失炎暑，重門深綠篁。宮臣禮嘉客，林表開蘭堂。',96,'御定全唐詩/json/238.json','["下馬失炎暑，重門深綠篁。宮臣禮嘉客，林表開蘭堂。", "茲夕興難盡，澄罍照墨場。鮮風吹印綬，密坐皆馨香。", "美景惜文會，清吟遲羽觴。東林晚來好，目極趣何長。", "鳥道掛疏雨，人家殘夕陽。城隅擁歸騎，留醉戀瓊芳。"]'),
('yuding-78','柏崖老人號無名先生男削髮女黃冠自以雲泉獨樂命予賦詩','錢起','唐','御定全唐诗','yuding','','[]','古也憂婚嫁，君能樂性腸。長男棲月宇，少女炫霓裳。',96,'御定全唐詩/json/238.json','["古也憂婚嫁，君能樂性腸。長男棲月宇，少女炫霓裳。", "問爾餐霞處，春山芝桂旁。鶴前飛九轉，壺裏駐三光。", "與我開龍嶠，披雲靜藥堂。胡麻兼藻綠，石髓隔花香。", "帝力言何有，椿年喜漸長。窅然高象外，寧不傲羲皇。"]'),
('yuding-79','贈李十六','錢起','唐','御定全唐诗','yuding','','[]','半面喜投分，數年欽盛名。常思夢顏色，誰憶訪柴荊。',96,'御定全唐詩/json/238.json','["半面喜投分，數年欽盛名。常思夢顏色，誰憶訪柴荊。", "忽聽款扉響，欣然倒屣迎。蓬蒿駐騶馭，雞犬傍簪纓。", "酌水即嘉宴，新知甚故情。僕夫視日色，棲鳥催車聲。", "自爾宴言後，至今門館清。何當更乘興，林下已苔生。"]'),
('yuding-80','裴僕射東亭','錢起','唐','御定全唐诗','yuding','','[]','鳳扆任匡濟，雲溪難退還。致君超列辟，得道在榮班。',108,'御定全唐詩/json/238.json','["鳳扆任匡濟，雲溪難退還。致君超列辟，得道在榮班。", "朱戟繚垣下，高齋芳樹間。隔花開遠水，廢卷愛晴山。", "晚沐值清興，知音同解顏。藉蘭開賜酒，留客下重關。", "仙犬逐人靜，朝車映竹閑。則知真隱逸，未必謝區寰。", "軒後三朝顧，赤松何足攀。"]'),
('yuding-81','中書王舍人輞川舊居','錢起','唐','御定全唐诗','yuding','','[]','幾年家絕壑，滿徑種芳蘭。帶石買松貴，通溪漲水寬。',120,'御定全唐詩/json/238.json','["幾年家絕壑，滿徑種芳蘭。帶石買松貴，通溪漲水寬。", "誦經連穀響，吹律減雲寒。誰謂桃源裏，天書問考盤。", "一從解蕙帶，三入偶蟬冠。今夕複何夕，歸休尋舊歡。", "片雲隔蒼翠，春雨半林湍。藤長穿松蓋，花繁壓藥欄。", "景深青眼下，興絕彩毫端。笑向同來客，登龍此地難。"]'),
('yuding-82','送襄陽盧判官奏開河事','錢起','唐','御定全唐诗','yuding','','[]','千里趨魏闕，一言簡聖聰。河流引關外，國用贍秦中。',120,'御定全唐詩/json/238.json','["千里趨魏闕，一言簡聖聰。河流引關外，國用贍秦中。", "有詔許其策，隨山興此功。連雲積石阻，計日安波通。", "飛棹轉年穀，利人勝歲豐。言歸漢陽路，拜手蓬萊宮。", "紫殿賜衣出，青門酣酌同。晚陽過微雨，秋水見新鴻。", "坐惜去車遠，愁看離館空。因思郢川守，南楚滿清風。"]'),
('yuding-83','奉送戶部李郎中充晉國副節度出塞','錢起','唐','御定全唐诗','yuding','','[]','德佐調梅用，忠輸擊虜年。子房推廟略，漢主托兵權。',144,'御定全唐詩/json/238.json','["德佐調梅用，忠輸擊虜年。子房推廟略，漢主托兵權。", "受命榮中禁，分麾鎮左賢。風生黑山道，星下紫微天。", "始願文經國，俄看武定邊。鬼方堯日遠，幕府代雲連。", "汗馬將行矣，盧龍已肅然。關防驅使節，花月眷離筵。", "自忝知音遇，而今感義偏。淚聞橫吹落，心逐去旌懸。", "帝念夔能政，時須說濟川。勞還應即爾，朝暮玉墀前。"]'),
('yuding-84','奉和中書常舍人晚秋集賢院即事寄徐薛二侍禦','錢起','唐','御定全唐诗','yuding','','[]','文星垂太虛，辭伯綜群書。彩筆下鴛掖，褒衣來石渠。',144,'御定全唐詩/json/238.json','["文星垂太虛，辭伯綜群書。彩筆下鴛掖，褒衣來石渠。", "典墳探奧旨，造化睹權輿。述聖魯宣父，通經漢仲舒。", "窗明宜縹帶，地肅近丹除。清晝刪詩暇，高秋作賦初。", "露盤侵漢聳，宮柳度鴉疏。靜對連雲閣，晴聞過闕車。", "舊僚雲出矣，晚歲複何如。海嶠瞻歸路，江城夢直廬。", "含毫思兩鳳，望遠寄雙魚。定笑巴歌拙，還參麗曲餘。"]'),
('yuding-85','和范郎中宿直中書，曉玩清池，贈南省同僚兩垣遺補','錢起','唐','御定全唐诗','yuding','','[]','青瑣留才子，春池靜禁林。自矜仙島勝，宛在掖垣深。',144,'御定全唐詩/json/238.json','["青瑣留才子，春池靜禁林。自矜仙島勝，宛在掖垣深。", "引派彤庭裏，含虛玉砌陰。漲來知聖澤，清處見天心。", "蘭氣飄紅岸，文星動碧潯。鳳棲長近日，虯臥欲為霖。", "席寵雖高位，流謙乃素襟。焚香春漏盡，假寐曉鶯吟。", "丹地宜清泚，朝陽複照臨。司言兼逸趣，鼓興接知音。", "六義驚摛藻，三台響擲金。為憐風水外，落羽此漂沉。"]'),
('yuding-0','同程九早入中書','錢起','唐','御定全唐诗','yuding','','[]','漢家賢相重英奇，蟠木何材也見知。不意雲霄能自致，',40,'御定全唐詩/json/239.json','["漢家賢相重英奇，蟠木何材也見知。不意雲霄能自致，", "獨慚皇鑒明如日，未厭春光向玉墀。"]'),
('yuding-1','仲春宴王補闕城東小池','錢起','唐','御定全唐诗','yuding','','[]','王孫興至幽尋好，芳草春深景氣和。藥院愛隨流水入，',40,'御定全唐詩/json/239.json','["王孫興至幽尋好，芳草春深景氣和。藥院愛隨流水入，", "醉來倚玉無餘事，目送歸鴻笑複歌。"]'),
('yuding-2','夜宿靈台寺寄郎士元','錢起','唐','御定全唐诗','yuding','','[]','西日橫山含碧空，東方吐月滿禪宮。朝瞻雙頂青冥上，',40,'御定全唐詩/json/239.json','["西日橫山含碧空，東方吐月滿禪宮。朝瞻雙頂青冥上，", "萬里故人能尚爾，知君視聽我心同。"]'),
('yuding-3','題郎士元半日吳村別業，兼呈李長官','錢起','唐','御定全唐诗','yuding','','[]','半日吳村帶晚霞，閑門高柳亂飛鴉。橫雲嶺外千重樹，',40,'御定全唐詩/json/239.json','["半日吳村帶晚霞，閑門高柳亂飛鴉。橫雲嶺外千重樹，", "自歎梅生頭似雪，卻憐潘令縣如花。"]'),
('yuding-4','猷川雪後送僧粲臨還京，時避世臥疾','錢起','唐','御定全唐诗','yuding','','[]','連步青溪幾萬重，有時共立在孤峰。齋到盂空餐雪麥，',40,'御定全唐詩/json/239.json','["連步青溪幾萬重，有時共立在孤峰。齋到盂空餐雪麥，", "回望群山攜手處，離心一一涕無從。"]'),
('yuding-5','和李員外扈駕幸溫泉宮','錢起','唐','御定全唐诗','yuding','','[]','未央月曉度疏鐘，鳳輦時巡出九重。雪霽山門迎瑞日，',40,'御定全唐詩/json/239.json','["未央月曉度疏鐘，鳳輦時巡出九重。雪霽山門迎瑞日，", "遙羨枚皋扈仙蹕，偏承霄漢渥恩濃。"]'),
('yuding-6','長信怨','錢起','唐','御定全唐诗','yuding','','[]','長信螢來一葉秋，蛾眉淚盡九重幽。鳷鵲觀前明月度，',40,'御定全唐詩/json/239.json','["長信螢來一葉秋，蛾眉淚盡九重幽。鳷鵲觀前明月度，", "誰分昭陽夜歌舞，君王玉輦正淹留。"]'),
('yuding-7','送河南陸少府','錢起','唐','御定全唐诗','yuding','','[]','雲間陸生美且奇，銀章朱綬映金羈。自料抱材將致遠，',40,'御定全唐詩/json/239.json','["雲間陸生美且奇，銀章朱綬映金羈。自料抱材將致遠，", "朝夕詔書還柏署，行看飛隼集高枝。"]'),
('yuding-8','送李評事赴潭州使幕','錢起','唐','御定全唐诗','yuding','','[]','湖南遠去有餘情，蘋葉初齊白芷生。謾說簡書催物役，',40,'御定全唐詩/json/239.json','["湖南遠去有餘情，蘋葉初齊白芷生。謾說簡書催物役，", "幕下由來貴無事，佇聞談笑靜黎氓。"]'),
('yuding-9','送李九貶南陽','錢起','唐','御定全唐诗','yuding','','[]','玉柱金罍醉不歡，雲山驛道向東看，鴻聲斷續暮天遠，',40,'御定全唐詩/json/239.json','["玉柱金罍醉不歡，雲山驛道向東看，鴻聲斷續暮天遠，", "秋來回首君門阻，馬上應歌行路難。"]'),
('yuding-10','送裴頔侍禦使蜀','錢起','唐','御定全唐诗','yuding','','[]','柱史才年四十強，須髯玄發美清揚。朝天繡服乘恩貴，',40,'御定全唐詩/json/239.json','["柱史才年四十強，須髯玄發美清揚。朝天繡服乘恩貴，", "多才自有雲霄望，計日應追鴛鷺行。"]'),
('yuding-11','送韋信愛子歸覲','錢起','唐','御定全唐诗','yuding','','[]','離舟解纜到斜暉，春水東流燕北飛。才子學詩趨露冕，',40,'御定全唐詩/json/239.json','["離舟解纜到斜暉，春水東流燕北飛。才子學詩趨露冕，", "借問還珠盈合浦，何如鯉也入庭闈。"]'),
('yuding-12','送興平王少府游梁','錢起','唐','御定全唐诗','yuding','','[]','舊識相逢情更親，攀歡甚少愴離頻。黃綬罷來多遠客，',40,'御定全唐詩/json/239.json','["舊識相逢情更親，攀歡甚少愴離頻。黃綬罷來多遠客，", "梁國遺風重詞賦，諸侯應念馬卿貧。"]'),
('yuding-13','送張員外出牧岳州','錢起','唐','御定全唐诗','yuding','','[]','鳳凰銜詔與何人，喜政多才寵寇恂。臺上鴛鸞爭送遠，',40,'御定全唐詩/json/239.json','["鳳凰銜詔與何人，喜政多才寵寇恂。臺上鴛鸞爭送遠，", "應笑馮唐衰且拙，世情相見白頭新。"]'),
('yuding-14','送孫十尉溫縣','錢起','唐','御定全唐诗','yuding','','[]','飛花落絮滿河橋，千里傷心送客遙。不惜芸香染黃綬，',40,'御定全唐詩/json/239.json','["飛花落絮滿河橋，千里傷心送客遙。不惜芸香染黃綬，", "急管繁弦催一醉，頹陽不駐引征鑣。"]'),
('yuding-15','送鐘評事應宏詞下第東歸','錢起','唐','御定全唐诗','yuding','','[]','芳歲歸人嗟轉蓬，含情回首灞陵東。蛾眉不入秦台鏡，',40,'御定全唐詩/json/239.json','["芳歲歸人嗟轉蓬，含情回首灞陵東。蛾眉不入秦台鏡，", "勸君稍盡離筵酒，千里佳期難再同。"]'),
('yuding-16','送嚴維尉河南','錢起','唐','御定全唐诗','yuding','','[]','蕙葉青青花亂開，少年趨府下蓬萊。甘泉未獻揚雄賦，',40,'御定全唐詩/json/239.json','["蕙葉青青花亂開，少年趨府下蓬萊。甘泉未獻揚雄賦，", "欲知別後相思處，願植瓊枝向柏台。"]'),
('yuding-17','送馬員外拜官覲省','錢起','唐','御定全唐诗','yuding','','[]','二十為郎事漢文，鴛雛驥子自為群。筆精已許台中妙，',40,'御定全唐詩/json/239.json','["二十為郎事漢文，鴛雛驥子自為群。筆精已許台中妙，", "莫言來往朝天遠，看取鳴鞘入斷雲。"]'),
('yuding-18','送冷朝陽擢第後歸金陵覲省','錢起','唐','御定全唐诗','yuding','','[]','萊子晝歸今始好，潘園景色夏偏濃。夕陽流水吟詩去，',40,'御定全唐詩/json/239.json','["萊子晝歸今始好，潘園景色夏偏濃。夕陽流水吟詩去，", "佳期少別俄千里，雲樹愁看過幾重。"]'),
('yuding-19','九日宴浙江西亭','錢起','唐','御定全唐诗','yuding','','[]','詩人九日憐芳菊，筵客高齋宴浙江。漁浦浪花搖素壁，',40,'御定全唐詩/json/239.json','["詩人九日憐芳菊，筵客高齋宴浙江。漁浦浪花搖素壁，", "四子醉時爭講習，笑論黃霸舊為邦。"]'),
('yuding-20','和王員外雪晴早朝','錢起','唐','御定全唐诗','yuding','','[]','紫微晴雪帶恩光，繞仗偏隨鴛鷺行。長信月留寧避曉，',40,'御定全唐詩/json/239.json','["紫微晴雪帶恩光，繞仗偏隨鴛鷺行。長信月留寧避曉，", "題柱盛名兼絕唱，風流誰繼漢田郎。"]'),
('yuding-21','避暑納涼','錢起','唐','御定全唐诗','yuding','','[]','木槿花開畏日長，時搖輕扇倚繩床。初晴草蔓緣新筍，',40,'御定全唐詩/json/239.json','["木槿花開畏日長，時搖輕扇倚繩床。初晴草蔓緣新筍，", "無事始然知靜勝，深垂紗帳詠滄浪。"]'),
('yuding-22','早夏','錢起','唐','御定全唐诗','yuding','','[]','楚狂身世恨情多，似病如憂正是魔，花萼敗春多寂寞，',40,'御定全唐詩/json/239.json','["楚狂身世恨情多，似病如憂正是魔，花萼敗春多寂寞，", "軍旅閱詩裁不得，可憐風景遣如何。"]'),
('yuding-23','題嵩陽焦道士石壁','錢起','唐','御定全唐诗','yuding','','[]','三峰花畔碧堂懸，錦裏真人此得仙。玉體才飛西蜀雨，',40,'御定全唐詩/json/239.json','["三峰花畔碧堂懸，錦裏真人此得仙。玉體才飛西蜀雨，", "幸入桃源因去世，方期丹訣一延年。"]'),
('yuding-24','題延州聖僧穴','錢起','唐','御定全唐诗','yuding','','[]','定力無涯不可稱，未知何代坐禪僧。默默山門宵閉月，',40,'御定全唐詩/json/239.json','["定力無涯不可稱，未知何代坐禪僧。默默山門宵閉月，", "昔日捨身緣救鴿，今時出見有飛鷹。"]'),
('yuding-25','樂游原晴望上中書李侍郎','錢起','唐','御定全唐诗','yuding','','[]','爽氣朝來萬里清，憑高一望九秋輕。不知鳳沼霖初霽，',24,'御定全唐詩/json/239.json','["爽氣朝來萬里清，憑高一望九秋輕。不知鳳沼霖初霽，"]'),
('yuding-26','幽居春暮書懷','錢起','唐','御定全唐诗','yuding','','[]','自哂鄙夫多野性，貧居數畝半臨湍。溪雲雜雨來茅屋，',40,'御定全唐詩/json/239.json','["自哂鄙夫多野性，貧居數畝半臨湍。溪雲雜雨來茅屋，", "更憐童子宜春服，花裏尋師指杏壇。"]'),
('yuding-27','謁許由廟','錢起','唐','御定全唐诗','yuding','','[]','故向箕山訪許由，林泉物外自清幽。松上掛瓢枝幾變，',40,'御定全唐詩/json/239.json','["故向箕山訪許由，林泉物外自清幽。松上掛瓢枝幾變，", "緬想古人增嘆惜，颯然雲樹滿岩秋。"]'),
('yuding-28','過張成侍禦宅','錢起','唐','御定全唐诗','yuding','','[]','丞相幕中題鳳人，文章心事每相親。從軍誰謂仲宣樂，',40,'御定全唐詩/json/239.json','["丞相幕中題鳳人，文章心事每相親。從軍誰謂仲宣樂，", "欲知別後相思意，唯願瓊枝入夢頻。"]'),
('yuding-29','酬考功楊員外見贈佳句','錢起','唐','御定全唐诗','yuding','','[]','上林諫獵知才薄，尺組承恩愧命牽。潢潦難滋滄海潤，',40,'御定全唐詩/json/239.json','["上林諫獵知才薄，尺組承恩愧命牽。潢潦難滋滄海潤，", "相國無私人守朴，何辭老去上皇年。"]'),
('yuding-30','寄永嘉王十二','錢起','唐','御定全唐诗','yuding','','[]','永嘉風景入新年，才子詩成定可憐。夢裏還鄉不相見，',40,'御定全唐詩/json/239.json','["永嘉風景入新年，才子詩成定可憐。夢裏還鄉不相見，", "願得回風吹海雁，飛書一宿到君邊。"]'),
('yuding-31','七盤嶺阻寇聞李端公先到南楚','錢起','唐','御定全唐诗','yuding','','[]','日暮窮途淚滿襟，雲天南望羨飛禽。阮腸暗與孤鴻斷，',40,'御定全唐詩/json/239.json','["日暮窮途淚滿襟，雲天南望羨飛禽。阮腸暗與孤鴻斷，", "秦楚眼看成絕國，相思一寄白頭吟。"]'),
('yuding-32','酬趙給事相尋不遇留贈','錢起','唐','御定全唐诗','yuding','','[]','誰憶顏生窮巷裏，能勞馬跡破春苔。忽看童子掃花處，',40,'御定全唐詩/json/239.json','["誰憶顏生窮巷裏，能勞馬跡破春苔。忽看童子掃花處，", "豈無雞黍期他日，惜此殘春阻綠杯。"]'),
('yuding-33','山中酬楊補闕見過','錢起','唐','御定全唐诗','yuding','','[]','日暖風恬種藥時，紅泉翠壁薜蘿垂。幽溪鹿過苔還靜，',41,'御定全唐詩/json/239.json','["日暖風恬種藥時，紅泉翠壁薜蘿垂。幽溪鹿過苔還靜，", "卻慚身外牽纓冕，未勝杯前倒接z5。"]'),
('yuding-34','同王錥起居程浩郎中韓翃舍人題安國寺用上人院','錢起','唐','御定全唐诗','yuding','','[]','慧眼沙門真遠公，經行宴坐有儒風。香緣不絕簪裾會，',40,'御定全唐詩/json/239.json','["慧眼沙門真遠公，經行宴坐有儒風。香緣不絕簪裾會，", "狂夫入室無餘事，唯與天花一笑同。"]'),
('yuding-35','尋司勳李郎中不遇','錢起','唐','御定全唐诗','yuding','','[]','知己知音同舍郎，如何咫尺阻清揚。每恨蒹葭傍芳樹，',40,'御定全唐詩/json/239.json','["知己知音同舍郎，如何咫尺阻清揚。每恨蒹葭傍芳樹，", "唯有早朝趨鳳閣，朝時憐羽接鴛行。"]'),
('yuding-36','贈張南史','錢起','唐','御定全唐诗','yuding','','[]','紫泥何日到滄洲，笑向東陽沈隱侯。黛色晴峰雲外出，',40,'御定全唐詩/json/239.json','["紫泥何日到滄洲，笑向東陽沈隱侯。黛色晴峰雲外出，", "溪畔秋蘭雖可佩，知君不得少停舟。"]'),
('yuding-37','暇日覽舊詩因以題詠','錢起','唐','御定全唐诗','yuding','','[]','逍遙心地得關關，偶被功名涴我閑。有壽亦將歸象外，',40,'御定全唐詩/json/239.json','["逍遙心地得關關，偶被功名涴我閑。有壽亦將歸象外，", "筐篋靜開難似此，蕊珠春色海中山。"]'),
('yuding-38','漢武出獵','錢起','唐','御定全唐诗','yuding','','[]','漢家無事樂時雍，羽獵年年出九重。玉帛不朝金闕路，',40,'御定全唐詩/json/239.json','["漢家無事樂時雍，羽獵年年出九重。玉帛不朝金闕路，", "薄暮方歸長樂觀，垂楊幾處綠煙濃。"]'),
('yuding-39','宴曹王宅','錢起','唐','御定全唐诗','yuding','','[]','賢王駟馬退朝初，小苑三春帶雨餘。林沼蔥蘢多貴氣，',40,'御定全唐詩/json/239.json','["賢王駟馬退朝初，小苑三春帶雨餘。林沼蔥蘢多貴氣，", "自歎平生相識願，何如今日廁應徐。"]'),
('yuding-40','重贈趙給事','錢起','唐','御定全唐诗','yuding','','[]','久飛鴛掖出時髦，恥負平生稽古勞。玉樹滿庭家轉貴，',40,'御定全唐詩/json/239.json','["久飛鴛掖出時髦，恥負平生稽古勞。玉樹滿庭家轉貴，", "應念潛郎守貧病，常悲休沐對蓬蒿。"]'),
('yuding-41','贈闕下裴舍人','錢起','唐','御定全唐诗','yuding','','[]','二月黃鶯飛上林，春城紫禁曉陰陰。長樂鐘聲花外盡，',40,'御定全唐詩/json/239.json','["二月黃鶯飛上林，春城紫禁曉陰陰。長樂鐘聲花外盡，", "獻賦十年猶未遇，羞將白髮對華簪。"]'),
('yuding-42','登劉賓客高齋','錢起','唐','御定全唐诗','yuding','','[]','能以功成疏寵位，不將心賞負雲霞。林間客散孫弘閣，',40,'御定全唐詩/json/239.json','["能以功成疏寵位，不將心賞負雲霞。林間客散孫弘閣，", "日陪鯉也趨文苑，誰道門生隔絳紗。"]'),
('yuding-43','哭辛霽','錢起','唐','御定全唐诗','yuding','','[]','流水辭山花別枝，隨風一去絕還期。昨夜故人泉下宿，',40,'御定全唐詩/json/239.json','["流水辭山花別枝，隨風一去絕還期。昨夜故人泉下宿，", "旦暮餘生幾息在，不應存沒未嘗悲。"]'),
('yuding-44','和慕容法曹尋漁者寄城中故人','錢起','唐','御定全唐诗','yuding','','[]','孤煙一點綠溪湄，漁父幽居即舊基。饑鷺不驚收釣處，',40,'御定全唐詩/json/239.json','["孤煙一點綠溪湄，漁父幽居即舊基。饑鷺不驚收釣處，", "勝事宛然懷抱裏，頃來新得謝公詩。"]'),
('yuding-45','山花','錢起','唐','御定全唐诗','yuding','','[]','山花照塢複燒溪，樹樹枝枝盡可迷。野客未來枝畔立，',40,'御定全唐詩/json/239.json','["山花照塢複燒溪，樹樹枝枝盡可迷。野客未來枝畔立，", "別有妖妍勝桃李，攀來折去亦成蹊。"]'),
('yuding-46','送楊著作歸東海','錢起','唐','御定全唐诗','yuding','','[]','楊柳出關色，東行千里期。酒酣暫輕別，路遠始相思。',36,'御定全唐詩/json/239.json','["楊柳出關色，東行千里期。酒酣暫輕別，路遠始相思。", "欲識離心盡，斜陽到海時。"]'),
('yuding-47','送李協律還東京','錢起','唐','御定全唐诗','yuding','','[]','芳草忽無色，王孫複入關。長河侵驛道，匹馬傍雲山。',36,'御定全唐詩/json/239.json','["芳草忽無色，王孫複入關。長河侵驛道，匹馬傍雲山。", "愁見離居久，螢飛秋月閑。"]'),
('yuding-48','秋館言懷','錢起','唐','御定全唐诗','yuding','','[]','蟋蟀已秋思，蕙蘭仍碧滋。蹉跎獻賦客，歎息此良時。',36,'御定全唐詩/json/239.json','["蟋蟀已秋思，蕙蘭仍碧滋。蹉跎獻賦客，歎息此良時。", "日夕雲台下，商歌空自悲。"]'),
('yuding-49','和劉明府宴縣前山亭','錢起','唐','御定全唐诗','yuding','','[]','城隅勞心處，雪後歲芳開。山映千花出，泉經萬井來。',36,'御定全唐詩/json/239.json','["城隅勞心處，雪後歲芳開。山映千花出，泉經萬井來。", "翔鸞欲下舞，上客且留杯。"]'),
('yuding-50','新雨喜得王卿書問','錢起','唐','御定全唐诗','yuding','','[]','苦雨暗秋徑，寒花垂紫苔。愁中綠尊盡，夢裏故人來。',36,'御定全唐詩/json/239.json','["苦雨暗秋徑，寒花垂紫苔。愁中綠尊盡，夢裏故人來。", "果有相思字，銀鉤新月開。"]'),
('yuding-51','賦得巢燕送客','錢起','唐','御定全唐诗','yuding','','[]','能棲杏梁際，不與黃雀群。夜影寄紅燭，朝飛高碧雲。',36,'御定全唐詩/json/239.json','["能棲杏梁際，不與黃雀群。夜影寄紅燭，朝飛高碧雲。", "含情別故侶，花月惜春分。"]'),
('yuding-52','題張藍田訟堂','錢起','唐','御定全唐诗','yuding','','[]','角巾高枕向晴山，頌簡庭空不用關。秋風窗下琴書靜，',24,'御定全唐詩/json/239.json','["角巾高枕向晴山，頌簡庭空不用關。秋風窗下琴書靜，"]'),
('yuding-53','江行無題一百首','錢起','唐','御定全唐诗','yuding','','[]','傾酒向漣漪，乘流東去時。寸心同尺璧，投此報馮夷。',576,'御定全唐詩/json/239.json','["傾酒向漣漪，乘流東去時。寸心同尺璧，投此報馮夷。", "江曲全縈楚，雲飛半自秦。峴山回首望，如別故關人。", "浦煙函夜色，冷日轉秋旻。自有沈碑石，清光不照人。", "楚岸雲空合，楚城人不來。只今誰善舞，莫恨發陽臺。", "行背青山郭，吟當白露秋。風流無屈宋，空詠古荊州。", "晚來漁父喜，罾重欲收遲。恐有長江使，金錢願贖龜。", "去指龍沙路，徒懸象闕心。夜涼無遠夢，不為偶聞砧。", "霽雲疏有葉，雨浪細無花。隱放扁舟去，江天自有涯。", "好日當秋半，層波動旅腸。已行千裏外，誰與共秋光。", "潤色非東裏，官曹更建章。宦遊難自定，來喚棹船郎。", "夜江清未曉，徒惜月光沉。不是因行樂，堪傷老大心。", "翳日多喬木，維舟取束薪。靜聽江叟語，俱是厭兵人。", "箭漏日初短，汀煙草未衰。雨餘雖更綠，不是采蘋時。", "山雨夜來漲，喜魚跳滿江。岸沙平欲盡，垂蓼入船窗。", "渚邊新雁下，舟上獨淒涼。俱是南來客，憐君綴一行。", "牽路沿江狹，沙崩岸不平。盡知行處險，誰肯載時輕。", "雲密連江暗，風斜著物鳴。一杯真戰將，笑爾作愁兵。", "柳拂斜開路，籬邊數戶村。可能還有意，不掩向江門。", "不識桓公渴，徒吟子美詩。江清唯獨看，心外更誰知。", "憔悴異靈均，非讒作逐臣。如逢漁父問，未是獨醒人。", "水涵秋色靜，雲帶夕陽高。詩癖非吾病，何妨吮短毫。", "登舟非古岸，還似阻西陵。箕伯無多少，回頭詎不能。", "帆翅初張處，雲鵬怒翼同。莫愁千里路，自有到來風。", "秋雲久無雨，江燕社猶飛。卻笑舟中客，今年未得歸。"]'),
('yuding-54','言懷','錢起','唐','御定全唐诗','yuding','','[]','夜月霽未好，雲泉堪夢歸。如何建章漏，催著早朝衣。',24,'御定全唐詩/json/239.json','["夜月霽未好，雲泉堪夢歸。如何建章漏，催著早朝衣。"]'),
('yuding-55','和張僕射塞下曲','錢起','唐','御定全唐诗','yuding','','[]','月黑雁飛高，單于夜遁逃。欲將輕騎逐，大雪滿弓刀。',24,'御定全唐詩/json/239.json','["月黑雁飛高，單于夜遁逃。欲將輕騎逐，大雪滿弓刀。"]'),
('yuding-56','送李明府去官','錢起','唐','御定全唐诗','yuding','','[]','謗言三至後，直道歎何如。今日藍溪水，無人不夜魚。',24,'御定全唐詩/json/239.json','["謗言三至後，直道歎何如。今日藍溪水，無人不夜魚。"]'),
('yuding-57','赴章陵酬李卿贈別','錢起','唐','御定全唐诗','yuding','','[]','一官叨下秩，九棘謝知音。芳草文園路，春愁滿別心。',24,'御定全唐詩/json/239.json','["一官叨下秩，九棘謝知音。芳草文園路，春愁滿別心。"]'),
('yuding-58','逢俠者','錢起','唐','御定全唐诗','yuding','','[]','燕趙悲歌士，相逢劇孟家。寸心言不盡，前路日將斜。',24,'御定全唐詩/json/239.json','["燕趙悲歌士，相逢劇孟家。寸心言不盡，前路日將斜。"]'),
('yuding-59','郎員外見尋不遇','錢起','唐','御定全唐诗','yuding','','[]','軒騎來相訪，漁樵悔晚歸。更憐垂露跡，花裏點牆衣。',24,'御定全唐詩/json/239.json','["軒騎來相訪，漁樵悔晚歸。更憐垂露跡，花裏點牆衣。"]'),
('yuding-60','過李侍禦宅','錢起','唐','御定全唐诗','yuding','','[]','不見承明客，愁聞長樂鐘。馬卿何早世，漢主欲登封。',24,'御定全唐詩/json/239.json','["不見承明客，愁聞長樂鐘。馬卿何早世，漢主欲登封。"]'),
('yuding-61','宿洞口館','錢起','唐','御定全唐诗','yuding','','[]','野竹通溪冷，秋泉入戶鳴。亂來人不到，芳草上階生。',24,'御定全唐詩/json/239.json','["野竹通溪冷，秋泉入戶鳴。亂來人不到，芳草上階生。"]'),
('yuding-62','九日寄侄箊箕等','錢起','唐','御定全唐诗','yuding','','[]','采菊偏相憶，傳香寄便風。今朝竹林下，莫使桂尊空。',24,'御定全唐詩/json/239.json','["采菊偏相憶，傳香寄便風。今朝竹林下，莫使桂尊空。"]'),
('yuding-63','梨花','錢起','唐','御定全唐诗','yuding','','[]','豔靜如籠月，香寒未逐風。桃花徒照地，終被笑妖紅。',24,'御定全唐詩/json/239.json','["豔靜如籠月，香寒未逐風。桃花徒照地，終被笑妖紅。"]'),
('yuding-64','題崔逸人山亭','錢起','唐','御定全唐诗','yuding','','[]','藥徑深紅蘚，山窗滿翠微。羨君花下酒，蝴蝶夢中飛。',24,'御定全唐詩/json/239.json','["藥徑深紅蘚，山窗滿翠微。羨君花下酒，蝴蝶夢中飛。"]'),
('yuding-65','藍田溪雜詠二十二首：登臺','錢起','唐','御定全唐诗','yuding','','[]','望山登春台，目盡趣難極。晚景下平阡，花際霞峰色。',24,'御定全唐詩/json/239.json','["望山登春台，目盡趣難極。晚景下平阡，花際霞峰色。"]'),
('yuding-66','藍田溪雜詠二十二首：板橋','錢起','唐','御定全唐诗','yuding','','[]','靜宜樵隱度，遠與車馬隔。有時行藥來，喜遇歸山客。',24,'御定全唐詩/json/239.json','["靜宜樵隱度，遠與車馬隔。有時行藥來，喜遇歸山客。"]'),
('yuding-67','藍田溪雜詠二十二首：石井','錢起','唐','御定全唐诗','yuding','','[]','片霞照仙井，泉底桃花紅。那知幽石下，不與武陵通。',24,'御定全唐詩/json/239.json','["片霞照仙井，泉底桃花紅。那知幽石下，不與武陵通。"]'),
('yuding-68','藍田溪雜詠二十二首：古藤','錢起','唐','御定全唐诗','yuding','','[]','引蔓出雲樹，垂綸覆巢鶴。幽人對酒時，苔上閑花落。',24,'御定全唐詩/json/239.json','["引蔓出雲樹，垂綸覆巢鶴。幽人對酒時，苔上閑花落。"]'),
('yuding-69','藍田溪雜詠二十二首：晚歸鷺','錢起','唐','御定全唐诗','yuding','','[]','池上靜難厭，雲間欲去晚。忽背夕陽飛，乘興清風遠。',24,'御定全唐詩/json/239.json','["池上靜難厭，雲間欲去晚。忽背夕陽飛，乘興清風遠。"]'),
('yuding-70','藍田溪雜詠二十二首：洞仙謠','錢起','唐','御定全唐诗','yuding','','[]','幾轉到青山，數重度流水。秦人入雲去，知向桃源裏。',24,'御定全唐詩/json/239.json','["幾轉到青山，數重度流水。秦人入雲去，知向桃源裏。"]'),
('yuding-71','藍田溪雜詠二十二首：藥圃','錢起','唐','御定全唐诗','yuding','','[]','春畦生百藥，花葉香初霽。好容似風光，偏來入叢蕙。',24,'御定全唐詩/json/239.json','["春畦生百藥，花葉香初霽。好容似風光，偏來入叢蕙。"]'),
('yuding-72','藍田溪雜詠二十二首：石上苔','錢起','唐','御定全唐诗','yuding','','[]','淨與溪色連，幽宜松雨滴。誰知古石上，不染世人跡。',24,'御定全唐詩/json/239.json','["淨與溪色連，幽宜松雨滴。誰知古石上，不染世人跡。"]'),
('yuding-73','藍田溪雜詠二十二首：窗裏山','錢起','唐','御定全唐诗','yuding','','[]','遠岫見如近，千里一窗裏。坐來石上雲，乍謂壺中起。',24,'御定全唐詩/json/239.json','["遠岫見如近，千里一窗裏。坐來石上雲，乍謂壺中起。"]'),
('yuding-74','藍田溪雜詠二十二首：竹間路','錢起','唐','御定全唐诗','yuding','','[]','暗歸草堂靜，半入花園去。有時載酒來，不與清風遇。',24,'御定全唐詩/json/239.json','["暗歸草堂靜，半入花園去。有時載酒來，不與清風遇。"]'),
('yuding-75','藍田溪雜詠二十二首：竹嶼','錢起','唐','御定全唐诗','yuding','','[]','幽鳥清漣上，興來看不足。新篁壓水低，昨夜鴛鴦宿。',24,'御定全唐詩/json/239.json','["幽鳥清漣上，興來看不足。新篁壓水低，昨夜鴛鴦宿。"]'),
('yuding-76','藍田溪雜詠二十二首：砌下泉','錢起','唐','御定全唐诗','yuding','','[]','穿雲來自遠，激砌流偏駛。能資庭戶幽，更引海禽至。',24,'御定全唐詩/json/239.json','["穿雲來自遠，激砌流偏駛。能資庭戶幽，更引海禽至。"]'),
('yuding-77','藍田溪雜詠二十二首：戲鷗','錢起','唐','御定全唐诗','yuding','','[]','乍依菱蔓聚，盡向蘆花滅。更喜好風來，數片翻晴雪。',24,'御定全唐詩/json/239.json','["乍依菱蔓聚，盡向蘆花滅。更喜好風來，數片翻晴雪。"]'),
('yuding-78','藍田溪雜詠二十二首：遠山鐘','錢起','唐','御定全唐诗','yuding','','[]','風送出山鐘，雲霞度水淺。欲知聲盡處，鳥滅寥天遠。',24,'御定全唐詩/json/239.json','["風送出山鐘，雲霞度水淺。欲知聲盡處，鳥滅寥天遠。"]'),
('yuding-79','藍田溪雜詠二十二首：東陂','錢起','唐','御定全唐诗','yuding','','[]','永日興難望，掇芳春陂曲。新晴花枝下，愛此苔水綠。',24,'御定全唐詩/json/239.json','["永日興難望，掇芳春陂曲。新晴花枝下，愛此苔水綠。"]'),
('yuding-80','藍田溪雜詠二十二首：池上亭','錢起','唐','御定全唐诗','yuding','','[]','臨池構杏梁，待客歸煙塘。水上褰簾好，蓮開杜若香。',24,'御定全唐詩/json/239.json','["臨池構杏梁，待客歸煙塘。水上褰簾好，蓮開杜若香。"]'),
('yuding-81','藍田溪雜詠二十二首：銜魚翠鳥','錢起','唐','御定全唐诗','yuding','','[]','有意蓮葉間，瞥然下高樹。擘波得潛魚，一點翠光去。',24,'御定全唐詩/json/239.json','["有意蓮葉間，瞥然下高樹。擘波得潛魚，一點翠光去。"]'),
('yuding-82','藍田溪雜詠二十二首：石蓮花','錢起','唐','御定全唐诗','yuding','','[]','幽石生芙蓉，百花慚美色。遠笑越溪女，聞芳不可識。',24,'御定全唐詩/json/239.json','["幽石生芙蓉，百花慚美色。遠笑越溪女，聞芳不可識。"]'),
('yuding-83','藍田溪雜詠二十二首：潺湲聲','錢起','唐','御定全唐诗','yuding','','[]','亂石跳素波，寒聲聞幾處。颼颼暝風引，散出空林去。',24,'御定全唐詩/json/239.json','["亂石跳素波，寒聲聞幾處。颼颼暝風引，散出空林去。"]'),
('yuding-84','藍田溪雜詠二十二首：松下雪','錢起','唐','御定全唐诗','yuding','','[]','雖因朔風至，不向瑤台側。唯助苦寒松，偏明後凋色。',24,'御定全唐詩/json/239.json','["雖因朔風至，不向瑤台側。唯助苦寒松，偏明後凋色。"]'),
('yuding-85','藍田溪雜詠二十二首：田鶴','錢起','唐','御定全唐诗','yuding','','[]','田鶴望碧霄，舞風亦自舉。單飛後片雪，早晚及前侶。',24,'御定全唐詩/json/239.json','["田鶴望碧霄，舞風亦自舉。單飛後片雪，早晚及前侶。"]'),
('yuding-86','藍田溪雜詠二十二首：題南陂','錢起','唐','御定全唐诗','yuding','','[]','家住鳳城南，門臨古陂曲。時憐上林雁，半入池塘宿。',24,'御定全唐詩/json/239.json','["家住鳳城南，門臨古陂曲。時憐上林雁，半入池塘宿。"]'),
('yuding-87','藍田溪雜詠二十二首：傷秋','錢起','唐','御定全唐诗','yuding','','[]','歲去人頭白，秋來樹葉黃。搔頭向黃葉，與爾共悲傷。',24,'御定全唐詩/json/239.json','["歲去人頭白，秋來樹葉黃。搔頭向黃葉，與爾共悲傷。"]'),
('yuding-88','送崔山人歸山','錢起','唐','御定全唐诗','yuding','','[]','東山殘雨掛斜暉，野客巢由指翠微。',32,'御定全唐詩/json/239.json','["東山殘雨掛斜暉，野客巢由指翠微。", "別酒稍酣乘興去，知君不羨白雲歸。"]'),
('yuding-89','題禮上人壁畫山水','錢起','唐','御定全唐诗','yuding','','[]','連山畫出映禪扉，粉壁香筵滿翠微。',32,'御定全唐詩/json/239.json','["連山畫出映禪扉，粉壁香筵滿翠微。", "坐來爐氣縈空散，共指晴雲向嶺歸。"]'),
('yuding-90','送歐陽子還江華郡','錢起','唐','御定全唐诗','yuding','','[]','江華勝事接湘濱，千里湖山入興新。',32,'御定全唐詩/json/239.json','["江華勝事接湘濱，千里湖山入興新。", "才子思歸催去棹，汀花且為駐殘春。"]'),
('yuding-91','暮春歸故山草堂','錢起','唐','御定全唐诗','yuding','','[]','穀口春殘黃鳥稀，辛夷花盡杏花飛。',32,'御定全唐詩/json/239.json','["穀口春殘黃鳥稀，辛夷花盡杏花飛。", "始憐幽竹山窗下，不改清陰待我歸。"]'),
('yuding-92','訪李卿不遇','錢起','唐','御定全唐诗','yuding','','[]','畫戟朱樓映晚霞，高梧寒柳度飛鴉。',32,'御定全唐詩/json/239.json','["畫戟朱樓映晚霞，高梧寒柳度飛鴉。", "門前不見歸軒至，城上愁看落日斜。"]'),
('yuding-93','與趙莒茶宴','錢起','唐','御定全唐诗','yuding','','[]','竹下忘言對紫茶，全勝羽客醉流霞。',32,'御定全唐詩/json/239.json','["竹下忘言對紫茶，全勝羽客醉流霞。", "塵心洗盡興難盡，一樹蟬聲片影斜。"]'),
('yuding-94','故王維右丞堂前芍藥花開，淒然感懷','錢起','唐','御定全唐诗','yuding','','[]','芍藥花開出舊欄，春衫掩淚再來看。',32,'御定全唐詩/json/239.json','["芍藥花開出舊欄，春衫掩淚再來看。", "主人不在花長在，更勝青松守歲寒。"]'),
('yuding-95','送張參及第還家','錢起','唐','御定全唐诗','yuding','','[]','大學三年聞琢玉，東堂一舉早成名。',32,'御定全唐詩/json/239.json','["大學三年聞琢玉，東堂一舉早成名。", "借問還家何處好，玉人含笑下機迎。"]'),
('yuding-96','夜泊鸚鵡洲','錢起','唐','御定全唐诗','yuding','','[]','月照溪邊一罩蓬，夜聞清唱有微風。',32,'御定全唐詩/json/239.json','["月照溪邊一罩蓬，夜聞清唱有微風。", "小樓深巷敲方響，水國人家在處同。"]'),
('yuding-97','歸雁','錢起','唐','御定全唐诗','yuding','','[]','瀟湘何事等閒回，水碧沙明兩岸苔。',32,'御定全唐詩/json/239.json','["瀟湘何事等閒回，水碧沙明兩岸苔。", "二十五弦彈夜月，不勝清怨卻飛來。"]'),
('yuding-98','春郊','錢起','唐','御定全唐诗','yuding','','[]','水繞冰渠漸有聲，氣融煙塢晚來明。',32,'御定全唐詩/json/239.json','["水繞冰渠漸有聲，氣融煙塢晚來明。", "東風好作陽和使，逢草逢花報發生。"]'),
('yuding-99','晚歸嚴明府題門','錢起','唐','御定全唐诗','yuding','','[]','降士林沾蕙草寒，弦驚翰苑失鴛鸞。',32,'御定全唐詩/json/239.json','["降士林沾蕙草寒，弦驚翰苑失鴛鸞。", "秋中回首君門阻，馬上應歌行路難。"]'),
('yuding-100','秋夜送趙冽歸襄陽','錢起','唐','御定全唐诗','yuding','','[]','鬥酒忘言良夜深，紅萱露滴鵲驚林。',32,'御定全唐詩/json/239.json','["鬥酒忘言良夜深，紅萱露滴鵲驚林。", "欲知別後思今夕，漢水東流是寸心。"]'),
('yuding-101','送符別駕還郡','錢起','唐','御定全唐诗','yuding','','[]','驥足駸駸吳越關，屏星複與紫書還。',32,'御定全唐詩/json/239.json','["驥足駸駸吳越關，屏星複與紫書還。", "已知從事元無事，城上愁看海上山。"]'),
('yuding-102','同王員外隴城絕句','錢起','唐','御定全唐诗','yuding','','[]','三軍版築脫金刀，黎庶翻慚將士勞。',32,'御定全唐詩/json/239.json','["三軍版築脫金刀，黎庶翻慚將士勞。", "不憶新城連嶂起，唯驚畫角入雲高。"]'),
('yuding-103','過故洛城','錢起','唐','御定全唐诗','yuding','','[]','故城門外春日斜，故城門裏無人家。',32,'御定全唐詩/json/239.json','["故城門外春日斜，故城門裏無人家。", "市朝欲認不知處，漠漠野田空草花。"]'),
('yuding-104','校獵曲','錢起','唐','御定全唐诗','yuding','','[]','長楊殺氣連雲飛，漢主秋畋正掩圍。',32,'御定全唐詩/json/239.json','["長楊殺氣連雲飛，漢主秋畋正掩圍。", "重門日晏紅塵出，數騎胡人獵獸歸。"]'),
('yuding-105','晚過橫灞寄張藍田','錢起','唐','御定全唐诗','yuding','','[]','亂水東流落照時，黃花滿徑客行遲。',32,'御定全唐詩/json/239.json','["亂水東流落照時，黃花滿徑客行遲。", "林端忽見南山色，馬上還吟陶令詩。"]'),
('yuding-106','九日田舍','錢起','唐','御定全唐诗','yuding','','[]','今日陶家野興偏，東籬黃菊映秋田。',32,'御定全唐詩/json/239.json','["今日陶家野興偏，東籬黃菊映秋田。", "浮雲暝鳥飛將盡，始達青山新月前。"]'),
('yuding-107','長安落第','錢起','唐','御定全唐诗','yuding','','[]','花繁柳暗九門深，對飲悲歌淚滿襟。',32,'御定全唐詩/json/239.json','["花繁柳暗九門深，對飲悲歌淚滿襟。", "數日鶯花皆落羽，一回春至一傷心。"]'),
('yuding-0','二風詩：治風詩五篇：至仁','元結','唐','御定全唐诗','yuding','','[]','（古有仁帝，能全仁明以封天下，故為《至仁》之詩',93,'御定全唐詩/json/240.json','["（古有仁帝，能全仁明以封天下，故為《至仁》之詩", "二章四韻十二句）", "猗皇至聖兮，至惠至仁，德施蘊蘊。", "蘊蘊如何？不全不缺，莫知所貺。", "猗皇至聖兮，至儉至明，化流瀛瀛。", "瀛瀛如何？不虢不赩，莫知其極。"]'),
('yuding-1','二風詩：治風詩五篇：至慈','元結','唐','御定全唐诗','yuding','','[]','（古有慈帝，能保靜順以涵萬物，故為《至慈》之詩',73,'御定全唐詩/json/240.json','["（古有慈帝，能保靜順以涵萬物，故為《至慈》之詩", "二章四韻十四句）", "至化之深兮，猗猗娭娭。如煦如吹，如負如持，", "至化之極兮，瀛瀛溶溶。如涵如封，如隨如從，"]'),
('yuding-2','二風詩：治風詩五篇：至勞','元結','唐','御定全唐诗','yuding','','[]','（古有勞王，能執勞儉以大功業，故為《至勞》之詩',152,'御定全唐詩/json/240.json','["（古有勞王，能執勞儉以大功業，故為《至勞》之詩", "三章六韻二十四句）", "至哉勤績，不盈不延；誰能頌之，我請頌焉。", "于戲勞王，勤亦何極；濟爾九土，山川溝洫。", "至哉儉德，不豐不敷；誰能頌之，我請頌夫。", "于戲勞王，儉亦何深；戒爾萬代，奢侈荒淫。", "至哉茂功，不升不圮；誰能頌之，我請頌矣。", "于戲勞王，功亦何大；去爾兆庶，洪湮災害。"]'),
('yuding-3','二風詩：治風詩五篇：至正','元結','唐','御定全唐诗','yuding','','[]','（古有正王，能正慎恭和以安上下，故為《至正》之詩',71,'御定全唐詩/json/240.json','["（古有正王，能正慎恭和以安上下，故為《至正》之詩", "一章四韻八句）", "為君之道，何以為明？功不濫賞，罪不濫刑；", "讜言則聽，諂言不聽；王至是然，可為明焉。"]'),
('yuding-4','二風詩：治風詩五篇：至理','元結','唐','御定全唐诗','yuding','','[]','（古有理王，能守清一以致無刑，故為《至理》之詩',66,'御定全唐詩/json/240.json','["（古有理王，能守清一以致無刑，故為《至理》之詩", "一章三韻十二句）", "理何為兮，系修文德。加之清一，莫不順則。意彼刑法，", "嗚呼嗚呼！人不斯察。"]'),
('yuding-5','二風詩：亂風詩五篇：至荒','元結','唐','御定全唐诗','yuding','','[]','（古有荒王，忘戒慎道，以逸豫失國，故為《至荒》',86,'御定全唐詩/json/240.json','["（古有荒王，忘戒慎道，以逸豫失國，故為《至荒》", "之詩一章三韻十二句）", "國有世謨，仁信勤歟。王實惛荒，終亡此乎。", "焉有力恣諂惑，而不亡其國？嗚呼亡王，忍為此心！", "敢正亡王，永為世箴。"]'),
('yuding-6','二風詩：亂風詩五篇：至亂','元結','唐','御定全唐诗','yuding','','[]','（古有亂王，肆極凶虐，亂亡乃已，故為《至亂》之詩',92,'御定全唐詩/json/240.json','["（古有亂王，肆極凶虐，亂亡乃已，故為《至亂》之詩", "二章二韻十二句）", "嘻乎王家，曾有凶王，中世失國，豈非驕荒。", "複複之難，令則可忘。", "嘻乎亂王，王心何思？暴淫虐惑，無思不為；", "生人冤怨，言何極之。"]'),
('yuding-7','二風詩：亂風詩五篇：至虐','元結','唐','御定全唐诗','yuding','','[]','（古有虐王，昏毒狂忍，無惡不及，故為《至虐》之詩',99,'御定全唐詩/json/240.json','["（古有虐王，昏毒狂忍，無惡不及，故為《至虐》之詩", "二章四韻十八句）", "夫為君上兮，慈順明恕，可以化人。忍行昏恣，", "夫為君上兮，兢慎儉約，可以保身，忍行荒惑，虐暴於人；", "前世失國，如王者多。於斯不寤，當如之何。"]'),
('yuding-8','二風詩：亂風詩五篇：至惑','元結','唐','御定全唐诗','yuding','','[]','（古有惑王，用奸臣以虐外，寵妖女以亂內，內外用亂，',126,'御定全唐詩/json/240.json','["（古有惑王，用奸臣以虐外，寵妖女以亂內，內外用亂，", "賢聖為上兮，必儉約戒身，鑒察化人，所以保福也。", "如何不思，荒恣是為？上下隔塞，人神怨奰；", "敖惡無厭，不畏顛墜。", "聖賢為上兮，必用賢正，黜奸佞之臣，所以長久也。", "如何反是，以為亂矣？寵邪信惑，近佞好諛；廢嫡立庶，"]'),
('yuding-9','二風詩：亂風詩五篇：至傷','元結','唐','御定全唐诗','yuding','','[]','（古有傷王，以崩蕩之餘，無惡不為也。亂亡之由，',80,'御定全唐詩/json/240.json','["（古有傷王，以崩蕩之餘，無惡不為也。亂亡之由，", "夫可傷兮？傷王乎，欲何為乎？將蠹枯矣，無人救乎？", "蠹枯及矣，不可救乎？嗟傷王！自為人君，變為人奴！", "為人君者，忘戒乎。"]'),
('yuding-10','補樂歌十首：網罟','元結','唐','御定全唐诗','yuding','','[]','（《網罟》，伏羲氏之樂歌也。其義蓋稱伏羲能易人',73,'御定全唐詩/json/240.json','["（《網罟》，伏羲氏之樂歌也。其義蓋稱伏羲能易人", "取禽獸之勞，凡二章，章四句）", "吾人苦兮，水深深。網罟設兮，水不深。", "吾人苦兮，山幽幽。網罟設兮，山不幽。"]'),
('yuding-11','補樂歌十首：豐年','元結','唐','御定全唐诗','yuding','','[]','（《豐年》，神農氏之樂歌也，其義蓋稱神農教人種植',75,'御定全唐詩/json/240.json','["（《豐年》，神農氏之樂歌也，其義蓋稱神農教人種植", "之功。凡二章，章四句）", "猗太帝兮，其智如神；分草實兮，濟我生人。", "猗太帝兮，其功如天；均四時兮，成我豐年。"]'),
('yuding-12','補樂歌十首：雲門','元結','唐','御定全唐诗','yuding','','[]','（《雲門》，軒轅氏之樂歌也，其義蓋言雲之出，潤益',89,'御定全唐詩/json/240.json','["（《雲門》，軒轅氏之樂歌也，其義蓋言雲之出，潤益", "萬物，如帝之德，無所不施。凡二章，章四句）", "玄雲溶溶兮，垂雨濛濛；類我聖澤兮，涵濡不窮。", "玄雲漠漠兮，含映逾光；類我聖德兮，溥被無方。"]'),
('yuding-13','補樂歌十首：九淵','元結','唐','御定全唐诗','yuding','','[]','（《九淵》，少昊氏之樂歌也，其義蓋稱少昊之德，',45,'御定全唐詩/json/240.json','["（《九淵》，少昊氏之樂歌也，其義蓋稱少昊之德，", "聖德至深兮，奫奫如淵；生類娭娭兮，孰知其然。"]'),
('yuding-14','補樂歌十首：五莖','元結','唐','御定全唐诗','yuding','','[]','（《五莖》，顓頊氏之樂歌也，其義蓋稱顓頊得五德',75,'御定全唐詩/json/240.json','["（《五莖》，顓頊氏之樂歌也，其義蓋稱顓頊得五德", "之根莖。凡一章，章八句）", "植植萬物兮，滔滔根莖；五德涵柔兮，渢渢而生。", "其生如何兮秞秞，天下皆自我君兮化成。"]'),
('yuding-15','補樂歌十首：六英','元結','唐','御定全唐诗','yuding','','[]','（《六英》，高辛氏之樂歌也，其義蓋稱帝嚳能總',100,'御定全唐詩/json/240.json','["（《六英》，高辛氏之樂歌也，其義蓋稱帝嚳能總", "六合之英華。凡二章，章六句）", "我有金石兮，擊考崇崇。與汝歌舞兮，上帝之風。", "由六合兮，英華渢渢。", "我有絲竹兮，韻和泠泠。與汝歌舞兮，上帝之聲。", "由六合兮，根底嬴嬴。"]'),
('yuding-16','補樂歌十首：咸池','元結','唐','御定全唐诗','yuding','','[]','（《咸池》，陶唐氏之樂歌也，其義蓋稱堯德至大，',67,'御定全唐詩/json/240.json','["（《咸池》，陶唐氏之樂歌也，其義蓋稱堯德至大，", "元化油油兮，孰知其然。至德汩汩兮，順之以先。", "元化浘浘兮，孰知其然。至道泱泱兮，由之以全。"]'),
('yuding-17','補樂歌十首：大韶','元結','唐','御定全唐诗','yuding','','[]','（《大韶》，有虞氏之樂歌也，其義蓋稱舜能紹先聖',78,'御定全唐詩/json/240.json','["（《大韶》，有虞氏之樂歌也，其義蓋稱舜能紹先聖", "之德。凡二章，章四句）", "森森群象兮，日見生成。欲聞朕初兮，玄封冥冥。", "洋洋至化兮，日見深柔。欲聞大濩兮，大淵油油。"]'),
('yuding-18','補樂歌十首：大夏','元結','唐','御定全唐诗','yuding','','[]','（《大夏》，有夏氏之樂歌也，其義蓋稱禹治水，',88,'御定全唐詩/json/240.json','["（《大夏》，有夏氏之樂歌也，其義蓋稱禹治水，", "茫茫下土兮，乃生九州。山有長岑兮，川有深流。", "茫茫下土兮，乃均四方。國有安乂兮，野有封疆。", "茫茫下土兮，乃歌萬年。上有茂功兮，下戴仁天。"]'),
('yuding-19','補樂歌十首：大濩','元結','唐','御定全唐诗','yuding','','[]','（《大濩》，有殷氏之樂歌也，其義蓋稱湯救天下，',61,'御定全唐詩/json/240.json','["（《大濩》，有殷氏之樂歌也，其義蓋稱湯救天下，", "萬姓苦兮，怨且哭，不有聖人兮，誰護育。", "聖人生兮，天下和。萬姓熙熙兮，舞且歌。"]'),
('yuding-20','系樂府十二首：思太古','元結','唐','御定全唐诗','yuding','','[]','東南三千里，沅湘為太湖。湖上山谷深，有人多似愚。',72,'御定全唐詩/json/240.json','["東南三千里，沅湘為太湖。湖上山谷深，有人多似愚。", "嬰孩寄樹顛，就水捕鷠鱸。所歡同鳥獸，身意複何拘。", "吾行遍九州，此風皆已無。籲嗟聖賢教，不覺久躊躕。"]'),
('yuding-21','系樂府十二首：隴上歎','元結','唐','御定全唐诗','yuding','','[]','援車登隴阪，窮高遂停駕。延望戎狄鄉，巡迴複悲吒。',72,'御定全唐詩/json/240.json','["援車登隴阪，窮高遂停駕。延望戎狄鄉，巡迴複悲吒。", "滋移有情教，草木猶可化。聖賢禮讓風，何不遍西夏。", "父子忍猜害，君臣敢欺詐。所適今若斯，悠悠欲安舍。"]'),
('yuding-22','系樂府十二首：頌東夷','元結','唐','御定全唐诗','yuding','','[]','嘗聞古天子，朝會張新樂。金石無全聲，宮商亂清濁。',72,'御定全唐詩/json/240.json','["嘗聞古天子，朝會張新樂。金石無全聲，宮商亂清濁。", "東驚且悲歎，節變何煩數。始知中國人，耽此亡純樸。", "爾為外方客，何為獨能覺。其音若或在，蹈海吾將學。"]'),
('yuding-23','系樂府十二首：賤士吟','元結','唐','御定全唐诗','yuding','','[]','南風發天和，和氣天下流。能使萬物榮，不能變羈愁。',72,'御定全唐詩/json/240.json','["南風發天和，和氣天下流。能使萬物榮，不能變羈愁。", "為愁亦何爾，自請說此由。諂競實多路，苟邪皆共求。", "嘗聞古君子，指以為深羞。正方終莫可，江海有滄洲。"]'),
('yuding-24','系樂府十二首：欸乃曲','元結','唐','御定全唐诗','yuding','','[]','誰能聽欸乃，欸乃感人情。不恨湘波深，不怨湘水清。',72,'御定全唐詩/json/240.json','["誰能聽欸乃，欸乃感人情。不恨湘波深，不怨湘水清。", "所嗟豈敢道，空羨江月明。昔聞扣斷舟，引釣歌此聲。", "始歌悲風起，歌竟愁雲生。遺曲今何在，逸為漁父行。"]'),
('yuding-25','系樂府十二首：貧婦詞','元結','唐','御定全唐诗','yuding','','[]','誰知苦貧夫，家有愁怨妻。請君聽其詞，能不為酸淒。',72,'御定全唐詩/json/240.json','["誰知苦貧夫，家有愁怨妻。請君聽其詞，能不為酸淒。", "所憐抱中兒，不如山下麑。空念庭前地，化為人吏蹊。", "出門望山澤，回頭心複迷。何時見府主，長跪向之啼。"]'),
('yuding-26','系樂府十二首：去鄉悲','元結','唐','御定全唐诗','yuding','','[]','躊躕古塞關，悲歌為誰長。日行見孤老，羸弱相提將。',72,'御定全唐詩/json/240.json','["躊躕古塞關，悲歌為誰長。日行見孤老，羸弱相提將。", "聞其呼怨聲，聞聲問其方。方言無患苦，豈棄父母鄉。", "非不見其心，仁惠誠所望。念之何可說，獨立為淒傷。"]'),
('yuding-27','系樂府十二首：壽翁興','元結','唐','御定全唐诗','yuding','','[]','借問多壽翁，何方自修育。惟雲順所然，忘情學草木。',72,'御定全唐詩/json/240.json','["借問多壽翁，何方自修育。惟雲順所然，忘情學草木。", "始知世上術，勞苦化金玉。不見充所求，空聞肆耽欲。", "清和存王母，潛濩無亂黷。誰正好長生，此言堪佩服。"]'),
('yuding-28','系樂府十二首：農臣怨','元結','唐','御定全唐诗','yuding','','[]','農臣何所怨，乃欲幹人主。不識天地心，徒然怨風雨。',72,'御定全唐詩/json/240.json','["農臣何所怨，乃欲幹人主。不識天地心，徒然怨風雨。", "將論草木患，欲說昆蟲苦。巡迴宮闕傍，其意無由吐。", "一朝哭都市，淚盡歸田畝。謠頌若采之，此言當可取。"]'),
('yuding-29','系樂府十二首：謝大龜','元結','唐','御定全唐诗','yuding','','[]','客來自江漢，雲得雙大龜。且言龜甚靈，問我君何疑。',72,'御定全唐詩/json/240.json','["客來自江漢，雲得雙大龜。且言龜甚靈，問我君何疑。", "自昔保方正，顧嘗無妄私。順和固鄙分，全守真常規。", "行之恐不及，此外將何為。惠恩如可謝，占問敢終辭。"]'),
('yuding-30','系樂府十二首：古遺歎','元結','唐','御定全唐诗','yuding','','[]','古昔有遺歎，所歎何所為。有國遺賢臣，萬事為冤悲。',72,'御定全唐詩/json/240.json','["古昔有遺歎，所歎何所為。有國遺賢臣，萬事為冤悲。", "所遺非遺望，所遺非可遺。所遺非遺用，所遺在遺之。", "嗟嗟山海客，全獨竟何辭。心非膏濡類，安得無不遺。"]'),
('yuding-31','系樂府十二首：下客謠','元結','唐','御定全唐诗','yuding','','[]','下客無黃金，豈思主人憐。客言勝黃金，主人然不然。',72,'御定全唐詩/json/240.json','["下客無黃金，豈思主人憐。客言勝黃金，主人然不然。", "珠玉成彩翠，綺羅如嬋娟。終恐見斯好，有時去君前。", "豈知保忠信，長使令德全。風聲與時茂，歌頌萬千年。"]'),
('yuding-32','漫歌八曲：故城東','元結','唐','御定全唐诗','yuding','','[]','漫惜故城東，良田野草生。說向縣大夫，大夫勸我耕。',48,'御定全唐詩/json/240.json','["漫惜故城東，良田野草生。說向縣大夫，大夫勸我耕。", "耕者我為先，耕者相次焉。誰愛故城東，今為近郭田。"]'),
('yuding-33','漫歌八曲：西陽城','元結','唐','御定全唐诗','yuding','','[]','江北有大洲，洲上堪力耕。此中宜五穀，不及西陽城。',48,'御定全唐詩/json/240.json','["江北有大洲，洲上堪力耕。此中宜五穀，不及西陽城。", "城畔多野桑，城中多古荒。衣食可力求，此外何所望。"]'),
('yuding-34','漫歌八曲：大回中','元結','唐','御定全唐诗','yuding','','[]','樊水欲東流，大江又北來。樊山當其南，此中為大回。',48,'御定全唐詩/json/240.json','["樊水欲東流，大江又北來。樊山當其南，此中為大回。", "回中魚好遊，回中多釣舟。漫欲作漁人，終焉無所求。"]'),
('yuding-35','漫歌八曲：小回中','元結','唐','御定全唐诗','yuding','','[]','叢石橫大江，人言是釣台。水石相沖激，此中為小回。',48,'御定全唐詩/json/240.json','["叢石橫大江，人言是釣台。水石相沖激，此中為小回。", "回中浪不惡，複在武昌郭。來客去客船，皆向此中泊。"]'),
('yuding-36','漫歌八曲：將牛何處去二首','元結','唐','御定全唐诗','yuding','','[]','將牛何處去，耕彼故城東。相伴有田父，相歡惟牧童。',48,'御定全唐詩/json/240.json','["將牛何處去，耕彼故城東。相伴有田父，相歡惟牧童。", "將牛何處去，耕彼西陽城。叔閑修農具，直者伴我耕。"]'),
('yuding-37','漫歌八曲：將船何處去二首','元結','唐','御定全唐诗','yuding','','[]','將船何處去，釣彼大回中。叔靜能鼓橈，正者隨弱翁。',48,'御定全唐詩/json/240.json','["將船何處去，釣彼大回中。叔靜能鼓橈，正者隨弱翁。", "將船何處去，送客小回南。有時逢惡客，還家亦少酣。"]'),
('yuding-38','引極三首：思元極','元結','唐','御定全唐诗','yuding','','[]','天曠莽兮杳泱茫，氣浩浩兮色蒼蒼。上何有兮人不測，',48,'御定全唐詩/json/240.json','["天曠莽兮杳泱茫，氣浩浩兮色蒼蒼。上何有兮人不測，", "思不從兮空自傷，心慅bj兮意惶懹。思假翼兮鸞鳳，"]'),
('yuding-39','引極三首：望仙府','元結','唐','御定全唐诗','yuding','','[]','山鑿落兮眇嶔岑，雲溶溶兮木棽棽。中何有兮人不睹，',47,'御定全唐詩/json/240.json','["山鑿落兮眇嶔岑，雲溶溶兮木棽棽。中何有兮人不睹，", "望不從兮知如何，心混混兮意渾和。思假足兮虎豹，"]'),
('yuding-40','引極三首：懷潛君','元結','唐','御定全唐诗','yuding','','[]','海浩淼兮汩洪溶，流蘊蘊兮濤洶洶。下何有兮人不聞，',47,'御定全唐詩/json/240.json','["海浩淼兮汩洪溶，流蘊蘊兮濤洶洶。下何有兮人不聞，", "思不從兮空踟躕，心回迷兮意縈紆。思假鱗兮鯤龍，"]'),
('yuding-41','演興四首：招太靈','元結','唐','御定全唐诗','yuding','','[]','招太靈兮山之巔，山屹dB兮水淪漣。祠之襰兮眇何年，',62,'御定全唐詩/json/240.json','["招太靈兮山之巔，山屹dB兮水淪漣。祠之襰兮眇何年，", "禧太靈兮端清，予願致夫精誠。久愵兮cJ々，", "望太靈兮儼而安，澹油溶兮都清閒。"]'),
('yuding-42','演興四首：初祀','元結','唐','御定全唐诗','yuding','','[]','山之乳兮葺太祠，木孫為桷兮木母榱。',69,'御定全唐詩/json/240.json','["山之乳兮葺太祠，木孫為桷兮木母榱。", "雲纓為dT兮愚木栭。洞淵禪兮揭巍巍。塗木蘭兮蒔糅蔫，", "翹修釤兮掉蕪殳，靈巫rw兮舞顒幹。薦天ed兮酒陽泉，"]'),
('yuding-43','演興四首：訟木魅','元結','唐','御定全唐诗','yuding','','[]','登高峰兮俯幽谷，心悴悴兮念群木。見樗栲兮相陰覆，',191,'御定全唐詩/json/240.json','["登高峰兮俯幽谷，心悴悴兮念群木。見樗栲兮相陰覆，", "槢橈橈兮未堅，椲桹桹兮可屈。", "櫁du樽兮不香，拔豐茸兮已實。豈元化之不均兮，", "儓予莫識天地之意兮，願截惡木之根，傾梟獍之古巢，", "實非吾心之不仁惠也，豈恥夫善惡之相紛。", "且欲畚三河之膏壤，裨濟水之清漣。將封灌乎善木，", "取方所以柯如兮，吾將出於南荒。求壽藤與蟠木，", "且憂顒之翩翩，又愁狖之賓士。及陰陽兮不和，", "重嗟惋兮何補，每齊心以精意。切援祝於神明，"]'),
('yuding-44','演興四首：閔嶺中','元結','唐','御定全唐诗','yuding','','[]','□群山以延想，吾獨閔乎嶺中。彼嶺中兮何有，',177,'御定全唐詩/json/240.json','["□群山以延想，吾獨閔乎嶺中。彼嶺中兮何有，", "欲采之以將壽，眇不知夫所從。大淵蘊蘊兮絕嶘岌岌，", "彼妖精兮變怪，必假見於風雨。常閃閃而伺人，", "久懹懹以ck惋，卻遲回而永歎。懼大靈兮不知，", "則必蒙皮篻以為矢，弦毋筱以為弧。化毒銅以為戟，", "且舂刺乎惡毒，又引射夫妖怪。盡群類兮使無，", "入嶺中而登玉峰，極閟絕而求翠茸。將吾壽兮隨所從，", "空仰訟于上玄，彼至精兮必應。甯古有而今無，"]'),
('yuding-0','閔荒詩','元結','唐','御定全唐诗','yuding','','[]','煬皇嗣君位，隋德滋昏幽。日作及身禍，以為長世謀。',289,'御定全唐詩/json/241.json','["煬皇嗣君位，隋德滋昏幽。日作及身禍，以為長世謀。", "居常恥前王，不思天子游。意欲出明堂，便登浮海舟。", "令行山川改，功與玄造侔。河淮可支合，峰gH生回溝。", "封隕下澤中，作山防逸流。船舲狀龍鷁，若負宮闕浮。", "荒娛未央極，始到滄海頭。忽見海門山，思作望海樓。", "不知新都城，已為征戰丘。當時有遺歌，歌曲太冤愁。", "四海非天獄，何為非天囚。天囚正兇忍，為我萬姓讎。", "人將引天釤，人將持天鎪。所欲充其心，相與絕悲憂。", "自得隋人歌，每為隋君羞。欲歌當陽春，似覺天下秋。", "更歌曲未終，如有怨氣浮。奈何昏王心，不覺此怨尤。", "遂令一夫唱，四海欣提矛。吾聞古賢君，其道常靜柔。", "慈惠恐不足，端和忘所求。嗟嗟有隋氏，惛惛誰與儔。"]'),
('yuding-1','忝官引','元結','唐','御定全唐诗','yuding','','[]','天下昔無事，僻居養愚鈍。山野性所安，熙然自全順。',252,'御定全唐詩/json/241.json','["天下昔無事，僻居養愚鈍。山野性所安，熙然自全順。", "忽逢暴兵起，閭巷見軍陣。將家瀛海濱，自棄同芻糞。", "往在幹元初，聖人啟休運。公車詣魏闕，天子垂清問。", "敢誦王者箴，亦獻當時論。朝廷愛方直，明主嘉忠信。", "屢授不次官，曾與專征印。兵家未曾學，榮利非所徇。", "偶得凶醜降，功勞愧方寸。爾來將四歲，慚恥言可盡。", "請取冤者辭，為吾忝官引。冤辭何者苦，萬邑餘灰燼。", "冤辭何者悲，生人盡鋒刃。冤辭何者甚，力役遇勞困。", "冤辭何者深，孤弱亦哀恨。無謀救冤者，祿位安可近。", "而可愛軒裳，其心又幹進。此言非所戒，此言敢貽訓。", "實欲辭無能，歸耕守吾分。"]'),
('yuding-2','舂陵行','元結','唐','御定全唐诗','yuding','','[]','軍國多所需，切責在有司。有司臨郡縣，刑法競欲施。',276,'御定全唐詩/json/241.json','["軍國多所需，切責在有司。有司臨郡縣，刑法競欲施。", "供給豈不憂，征斂又可悲。州小經亂亡，遺人實困疲。", "大鄉無十家，大族命單羸。朝餐是草根，暮食仍木皮。", "出言氣欲絕，意速行步遲。追呼尚不忍，況乃鞭撲之。", "郭亭傳急符，來往跡相追。更無寬大恩，但有迫促期。", "欲令鬻兒女，言發恐亂隨。悉使索其家，而又無生資。", "聽彼道路言，怨傷誰複知。去冬山賊來，殺奪幾無遺。", "所願見王官，撫養以惠慈。奈何重驅逐，不使存活為。", "安人天子命，符節我所持。州縣忽亂亡，得罪複是誰。", "逋緩違詔令，蒙責固其宜。前賢重守分，惡以禍福移。", "亦雲貴守官，不愛能適時。顧惟孱弱者，正直當不虧。", "何人采國風，吾欲獻此辭。"]'),
('yuding-3','賊退示官吏','元結','唐','御定全唐诗','yuding','','[]','昔歲逢太平，山林二十年。泉源在庭戶，洞壑當門前。',144,'御定全唐詩/json/241.json','["昔歲逢太平，山林二十年。泉源在庭戶，洞壑當門前。", "井稅有常期，日晏猶得眠。忽然遭世變，數歲親戎旃。", "今來典斯郡，山夷又紛然。城小賊不屠，人貧傷可憐。", "是以陷鄰境，此州獨見全。使臣將王命，豈不如賊焉。", "今彼征斂者，迫之如火煎。誰能絕人命，以作時世賢。", "思欲委符節，引竿自刺船。將家就魚麥，歸老江湖邊。"]'),
('yuding-4','寄源休','元結','唐','御定全唐诗','yuding','','[]','天下未偃兵，儒生預戎事。功勞安可問，且有忝官累。',96,'御定全唐詩/json/241.json','["天下未偃兵，儒生預戎事。功勞安可問，且有忝官累。", "昔常以荒浪，不敢學為吏。況當在兵家，言之豈容易。", "忽然向三嶺，境外為偏帥。時多尚矯詐，進退多欺貳。", "縱有一直方，則上似奸智。誰為明信者，能辨此勞畏。"]'),
('yuding-5','雪中懷孟武昌','元結','唐','御定全唐诗','yuding','','[]','冬來三度雪，農者歡歲稔。我麥根已濡，各得在倉廩。',96,'御定全唐詩/json/241.json','["冬來三度雪，農者歡歲稔。我麥根已濡，各得在倉廩。", "天寒未能起，孺子驚人寢。雲有山客來，籃中見冬簟。", "燒柴為溫酒，煮鱖為作沈。客亦愛杯尊，思君共杯飲。", "所嗟山路閑，時節寒又甚。不能苦相邀，興盡還就枕。"]'),
('yuding-6','與黨評事','元結','唐','御定全唐诗','yuding','','[]','自顧無功勞，一歲官再遷。局身班次中，常竊愧恥焉。',108,'御定全唐詩/json/241.json','["自顧無功勞，一歲官再遷。局身班次中，常竊愧恥焉。", "加以久荒浪，惛愚性頗全。未知在冠冕，不合無拘牽。", "勤強所不及，于人或未然。豈忘惠君子，恕之識見偏。", "且欲因我心，順為理化先。彼雲萬物情，有願隨所便。", "愛君得自遂，令我空淵禪。"]'),
('yuding-7','與黨侍禦','元結','唐','御定全唐诗','yuding','','[]','眾坐吾獨歡，或問歡為誰。高人党茂宗，複來官憲司。',168,'御定全唐詩/json/241.json','["眾坐吾獨歡，或問歡為誰。高人党茂宗，複來官憲司。", "昔吾順元和，與世行自遺。茂宗正作吏，日有趨走疲。", "及吾汙冠冕，茂宗方矯時。誚吾順讓者，乃是幹進資。", "今將問茂宗，茂宗欲何辭。若雲吾無心，此來複何為。", "若雲吾有羞，於此還見嗤。誰言萬類心，閑之不可窺。", "吾欲喻茂宗，茂宗宜聽之。長轅有修轍，馭者令爾馳。", "山谷安可怨，筋力當自悲。嗟嗟党茂宗，可為識者規。"]'),
('yuding-8','與瀼溪鄰里','元結','唐','御定全唐诗','yuding','','[]','昔年苦逆亂，舉族來南奔。日行幾十裏，愛君此山村。',120,'御定全唐詩/json/241.json','["昔年苦逆亂，舉族來南奔。日行幾十裏，愛君此山村。", "峰穀呀回映，誰家無泉源。修竹多夾路，扁舟皆到門。", "瀼溪中曲濱，其陽有閑園。鄰里昔贈我，許之及子孫。", "我嘗有匱乏，鄰里能相分。我嘗有不安，鄰里能相存。", "斯人轉貧弱，力役非無冤。終以瀼濱訟，無令天下論。"]'),
('yuding-9','招孟武昌','元結','唐','御定全唐诗','yuding','','[]','風霜枯萬物，退谷如春時。窮冬涸江海，杯湖澄清漪。',144,'御定全唐詩/json/241.json','["風霜枯萬物，退谷如春時。窮冬涸江海，杯湖澄清漪。", "湖盡到谷口，單船近階墀。湖中更何好，坐見大江水。", "欹石為水涯，半山在湖裏。谷口更何好，絕壑流寒泉。", "松桂蔭茅舍，白雲生坐邊。武昌不幹進，武昌人不厭。", "退谷正可遊，杯湖任來泛。湖上有水鳥，見人不飛鳴。", "穀口有山獸，往往隨人行。莫將車馬來，令我鳥獸驚。"]'),
('yuding-10','招陶別駕家陽華作','元結','唐','御定全唐诗','yuding','','[]','海內厭兵革，騷騷十二年。陽華洞中人，似不知亂焉。',180,'御定全唐詩/json/241.json','["海內厭兵革，騷騷十二年。陽華洞中人，似不知亂焉。", "誰能家此地，終老可自全。草堂背岩洞，幾峰軒戶前。", "清渠匝庭堂，出門仍灌田。半崖磐石徑，高亭臨極巔。", "引望見何處，迤逶隴北川。杉松幾萬株，蒼蒼滿前山。", "岩高曖華陽，飛溜何潺潺。洞深迷遠近，但覺多洄淵。", "晝遊興未盡，日暮不欲眠。探燭飲洞中，醉昏漱寒泉。", "始知天下心，耽愛各有偏。陶家世高逸，公忍不獨然。", "無或畢婚嫁，竟為俗務牽。"]'),
('yuding-11','游石溪示學者','元結','唐','御定全唐诗','yuding','','[]','小溪在城下，形勝堪賞愛。尤宜春水滿，水石更殊怪。',96,'御定全唐詩/json/241.json','["小溪在城下，形勝堪賞愛。尤宜春水滿，水石更殊怪。", "長山勢回合，井邑相縈帶。石林繞舜祠，西南正相對。", "階庭無爭訟，郊境罷守衛。時時溪上來，勸引辭學輩。", "今誰不務武，儒雅道將廢。豈忘二三子，旦夕相勉勵。"]'),
('yuding-12','遊潓泉示泉上學者','元結','唐','御定全唐诗','yuding','','[]','顧吾漫浪久，不欲有所拘。每到潓泉上，情性可安舒。',96,'御定全唐詩/json/241.json','["顧吾漫浪久，不欲有所拘。每到潓泉上，情性可安舒。", "草堂在山曲，澄瀾涵階除。松竹陰幽徑，清源湧坐隅。", "築塘列圃畦，引流灌時蔬。複在郊郭外，正堪靜者居。", "愜心則自適，喜尚人或殊。此中若可安，不服銅虎符。"]'),
('yuding-13','喻瀼溪鄉舊遊','元結','唐','御定全唐诗','yuding','','[]','往年在瀼濱，瀼人皆忘情。今來遊瀼鄉，瀼人見我驚。',108,'御定全唐詩/json/241.json','["往年在瀼濱，瀼人皆忘情。今來遊瀼鄉，瀼人見我驚。", "我心與瀼人，豈有辱與榮。瀼人異其心，應為我冠纓。", "昔賢惡如此，所以辭公卿。貧窮老鄉裏，自休還力耕。", "況曾經逆亂，日厭聞戰爭。尤愛一溪水，而能存讓名。", "終當來其濱，飲啄全此生。"]'),
('yuding-14','喻舊部曲','元結','唐','御定全唐诗','yuding','','[]','漫遊樊水陰，忽見舊部曲。尚言軍中好，猶望有所屬。',84,'御定全唐詩/json/241.json','["漫遊樊水陰，忽見舊部曲。尚言軍中好，猶望有所屬。", "故令爭者心，至死終不足。與之一杯酒，喻使燒戎服。", "兵興向十年，所見堪歎哭。相逢是遺人，當合識榮辱。", "勸汝學全生，隨我畬退穀。"]'),
('yuding-15','喻常吾直','元結','唐','御定全唐诗','yuding','','[]','山澤多饑人，閭裏多壞屋。戰爭且未息，征斂何時足。',96,'御定全唐詩/json/241.json','["山澤多饑人，閭裏多壞屋。戰爭且未息，征斂何時足。", "不能救人患，不合食天粟。何況假一官，而苟求其祿。", "近年更長吏，數月未為速。來者罷而官，豈得不為辱。", "勸為辭府主，從我游退穀。穀中有寒泉，為爾洗塵服。"]'),
('yuding-16','漫問相裏黃州','元結','唐','御定全唐诗','yuding','','[]','東鄰有漁父，西鄰有山僧。各問其性情，變之俱不能。',96,'御定全唐詩/json/241.json','["東鄰有漁父，西鄰有山僧。各問其性情，變之俱不能。", "公為二千石，我為山海客。志業豈不同，今已殊名跡。", "相裏不相類，相友且相異。何況天下人，而欲同其意。", "人意苟不同，分寸不相容。漫問軒裳客，何如耕釣翁。"]'),
('yuding-17','酬裴雲客','元結','唐','御定全唐诗','yuding','','[]','自厭久荒浪，于時無所任。耕釣以為事，來家樊水陰。',84,'御定全唐詩/json/241.json','["自厭久荒浪，于時無所任。耕釣以為事，來家樊水陰。", "甚醉或漫歌，甚閑亦漫吟。不知愚僻意，稱得雲客心。", "雲客方持斧，與人正相臨。符印隨坐起，守位常森森。", "縱能有相招，豈暇來山林。"]'),
('yuding-18','酬孟武昌苦雪','元結','唐','御定全唐诗','yuding','','[]','積雪閑山路，有人到庭前。雲是孟武昌，令獻苦雪篇。',228,'御定全唐詩/json/241.json','["積雪閑山路，有人到庭前。雲是孟武昌，令獻苦雪篇。", "長吟未及終，不覺為淒然。古之賢達者，與世竟何異。", "不能救時患，諷諭以全意。知公惜春物，豈非愛時和。", "知公苦陰雪，傷彼災患多。奸凶正驅馳，不合問君子。", "林鶯與野獸，無乃怨於此。兵興向九歲，稼穡誰能憂。", "何時不發卒，何日不殺牛。耕者日已少，耕牛日已希。", "皇天複何忍，更又恐斃之。自經危亂來，觸物堪傷歎。", "見君問我意，只益胸中亂。山禽饑不飛，山木凍皆折。", "懸泉化為冰，寒水近不熱。出門望天地，天地皆昏昏。", "時見雙峰下，雪中生白雲。"]'),
('yuding-19','漫酬賈沔州','元結','唐','御定全唐诗','yuding','','[]','往年壯心在，嘗欲濟時難。奉詔舉州兵，令得誅暴叛。',228,'御定全唐詩/json/241.json','["往年壯心在，嘗欲濟時難。奉詔舉州兵，令得誅暴叛。", "上將屢顛覆，偏師嘗救亂。未曾弛戈甲，終日領簿案。", "出入四五年，憂勞忘昏旦。無謀靜凶醜，自覺愚且懦。", "豈欲皂櫪中，爭食麧與藖。去年辭職事，所懼貽憂患。", "天子許安親，官又得閒散。自家樊水上，性情尤荒慢。", "雲山與水木，似不憎吾漫。以茲忘時世，日益無畏憚。", "漫醉人不嗔，漫眠人不喚。漫遊無遠近，漫樂無早晏。", "漫中漫亦忘，名利誰能算。聞君勸我意，為君一長歎。", "人誰年八十，我已過其半。家中孤弱子，長子未及冠。", "且為兒童主，種藥老溪澗。"]'),
('yuding-20','送孟校書往南海','元結','唐','御定全唐诗','yuding','','[]','吾聞近南海，乃是魑魅鄉。忽見孟夫子，歡然游此方。',84,'御定全唐詩/json/241.json','["吾聞近南海，乃是魑魅鄉。忽見孟夫子，歡然游此方。", "忽喜海風來，海帆又欲張。漂漂隨所去，不念歸路長。", "君有失母兒，愛之似阿陽。始解隨人行，不欲離君傍。", "相勸早旋歸，此言慎勿忘。"]'),
('yuding-21','別何員外','元結','唐','御定全唐诗','yuding','','[]','誰能守清躅，誰能嗣世儒。吾見何君饒，為人有是夫。',144,'御定全唐詩/json/241.json','["誰能守清躅，誰能嗣世儒。吾見何君饒，為人有是夫。", "黜官二十年，未曾暫崎嶇。終不病貧賤，寥寥無所拘。", "忽然逢知己，數月領官符。猶是尚書郎，收賦來江湖。", "人皆悉蒼生，隨意極所須。比盜無兵甲，似偷又不如。", "公能獨寬大，使之力自輸。吾欲探時謠，為公伏奏書。", "但恐抵忌諱，未知肯聽無。不然且相送，醉歡於坐隅。"]'),
('yuding-22','宴湖上亭作','元結','唐','御定全唐诗','yuding','','[]','廣亭蓋小湖，湖亭實清曠。軒窗幽水石，怪異尤難狀。',120,'御定全唐詩/json/241.json','["廣亭蓋小湖，湖亭實清曠。軒窗幽水石，怪異尤難狀。", "石尊能寒酒，寒水宜初漲。岸曲坐客稀，杯浮上搖漾。", "遠水入簾幕，淅瀝吹酒舫。欲去未回時，飄飄正堪望。", "酣興思共醉，促酒更相向。舫去若驚鳧，溶瀛滿湖浪。", "朝來暮忘返，暮歸獨惆悵。誰肯愛林泉，從吾老湖上。"]'),
('yuding-23','夜宴石魚湖作','元結','唐','御定全唐诗','yuding','','[]','風霜雖慘然，出遊熙天正。登臨日暮歸，置酒湖上亭。',120,'御定全唐詩/json/241.json','["風霜雖慘然，出遊熙天正。登臨日暮歸，置酒湖上亭。", "高燭照泉深，光華溢軒楹。如見海底日，曈曈始欲生。", "夜寒閉窗戶，石溜何清泠。若在深洞中，半崖聞水聲。", "醉人疑舫影，呼指遞相驚。何故有雙魚，隨吾酒舫行。", "醉昏能誕語，勸醉能忘情。坐無拘忌人，勿限醉與醒。"]'),
('yuding-24','劉侍禦月夜宴會','元結','唐','御定全唐诗','yuding','','[]','我從蒼梧來，將耕舊山田。踟躕為故人，且複停歸船。',96,'御定全唐詩/json/241.json','["我從蒼梧來，將耕舊山田。踟躕為故人，且複停歸船。", "日夕得相從，轉覺和樂全。愚愛涼風來，明月正滿天。", "河漢望不見，幾星猶粲然。中夜興欲酣，改坐臨清川。", "未醉恐天旦，更歌促繁弦。歡娛不可逢，請君莫言旋。"]'),
('yuding-25','樊上漫作','元結','唐','御定全唐诗','yuding','','[]','漫家郎亭下，複在樊水邊。去郭五六裏，扁舟到門前。',72,'御定全唐詩/json/241.json','["漫家郎亭下，複在樊水邊。去郭五六裏，扁舟到門前。", "山竹繞茅舍，庭中有寒泉。西邊雙石峰，引望堪忘年。", "四鄰皆漁父，近渚多閒田。且欲學耕釣，於斯求老焉。"]'),
('yuding-26','登殊亭作','元結','唐','御定全唐诗','yuding','','[]','時節方大暑，試來登殊亭。憑軒未及息，忽若秋氣生。',96,'御定全唐詩/json/241.json','["時節方大暑，試來登殊亭。憑軒未及息，忽若秋氣生。", "主人既多閑，有酒共我傾。坐中不相異，豈恨醉與醒。", "漫歌無人聽，浪語無人驚。時複一回望，心目出四溟。", "誰能守纓佩，日與災患並。請君誦此意，令彼惑者聽。"]'),
('yuding-27','石魚湖上作','元結','唐','御定全唐诗','yuding','','[]','吾愛石魚湖，石魚在湖裏。魚背有酒樽，繞魚是湖水。',96,'御定全唐詩/json/241.json','["吾愛石魚湖，石魚在湖裏。魚背有酒樽，繞魚是湖水。", "兒童作小舫，載酒勝一杯。座中令酒舫，空去複滿來。", "湖岸多欹石，石下流寒泉。醉中一盥漱，快意無比焉。", "金玉吾不須，軒冕吾不愛。且欲坐湖畔，石魚長相對。"]'),
('yuding-28','引東泉作','元結','唐','御定全唐诗','yuding','','[]','東泉人未知，在我左山東。引之傍山來，垂流落庭中。',97,'御定全唐詩/json/241.json','["東泉人未知，在我左山東。引之傍山來，垂流落庭中。", "宿霧含朝光，掩映如殘虹。有時散成雨，飄灑隨清風。", "眾源發淵竇，殊怪皆不同。此流又高懸，rT々在長空。", "山林何處無，茲地不可逢。吾欲解纓佩，便為泉上翁。"]'),
('yuding-29','登白雲亭','元結','唐','御定全唐诗','yuding','','[]','出門見南山，喜逐松徑行。窮高欲極遠，始到白雲亭。',120,'御定全唐詩/json/241.json','["出門見南山，喜逐松徑行。窮高欲極遠，始到白雲亭。", "長山繞井邑，登望宜新晴。州渚曲湘水，縈回隨郡城。", "九疑千萬峰，嵺嵺天外青。煙雲無遠近，皆傍林嶺生。", "俯視松竹間，石水何幽清。涵映滿軒戶，娟娟如鏡明。", "何人病惛濃，積醉且未醒。與我一登臨，為君安性情。"]'),
('yuding-30','潓陽亭作','元結','唐','御定全唐诗','yuding','','[]','問吾常宴息，泉上何處好。獨有潓陽亭，令人可終老。',120,'御定全唐詩/json/241.json','["問吾常宴息，泉上何處好。獨有潓陽亭，令人可終老。", "前軒臨潓泉，憑幾漱清流。外物自相擾，淵淵還複休。", "有時出東戶，更欲簷下坐。非我意不行，石渠能留我。", "峰石若鱗次，欹垂複旋回。為我引潓泉，泠泠簷下來。", "天寒宜泉溫，泉寒宜天暑。誰到潓陽亭，其心肯思去。"]'),
('yuding-31','登九疑第二峰','元結','唐','御定全唐诗','yuding','','[]','九疑第二峰，其上有仙壇。杉松映飛泉，蒼蒼在雲端。',72,'御定全唐詩/json/241.json','["九疑第二峰，其上有仙壇。杉松映飛泉，蒼蒼在雲端。", "何人居此處，雲是魯女冠。不知幾百歲，燕坐餌金丹。", "相傳羽化時，雲鶴滿峰戀。婦中有高人，相望空長歎。"]'),
('yuding-32','題孟中丞茅閣','元結','唐','御定全唐诗','yuding','','[]','小山為郡城，隨水能縈紆。亭亭最高處，今是西南隅。',144,'御定全唐詩/json/241.json','["小山為郡城，隨水能縈紆。亭亭最高處，今是西南隅。", "杉大老猶在，蒼蒼數十株。垂陰滿城上，枝葉何扶疏。", "乃知四海中，遺事誰謂無。及觀茅閣成，始覺形勝殊。", "憑軒望熊湘，雲榭連蒼梧。天下正炎熱，此然冰雪俱。", "客有在中坐，頌歌複何如。公欲舉遺材，如此佳木歟。", "公方庇蒼生，又如斯閣乎。請達謠頌聲，願公且踟躕。"]'),
('yuding-33','窊尊詩','元結','唐','御定全唐诗','yuding','','[]','巉巉小山石，數峰對窊亭。窊石堪為樽，狀類不可名。',156,'御定全唐詩/json/241.json','["巉巉小山石，數峰對窊亭。窊石堪為樽，狀類不可名。", "巡迴數尺間，如見小蓬瀛。尊中酒初漲，始有島嶼生。", "豈無日觀峰，直下臨滄溟。愛之不覺醉，醉臥還自醒。", "醒醉在尊畔，始為吾性情。若以形勝論，坐隅臨郡城。", "平湖近階砌，近山複青青。異木幾十株，林條冒簷楹。", "盤根滿石上，皆作龍蛇形。酒堂貯釀器，戶牖皆罌瓶。", "此尊可常滿，誰是陶淵明。"]'),
('yuding-34','朝陽岩下歌','元結','唐','御定全唐诗','yuding','','[]','朝陽岩下湘水深，朝陽洞口寒泉清。零陵城郭夾湘岸，',40,'御定全唐詩/json/241.json','["朝陽岩下湘水深，朝陽洞口寒泉清。零陵城郭夾湘岸，", "水石為娛安可羨，長歌一曲留相勸。"]'),
('yuding-35','無為洞口作','元結','唐','御定全唐诗','yuding','','[]','無為洞口春水滿，無為洞傍春雲白。愛此踟躕不能去，',40,'御定全唐詩/json/241.json','["無為洞口春水滿，無為洞傍春雲白。愛此踟躕不能去，", "欲問其心不能問，我到山中得無悶。"]'),
('yuding-36','宿無為觀','元結','唐','御定全唐诗','yuding','','[]','九疑山深幾千里，峰穀崎嶇人不到。山中舊有仙姥家，',40,'御定全唐詩/json/241.json','["九疑山深幾千里，峰穀崎嶇人不到。山中舊有仙姥家，", "霓裳羽蓋傍臨壑，飄颻似欲來雲鶴。"]'),
('yuding-37','宿洄溪翁宅','元結','唐','御定全唐诗','yuding','','[]','長松萬株繞茅舍，怪石寒泉近岩下。老翁八十猶能行，',40,'御定全唐詩/json/241.json','["長松萬株繞茅舍，怪石寒泉近岩下。老翁八十猶能行，", "時俗是非何足道，得似老翁吾即休。"]'),
('yuding-38','說洄溪招退者','元結','唐','御定全唐诗','yuding','','[]','長松亭亭滿四山，山間乳竇流清泉。洄溪正在此山裏，',88,'御定全唐詩/json/241.json','["長松亭亭滿四山，山間乳竇流清泉。洄溪正在此山裏，", "糜色如珈玉液酒，酒熟猶聞松節香。溪邊老翁年幾許，", "浯溪石下多泉源，盛暑大寒冬大溫。屠蘇宜在水中石，", "勿憚山深與地僻，羅浮尚有葛仙翁。"]'),
('yuding-39','宿丹崖翁宅','元結','唐','御定全唐诗','yuding','','[]','扁舟欲到瀧口湍，春水湍瀧上水難。投竿來泊丹崖下，',72,'御定全唐詩/json/241.json','["扁舟欲到瀧口湍，春水湍瀧上水難。投竿來泊丹崖下，", "泉流掩映在木杪。有若白鳥飛林間。往往隨風作霧雨，", "兒孫棹船抱酒甕，醉裏長歌揮釣車。吾將求退與翁遊，"]'),
('yuding-40','石魚湖上醉歌','元結','唐','御定全唐诗','yuding','','[]','石魚湖，似洞庭，夏水欲滿君山青。山為樽，水為沼，',40,'御定全唐詩/json/241.json','["石魚湖，似洞庭，夏水欲滿君山青。山為樽，水為沼，", "我持長瓢坐巴丘，酌飲四坐以散愁。"]'),
('yuding-41','橘井','元結','唐','御定全唐诗','yuding','','[]','靈橘無根井有泉，世間如夢又千年。鄉園不見重歸鶴，',40,'御定全唐詩/json/241.json','["靈橘無根井有泉，世間如夢又千年。鄉園不見重歸鶴，", "如何躡得蘇君跡，白日霓旌擁上天。"]'),
('yuding-42','石宮四詠','元結','唐','御定全唐诗','yuding','','[]','石宮春雲白，白雲宜蒼苔。拂雲踐石徑，俗士誰能來。',96,'御定全唐詩/json/241.json','["石宮春雲白，白雲宜蒼苔。拂雲踐石徑，俗士誰能來。", "石宮夏水寒，寒水宜高林。遠風吹蘿蔓，野客熙清陰。", "石宮秋氣清，清氣宜山谷。落葉逐霜風，幽人愛松竹。", "石宮冬日暖，暖日宜溫泉。晨光靜水霧，逸者猶安眠。"]'),
('yuding-43','欸乃曲五首','元結','唐','御定全唐诗','yuding','','[]','偶存名跡在人間，順俗與時未安閒。',160,'御定全唐詩/json/241.json','["偶存名跡在人間，順俗與時未安閒。", "來謁大官兼問政，扁舟卻入九疑山。", "湘江二月春水準，滿月和風宜夜行。", "唱橈欲過平陽戍，守吏相呼問姓名。", "千里楓林煙雨深，無朝無暮有猿吟。", "停橈靜聽曲中意，好是雲山韶濩音。", "零陵郡北湘水東，浯溪形勝滿湘中。", "溪口石顛堪自逸，誰能相伴作漁翁。", "下瀧船似入深淵，上瀧船似欲升天。", "瀧南始到九疑郡，應絕高人乘興船。"]'),
('yuding-0','郢城西樓吟','張繼','唐','御定全唐诗','yuding','','[]','連山盡塞水縈回，山上戍門臨水開。珠簾直下一百丈，',40,'御定全唐詩/json/242.json','["連山盡塞水縈回，山上戍門臨水開。珠簾直下一百丈，", "沙洲楓岸無來客，草綠花開山鳥鳴。"]'),
('yuding-1','登丹陽樓','張繼','唐','御定全唐诗','yuding','','[]','寒皋那可望，旅客又初還。迢遞高樓上，蕭疏涼野間。',48,'御定全唐詩/json/242.json','["寒皋那可望，旅客又初還。迢遞高樓上，蕭疏涼野間。", "暮晴依遠水，秋興屬連山。浮客時相見，霜凋朱翠顏。"]'),
('yuding-2','春夜皇甫冉宅歡宴','張繼','唐','御定全唐诗','yuding','','[]','流落時相見，悲歡共此情。興因尊酒洽，愁為故人輕。',48,'御定全唐詩/json/242.json','["流落時相見，悲歡共此情。興因尊酒洽，愁為故人輕。", "暗滴花莖露，斜暉月過城。那知橫吹笛，江外作邊聲。"]'),
('yuding-3','會稽秋晚奉呈于太守','張繼','唐','御定全唐诗','yuding','','[]','寂寂訟庭幽，森森戟戶秋。山光隱危堞，湖色上高樓。',48,'御定全唐詩/json/242.json','["寂寂訟庭幽，森森戟戶秋。山光隱危堞，湖色上高樓。", "禹穴探書罷，天臺作賦遊。雲浮將越客，歲晚共淹留。"]'),
('yuding-4','題嚴陵釣台','張繼','唐','御定全唐诗','yuding','','[]','舊隱人如在，清風亦似秋。客星沈夜壑，釣石俯春流。',48,'御定全唐詩/json/242.json','["舊隱人如在，清風亦似秋。客星沈夜壑，釣石俯春流。", "鳥向喬枝聚，魚依淺瀨遊。古來芳餌下，誰是不吞鉤。"]'),
('yuding-5','清明日自西午橋至瓜岩村有懷','張繼','唐','御定全唐诗','yuding','','[]','晚霽龍門雨，春生汝穴風。鳥啼官路靜，花發毀垣空。',48,'御定全唐詩/json/242.json','["晚霽龍門雨，春生汝穴風。鳥啼官路靜，花發毀垣空。", "鳴玉慚時輩，垂絲學老翁。舊遊人不見，惆悵洛城東。"]'),
('yuding-6','洛陽作','張繼','唐','御定全唐诗','yuding','','[]','洛陽天子縣，金谷石崇鄉。草色侵官道，花枝出苑牆。',48,'御定全唐詩/json/242.json','["洛陽天子縣，金谷石崇鄉。草色侵官道，花枝出苑牆。", "書成休逐客，賦罷遂為郎。貧賤非吾事，西游思自強。"]'),
('yuding-7','晚次淮陽','張繼','唐','御定全唐诗','yuding','','[]','微涼風葉下，楚俗轉清閒。候館臨秋水，郊扉掩暮山。',48,'御定全唐詩/json/242.json','["微涼風葉下，楚俗轉清閒。候館臨秋水，郊扉掩暮山。", "月明潮漸近，露濕雁初還。浮客了無定，萍流淮海間。"]'),
('yuding-8','送竇十九判官使江南','張繼','唐','御定全唐诗','yuding','','[]','遊客淹星紀，裁詩煉土風。今看乘傳去，那與問津同。',48,'御定全唐詩/json/242.json','["遊客淹星紀，裁詩煉土風。今看乘傳去，那與問津同。", "南郡迎徐子，臨川謁謝公。思歸一惆悵，于越古亭中。"]'),
('yuding-9','江上送客游廬山','張繼','唐','御定全唐诗','yuding','','[]','楚客自相送，沾裳春水邊。晚來風信好，併發上江船。',48,'御定全唐詩/json/242.json','["楚客自相送，沾裳春水邊。晚來風信好，併發上江船。", "花映新林岸，雲開瀑布泉。愜心應在此，佳句向誰傳。"]'),
('yuding-10','酬張二十員外前國子博士竇叔向','張繼','唐','御定全唐诗','yuding','','[]','故交日零落，心賞寄何人。幸與馮唐遇，心同跡複親。',48,'御定全唐詩/json/242.json','["故交日零落，心賞寄何人。幸與馮唐遇，心同跡複親。", "語言未終夕，離別又傷春。結念湓城下，聞猿詩興新。"]'),
('yuding-11','會稽郡樓雪霽','張繼','唐','御定全唐诗','yuding','','[]','江城昨夜雪如花，郢客登樓齊望華。夏禹壇前仍聚玉，',40,'御定全唐詩/json/242.json','["江城昨夜雪如花，郢客登樓齊望華。夏禹壇前仍聚玉，", "數處微明銷不盡，湖山清映越人家。"]'),
('yuding-12','馮翊西樓','張繼','唐','御定全唐诗','yuding','','[]','城上西樓倚暮天，樓中歸望正淒然。近郭亂山橫古渡，',40,'御定全唐詩/json/242.json','["城上西樓倚暮天，樓中歸望正淒然。近郭亂山橫古渡，", "陶令好文常對酒，相招那惜醉為眠。"]'),
('yuding-13','送鄒判官往陳留','張繼','唐','御定全唐诗','yuding','','[]','齊宋傷心地，頻年此用兵。女停襄邑杼，農廢汶陽耕。',72,'御定全唐詩/json/242.json','["齊宋傷心地，頻年此用兵。女停襄邑杼，農廢汶陽耕。", "國使乘軺去，諸侯擁節迎。深仁荷君子，薄賦恤黎甿。", "火燎原猶熱，波搖海未平。應將否泰理，一問魯諸生。"]'),
('yuding-14','酬李書記校書越城秋夜見贈','張繼','唐','御定全唐诗','yuding','','[]','東越秋城夜，西人白髮年。寒城警刁鬥，孤憤抱龍泉。',72,'御定全唐詩/json/242.json','["東越秋城夜，西人白髮年。寒城警刁鬥，孤憤抱龍泉。", "鳳輦棲岐下，鯨波鬥洛川。量空海陵粟，賜乏水衡錢。", "投閣嗤揚子，飛書代魯連。蒼蒼不可問，餘亦賦思玄。"]'),
('yuding-15','感懷','張繼','唐','御定全唐诗','yuding','','[]','調與時人背，心將靜者論。終年帝城裏，不識五侯門。',24,'御定全唐詩/json/242.json','["調與時人背，心將靜者論。終年帝城裏，不識五侯門。"]'),
('yuding-16','長相思','張繼','唐','御定全唐诗','yuding','','[]','遼陽望河縣，白首無由見。海上珊瑚枝，年年寄春燕。',24,'御定全唐詩/json/242.json','["遼陽望河縣，白首無由見。海上珊瑚枝，年年寄春燕。"]'),
('yuding-17','奉寄皇甫補闕','張繼','唐','御定全唐诗','yuding','','[]','京口情人別久，揚州估客來疏。',28,'御定全唐詩/json/242.json','["京口情人別久，揚州估客來疏。", "潮至潯陽回去，相思無處通書。"]'),
('yuding-18','楓橋夜泊','張繼','唐','御定全唐诗','yuding','','[]','月落烏啼霜滿天，江楓漁父對愁眠。',32,'御定全唐詩/json/242.json','["月落烏啼霜滿天，江楓漁父對愁眠。", "姑蘇城外寒山寺，夜半鐘聲到客船。"]'),
('yuding-19','閶門即事','張繼','唐','御定全唐诗','yuding','','[]','耕夫召募逐樓船，春草青青萬頃田。',32,'御定全唐詩/json/242.json','["耕夫召募逐樓船，春草青青萬頃田。", "試上吳門窺郡郭，清明幾處有新煙。"]'),
('yuding-20','安公房問法','張繼','唐','御定全唐诗','yuding','','[]','流年一日復一日，世事何時是了時。',32,'御定全唐詩/json/242.json','["流年一日復一日，世事何時是了時。", "試向東林問禪伯，遣將心地學琉璃。"]'),
('yuding-21','上清詞','張繼','唐','御定全唐诗','yuding','','[]','紫陽宮女捧丹砂，王母令過漢帝家。',32,'御定全唐詩/json/242.json','["紫陽宮女捧丹砂，王母令過漢帝家。", "春風不肯停仙馭，卻向蓬萊看杏花。"]'),
('yuding-22','送顧況泗上覲叔父','張繼','唐','御定全唐诗','yuding','','[]','吳鄉歲貢足嘉賓，後進之中見此人。',32,'御定全唐詩/json/242.json','["吳鄉歲貢足嘉賓，後進之中見此人。", "別業更臨洙泗上，擬將書卷對殘春。"]'),
('yuding-23','留別','張繼','唐','御定全唐诗','yuding','','[]','何事千年遇聖君，坐令雙鬢老江雲。',32,'御定全唐詩/json/242.json','["何事千年遇聖君，坐令雙鬢老江雲。", "南行更入山深淺，岐路悠悠水自分。"]'),
('yuding-24','送張中丞歸使幕','張繼','唐','御定全唐诗','yuding','','[]','獨受主恩歸，當朝似者稀。玉壺分禦酒，金殿賜春衣。',48,'御定全唐詩/json/242.json','["獨受主恩歸，當朝似者稀。玉壺分禦酒，金殿賜春衣。", "拂席流鶯醉，鳴鞭駿馬肥。滿台簪白筆，捧手戀清輝。"]'),
('yuding-25','華州夜宴庾侍禦宅','張繼','唐','御定全唐诗','yuding','','[]','世故他年別，心期此夜同。千峰孤燭外，片雨一更中。',48,'御定全唐詩/json/242.json','["世故他年別，心期此夜同。千峰孤燭外，片雨一更中。", "酒客逢山簡，詩人得謝公。自憐驅匹馬，拂曙向關東。"]'),
('yuding-26','贈章八元','張繼','唐','御定全唐诗','yuding','','[]','相見談經史，江樓坐夜闌。風聲吹戶響，燈影照人寒。',48,'御定全唐詩/json/242.json','["相見談經史，江樓坐夜闌。風聲吹戶響，燈影照人寒。", "俗薄交遊盡，時危出處難。衰年逢二妙，亦得悶懷寬。"]'),
('yuding-27','城西虎跑寺','張繼','唐','御定全唐诗','yuding','','[]','石勢虎蹲伏，山形龍屈盤。寺開梁殿閣，墳掩晉衣冠。',48,'御定全唐詩/json/242.json','["石勢虎蹲伏，山形龍屈盤。寺開梁殿閣，墳掩晉衣冠。", "出澗泉聲細，斜陽塔影寒。近城多□□，棲息此中安。"]'),
('yuding-28','褚主簿宅會畢庶子錢員外郎使君','張繼','唐','御定全唐诗','yuding','','[]','開甕臘酒熟，主人心賞同。斜陽疏竹上，殘雪亂山中。',36,'御定全唐詩/json/242.json','["開甕臘酒熟，主人心賞同。斜陽疏竹上，殘雪亂山中。", "更喜宣城印，朝廷與謝公。"]'),
('yuding-29','奉送王相公赴幽州','張繼','唐','御定全唐诗','yuding','','[]','黃閣開幃幄，丹墀拜冕旒。位高湯左相，權總漢諸侯。',72,'御定全唐詩/json/242.json','["黃閣開幃幄，丹墀拜冕旒。位高湯左相，權總漢諸侯。", "不改周南化，仍分趙北憂。雙旌過易水，千騎入幽州。", "塞草連天暮，邊風動地愁。無因隨遠道，結束佩吳鉤。"]'),
('yuding-30','重經巴丘','張繼','唐','御定全唐诗','yuding','','[]','昔年高接李膺歡，日泛仙舟醉碧瀾。詩句亂隨青草落，',40,'御定全唐詩/json/242.json','["昔年高接李膺歡，日泛仙舟醉碧瀾。詩句亂隨青草落，", "今日片帆城下去，秋風回首淚闌幹。"]'),
('yuding-31','九日巴丘楊公臺上宴集','張繼','唐','御定全唐诗','yuding','','[]','淒淒霜日上高臺，水國秋涼客思哀。萬疊銀山寒浪起，',40,'御定全唐詩/json/242.json','["淒淒霜日上高臺，水國秋涼客思哀。萬疊銀山寒浪起，", "江漢路長身不定，菊花三笑旅懷開。"]'),
('yuding-32','遊靈岩','張繼','唐','御定全唐诗','yuding','','[]','靈岩有路入煙霞，台殿高低釋子家。風滿回廊飄墜葉，',40,'御定全唐詩/json/242.json','["靈岩有路入煙霞，台殿高低釋子家。風滿回廊飄墜葉，", "誰謂無生真可學，山中亦自有年華。"]'),
('yuding-33','河間獻王墓','張繼','唐','御定全唐诗','yuding','','[]','漢家宗室獨稱賢，遺事閑中見舊編。偶過河間尋往跡，',40,'御定全唐詩/json/242.json','["漢家宗室獨稱賢，遺事閑中見舊編。偶過河間尋往跡，", "雅樂未興人已逝，雄歌依舊大風傳。"]'),
('yuding-34','秋日道中','張繼','唐','御定全唐诗','yuding','','[]','齊魯西風草樹秋，川原高下過東州。道邊白鶴來華表，',40,'御定全唐詩/json/242.json','["齊魯西風草樹秋，川原高下過東州。道邊白鶴來華表，", "徑行俯仰成今古，卻憶當年賦遠遊。"]'),
('yuding-35','華清宮','張繼','唐','御定全唐诗','yuding','','[]','天寶承平奈樂何，華清宮殿鬱嵯峨。朝元閣峻臨秦嶺，',40,'御定全唐詩/json/242.json','["天寶承平奈樂何，華清宮殿鬱嵯峨。朝元閣峻臨秦嶺，", "只今惟有溫泉水，嗚咽聲中感慨多。"]'),
('yuding-36','春申君祠','張繼','唐','御定全唐诗','yuding','','[]','春申祠宇空山裏，古柏陰陰石泉水。日暮江南無主人，',40,'御定全唐詩/json/242.json','["春申祠宇空山裏，古柏陰陰石泉水。日暮江南無主人，", "當時珠履三千客，趙使懷慚不敢言。"]'),
('yuding-37','人日代客子是日立春','張繼','唐','御定全唐诗','yuding','','[]','人日兼春日，長懷複短懷。遙知雙彩勝，並在一金釵。',24,'御定全唐詩/json/242.json','["人日兼春日，長懷複短懷。遙知雙彩勝，並在一金釵。"]'),
('yuding-38','寄鄭員外','張繼','唐','御定全唐诗','yuding','','[]','經月愁聞雨，新年苦憶君。何時共登眺，整屐待晴雲。',24,'御定全唐詩/json/242.json','["經月愁聞雨，新年苦憶君。何時共登眺，整屐待晴雲。"]'),
('yuding-39','飲李十二宅','張繼','唐','御定全唐诗','yuding','','[]','重門敞春夕，燈燭靄餘輝。醉我百尊酒，留連夜未歸。',24,'御定全唐詩/json/242.json','["重門敞春夕，燈燭靄餘輝。醉我百尊酒，留連夜未歸。"]'),
('yuding-40','山家','張繼','唐','御定全唐诗','yuding','','[]','板橋人渡泉聲，茅簷日午雞鳴。',28,'御定全唐詩/json/242.json','["板橋人渡泉聲，茅簷日午雞鳴。", "莫嗔焙茶煙暗，卻喜曬穀天晴。"]'),
('yuding-41','歸山','張繼','唐','御定全唐诗','yuding','','[]','心事數莖白髮，生涯一片青山。',28,'御定全唐詩/json/242.json','["心事數莖白髮，生涯一片青山。", "空林有雪相待，古道無人獨還。"]'),
('yuding-42','金谷園','張繼','唐','御定全唐诗','yuding','','[]','彩樓歌館正融融，一騎星飛錦帳空。',32,'御定全唐詩/json/242.json','["彩樓歌館正融融，一騎星飛錦帳空。", "老盡名花春不管，年年啼鳥怨東風。"]'),
('yuding-43','郵亭','張繼','唐','御定全唐诗','yuding','','[]','雲淡山橫日欲斜，郵亭下馬對殘花。',32,'御定全唐詩/json/242.json','["雲淡山橫日欲斜，郵亭下馬對殘花。", "自從身逐征西府，每到開時不在家。"]'),
('yuding-44','宿白馬寺','張繼','唐','御定全唐诗','yuding','','[]','白馬馱經事已空，斷碑殘刹見遺蹤。',32,'御定全唐詩/json/242.json','["白馬馱經事已空，斷碑殘刹見遺蹤。", "蕭蕭茅屋秋風起，一夜雨聲羈思濃。"]'),
('yuding-45','明德宮','張繼','唐','御定全唐诗','yuding','','[]','碧瓦朱楹白晝閑，金衣寶扇曉風寒。',32,'御定全唐詩/json/242.json','["碧瓦朱楹白晝閑，金衣寶扇曉風寒。", "摩雲觀閣高如許，長對河流出斷山。"]'),
('yuding-46','讀嶧山碑','張繼','唐','御定全唐诗','yuding','','[]','六國平來四海家，相君當代擅才華。',32,'御定全唐詩/json/242.json','["六國平來四海家，相君當代擅才華。", "誰知頌德山頭石，卻與他人戒後車。"]'),
('yuding-47','句','張繼','唐','御定全唐诗','yuding','','[]','漢月經時掩，胡塵與歲深。。',13,'御定全唐詩/json/242.json','["漢月經時掩，胡塵與歲深。。"]'),
('yuding-0','令狐員外宅宴寄中丞','韓翃','唐','御定全唐诗','yuding','','[]','寒色凝羅幕，同人清夜期。玉杯留醉處，銀燭送歸時。',36,'御定全唐詩/json/243.json','["寒色凝羅幕，同人清夜期。玉杯留醉處，銀燭送歸時。", "獨坐隔千里，空吟對雪詩。"]'),
('yuding-1','褚主簿宅會畢庶子錢員外郎使君','韓翃','唐','御定全唐诗','yuding','','[]','開甕臘酒熟，主人心賞同。斜陽疏竹上，殘雪亂天中。',36,'御定全唐詩/json/243.json','["開甕臘酒熟，主人心賞同。斜陽疏竹上，殘雪亂天中。", "更喜宣城印，朝廷與謝公。"]'),
('yuding-2','送李明府赴滑州','韓翃','唐','御定全唐诗','yuding','','[]','渭城寒食罷，送客歸遠道。烏帽背斜暉，青驪踏春草。',48,'御定全唐詩/json/243.json','["渭城寒食罷，送客歸遠道。烏帽背斜暉，青驪踏春草。", "酒醒孤燭夜，衣冷千山早。去事沈尚書，應憐詞賦好。"]'),
('yuding-3','送李司直赴江西使幕','韓翃','唐','御定全唐诗','yuding','','[]','斂版辭漢廷，進帆歸楚幕。三江城上轉，九裏人家泊。',96,'御定全唐詩/json/243.json','["斂版辭漢廷，進帆歸楚幕。三江城上轉，九裏人家泊。", "好酒近宜城，能詩謝康樂。雨晴西山樹，日出南昌郭。", "竹露點衣巾，湖煙濕扃鑰。主人蒼玉佩，後騎黃金絡。", "高視領八州，相期同一鶚。行當報知己，從此飛寥廓。"]'),
('yuding-4','祭嶽回重贈孟都督','韓翃','唐','御定全唐诗','yuding','','[]','封作天齊王，清祠太山下。魯公秋賽畢，曉日回高駕。',48,'御定全唐詩/json/243.json','["封作天齊王，清祠太山下。魯公秋賽畢，曉日回高駕。", "從騎盡幽並，同人皆沈謝。自矜文武足，一醉寒溪夜。"]'),
('yuding-5','送南少府歸壽春','韓翃','唐','御定全唐诗','yuding','','[]','人言壽春遠，此去先秋到。孤客小翼舟，諸生高翅帽。',48,'御定全唐詩/json/243.json','["人言壽春遠，此去先秋到。孤客小翼舟，諸生高翅帽。", "淮風生竹簟，楚雨移茶灶。若在八公山，題詩一相報。"]'),
('yuding-6','贈別崔司直赴江東兼簡常州獨孤使君','韓翃','唐','御定全唐诗','yuding','','[]','愛君青袍色，芳草能相似。官重法家流，名高墨曹吏。',96,'御定全唐詩/json/243.json','["愛君青袍色，芳草能相似。官重法家流，名高墨曹吏。", "春衣淮上宿，美酒江邊醉。楚酪沃雕胡，湘羹糝香餌。", "前朝山水國，舊日風流地。蘇山逐青驄，江家驅白鼻。", "右軍尚少年，三領東方騎。亦過小丹陽，應知百城貴。"]'),
('yuding-7','經月岩山','韓翃','唐','御定全唐诗','yuding','','[]','驅車過閩越，路出饒陽西。仙山翠如畫，簇簇生虹蜺。',120,'御定全唐詩/json/243.json','["驅車過閩越，路出饒陽西。仙山翠如畫，簇簇生虹蜺。", "群峰若侍從，眾阜如嬰提。岩巒互吞吐，嶺岫相追攜。", "中有月輪滿，皎潔如圓珪。玉皇恣遊覽，到此神應迷。", "嫦娥曳霞帔，引我同攀躋。騰騰上天半，玉鏡懸飛梯。", "瑤池何悄悄，鸞鶴煙中棲。回頭望塵事，露下寒淒淒。"]'),
('yuding-8','送客之江甯','韓翃','唐','御定全唐诗','yuding','','[]','春流送客不應賒，南入徐州見柳花。朱雀橋邊看淮水，',48,'御定全唐詩/json/243.json','["春流送客不應賒，南入徐州見柳花。朱雀橋邊看淮水，", "楚雲朝下石頭城，江燕雙飛瓦棺寺。吳士風流甚可親，"]'),
('yuding-9','送山陰姚丞攜妓之任兼寄山陰蘇少府','韓翃','唐','御定全唐诗','yuding','','[]','東風香草路，南客心容與。白皙吳王孫，青蛾柳家女。',96,'御定全唐詩/json/243.json','["東風香草路，南客心容與。白皙吳王孫，青蛾柳家女。", "都門數騎出，河口片帆舉。夜簟眠橘洲，春衫傍楓嶼。", "山陰政簡甚從容，到罷唯求物外蹤。落日花邊剡溪水，", "加餐共愛鱸魚肥，醒酒仍憐甘蔗熟。知君煉思本清新，"]'),
('yuding-10','和高平朱參軍思歸作','韓翃','唐','御定全唐诗','yuding','','[]','髯參軍，髯參軍，身為北州吏，心寄東山雲。',68,'御定全唐詩/json/243.json','["髯參軍，髯參軍，身為北州吏，心寄東山雲。", "坐見萋萋芳草綠。遙思往日晴江曲。刺船頻向剡中回，", "狂歌好愛陶彭澤，佳句唯稱謝法曹。平生樂事多如此，"]'),
('yuding-11','贈別成明府赴劍南','韓翃','唐','御定全唐诗','yuding','','[]','朝為三室印，晚為三蜀人。遙知下車日，正及巴山春。',72,'御定全唐詩/json/243.json','["朝為三室印，晚為三蜀人。遙知下車日，正及巴山春。", "縣道橘花裏，驛流江水濱。公門輒無事，賞地能相親。", "解衣初醉綠芳夕，應采蹲鴟薦佳客。霽水遠映西川時，"]'),
('yuding-12','送孫潑赴雲中','韓翃','唐','御定全唐诗','yuding','','[]','黃驄少年舞雙戟，目視旁人皆辟易。百戰能誇隴上兒，',48,'御定全唐詩/json/243.json','["黃驄少年舞雙戟，目視旁人皆辟易。百戰能誇隴上兒，", "敲石軍中傳夜火，斧冰河畔汲朝漿。前鋒直指陰山外，"]'),
('yuding-13','送客還江東','韓翃','唐','御定全唐诗','yuding','','[]','還家不落春風後，數日應沽越人酒。池畔花深鬥鴨欄，',40,'御定全唐詩/json/243.json','["還家不落春風後，數日應沽越人酒。池畔花深鬥鴨欄，", "把手閑歌香橘下，空山一望鷓鴣飛。"]'),
('yuding-14','送夏侯侍郎','韓翃','唐','御定全唐诗','yuding','','[]','元戎車右早飛聲，禦史府中新正名。翰墨已齊鐘大理，',88,'御定全唐詩/json/243.json','["元戎車右早飛聲，禦史府中新正名。翰墨已齊鐘大理，", "前路應留白玉台，行人輒美黃金絡。使君下馬愛瀛洲，", "公庭日夕羅山翠，功遂心閑無一事。移書或問島邊人，", "浮雲飛鳥兩相忘，他日依依城上樓。"]'),
('yuding-15','送李湜下第歸衛州便游河北','韓翃','唐','御定全唐诗','yuding','','[]','莫嗟太常屈，便入蘇門嘯。裏在應未遲，勿作我身料。',112,'御定全唐詩/json/243.json','["莫嗟太常屈，便入蘇門嘯。裏在應未遲，勿作我身料。", "輕雲日下不成陰，出對流芳攪別心。萬雉城東春水闊，", "佳期縱得上宮遊，旅食還為北邙客。路出司州勝景長，", "屢道主人多愛士，何辭策馬千餘裏。高譚魏國訪先生，", "有錢莫向河間用，載筆須來闕下游。"]'),
('yuding-16','張山人草堂會王方士','韓翃','唐','御定全唐诗','yuding','','[]','嶼花晚，山日長，蕙帶麻襦食草堂。一片水光飛入戶，',24,'御定全唐詩/json/243.json','["嶼花晚，山日長，蕙帶麻襦食草堂。一片水光飛入戶，"]'),
('yuding-17','送蓚縣劉主簿楚','韓翃','唐','御定全唐诗','yuding','','[]','起家得事平原侯，晚出都門辭舊遊。草色連綿幾千里，',64,'御定全唐詩/json/243.json','["起家得事平原侯，晚出都門辭舊遊。草色連綿幾千里，", "鄴下淹留佳賞新，群公舊日心相親。金盤曉鱠朱衣鮒，", "寒水浮瓜五月時，把君衣袖長河曲。"]'),
('yuding-18','題玉山觀禪師蘭若','韓翃','唐','御定全唐诗','yuding','','[]','玉山宴坐移年月，錫杖承恩詣丹闕。先朝親與會龍華，',72,'御定全唐詩/json/243.json','["玉山宴坐移年月，錫杖承恩詣丹闕。先朝親與會龍華，", "禪床久臥虎溪水，蘭若初開鳳城裏。不出囂塵見遠公，", "掖垣揮翰君稱美，遠客陪遊問真理。薄宦深知誤此心，"]'),
('yuding-19','贈別上元主簿張著','韓翃','唐','御定全唐诗','yuding','','[]','上書一見平津侯，劍笏斜齊秣陵尉。朝垂綬帶迎遠客，',72,'御定全唐詩/json/243.json','["上書一見平津侯，劍笏斜齊秣陵尉。朝垂綬帶迎遠客，", "回船對酒三生渚，系馬焚香五願祠。日日澄江帶山翠，", "風流才調愛君偏，此別相逢定幾年。惆悵浮雲迷遠道，"]'),
('yuding-20','別汜水縣尉','韓翃','唐','御定全唐诗','yuding','','[]','未央宮殿金開鑰，詔引賢良卷珠箔。花間賜食近丹墀，',96,'御定全唐詩/json/243.json','["未央宮殿金開鑰，詔引賢良卷珠箔。花間賜食近丹墀，", "谷永直言身不顧，郤詵高第轉名香。綠槐陰陰出關道，", "五侯客舍偏留宿，一縣人家爭看歸。南向千峰北臨水，", "自憐寂寞會君稀，猶著前時博士衣。我欲低眉問知己，"]'),
('yuding-21','別李明府','韓翃','唐','御定全唐诗','yuding','','[]','寵光五世腰青組，出入珠宮引簫鼓。醉舞雄王玳瑁床，',72,'御定全唐詩/json/243.json','["寵光五世腰青組，出入珠宮引簫鼓。醉舞雄王玳瑁床，", "羅山道士請人送，林邑使臣調象騎。愛君一身游上國，", "五侯焦石烹江筍，千戶沉香染客衣。別後想君難可見，"]'),
('yuding-22','送中兄典邵州','韓翃','唐','御定全唐诗','yuding','','[]','官騎連西向楚雲，朱軒出餞晝紛紛。百城兼領安南國，',88,'御定全唐詩/json/243.json','["官騎連西向楚雲，朱軒出餞晝紛紛。百城兼領安南國，", "玉顏送酒銅鞮歌，金管留人石頭宿。北雁初回江燕飛，", "百事無留到官後，重門寂寂垂高柳。零陵過贈石香溪，", "他日新詩應見報，還如宣遠在安城。"]'),
('yuding-23','送萬巨','韓翃','唐','御定全唐诗','yuding','','[]','漢相見王陵，揚州事張禹。風帆木蘭楫，水國蓮花府。',96,'御定全唐詩/json/243.json','["漢相見王陵，揚州事張禹。風帆木蘭楫，水國蓮花府。", "百丈清江十月天，寒城鼓角曉鐘前。金爐促膝諸曹吏，", "好逢南苑看人歸，也向西池留客醉。高柳垂煙橘帶霜，", "夫子前年入朝後，高名籍籍時賢口。共憐詩興轉清新，"]'),
('yuding-24','送巴州楊使君','韓翃','唐','御定全唐诗','yuding','','[]','白雲縣北千山口，青歲欲開殘雪後。前驅錦帶魚皮鞮，',48,'御定全唐詩/json/243.json','["白雲縣北千山口，青歲欲開殘雪後。前驅錦帶魚皮鞮，", "愁看野馬隨官騎，笑取秦人帶客旗。使者下車憂疾苦，"]'),
('yuding-25','送王侍禦赴江西兼寄李袁州','韓翃','唐','御定全唐诗','yuding','','[]','中朝理章服，南國隨旌旆。臘酒湘城隅，春衣楚江外。',96,'御定全唐詩/json/243.json','["中朝理章服，南國隨旌旆。臘酒湘城隅，春衣楚江外。", "垂簾白角簟，下箸鱸魚鱠。雄筆佐名公，虛舟應時輩。", "按俗承流幾路清，平明山靄春江雲。湓城詩贈魚司馬，", "井上銅人行見無，湖中石燕飛應盡。禮門前直事仙郎，"]'),
('yuding-26','寄雍丘竇明府','韓翃','唐','御定全唐诗','yuding','','[]','少年結綬騁金羈，許下如看瓊樹枝。入裏親過朗陵伯，',112,'御定全唐詩/json/243.json','["少年結綬騁金羈，許下如看瓊樹枝。入裏親過朗陵伯，", "時輩甯將白筆期，高流佇向丹霄見。何事翻飛不及群，", "中歲胡塵靜如掃，一官又罷行將老。薛公薦士得君初，", "□□□□□□□，□出重門煙樹裏。感物吟詩對暮天，", "獨坐不堪朝與夕，高風蕭索亂蟬悲。"]'),
('yuding-27','贈兗州孟都督','韓翃','唐','御定全唐诗','yuding','','[]','少年親事冠軍侯，中歲仍遷北兗州。露冕甯誇漢車服，',72,'御定全唐詩/json/243.json','["少年親事冠軍侯，中歲仍遷北兗州。露冕甯誇漢車服，", "閒心近掩陶使君，詩興遙齊謝康樂。遠山重疊水逶迤，", "北場爭轉黃金勒，愛客華亭賞秋色。捲簾滿地鋪氍毹，"]'),
('yuding-28','別孟都督','韓翃','唐','御定全唐诗','yuding','','[]','平蕪霽色寒城下，美酒百壺爭勸把。連呼寶劍銳頭兒，',40,'御定全唐詩/json/243.json','["平蕪霽色寒城下，美酒百壺爭勸把。連呼寶劍銳頭兒，", "他時相憶若相問，青瑣門前開素書。"]'),
('yuding-29','送別鄭明府','韓翃','唐','御定全唐诗','yuding','','[]','長頭大鼻鬢如雪，早歲連兵劍鋒折。千金盡去無鬥儲，',48,'御定全唐詩/json/243.json','["長頭大鼻鬢如雪，早歲連兵劍鋒折。千金盡去無鬥儲，", "路傍誰識鄭公子，谷口應知漢逸人。兒女相悲探井臼，"]'),
('yuding-30','贈別王侍禦赴上都','韓翃','唐','御定全唐诗','yuding','','[]','翩翩馬上郎，執簡佩銀章。西向洛陽歸鄠杜，',68,'御定全唐詩/json/243.json','["翩翩馬上郎，執簡佩銀章。西向洛陽歸鄠杜，", "青青樹色傍行衣，乳燕流鶯相間飛。遠過三峰臨八水，", "相思掩泣複何如，公子門前人漸疏。幸有心期當小暑，"]'),
('yuding-31','贈別太常李博士兼寄兩省舊游','韓翃','唐','御定全唐诗','yuding','','[]','兩年戴武弁，趨侍明光殿。一朝簪惠文，客事信陵君。',96,'御定全唐詩/json/243.json','["兩年戴武弁，趨侍明光殿。一朝簪惠文，客事信陵君。", "簡異當朝執，香非寓直熏。差肩何記室，攜手李將軍。", "玉鐙初回酸棗館，金鈿正舞石榴裙。忽驚萬事隨流水，", "暫誇五首軍中詩，還憶萬年枝下客。昨日留歡今送歸，"]'),
('yuding-32','寄哥舒僕射','韓翃','唐','御定全唐诗','yuding','','[]','萬里長城家，一生唯報國。腰垂紫文綬，手控黃金勒。',96,'御定全唐詩/json/243.json','["萬里長城家，一生唯報國。腰垂紫文綬，手控黃金勒。", "高視黑頭翁，遙吞白騎賊。先麾牙門將，轉鬥黃河北。", "帳下親兵皆少年，錦衣承日繡行纏。轆轤寶劍初出鞘，", "左盤右射紅塵中，鶻入鴉群有誰敵。殺將破軍白日餘，"]'),
('yuding-33','贈別華陰道士','韓翃','唐','御定全唐诗','yuding','','[]','紫府先生舊同學，腰垂彤管貯靈藥。恥論方士小還丹，',72,'御定全唐詩/json/243.json','["紫府先生舊同學，腰垂彤管貯靈藥。恥論方士小還丹，", "晝灑瑤台五雲濕，夜行金燭七星齊。回身暫下青冥裏，", "青青百草雲台春，煙駕霓衣白角巾。露葉獨歸仙掌去，"]'),
('yuding-34','送崔秀才赴上元兼省叔父','韓翃','唐','御定全唐诗','yuding','','[]','寒塘斂暮雪，臘鼓迎春早。匹馬五城人，重裘千里道。',88,'御定全唐詩/json/243.json','["寒塘斂暮雪，臘鼓迎春早。匹馬五城人，重裘千里道。", "淮山輕露濕，江樹狂風掃。楚縣九醞醲，揚州百花好。", "練湖東望接雲陽，女市西游入建康。行樂遠誇紅布旆，", "煙開日上板橋南，吳岫青青出林表。"]'),
('yuding-0','贈別韋兵曹歸池州','韓翃','唐','御定全唐诗','yuding','','[]','南陵八月天，暮色遠峰前。楚竹青陽路，吳江赤馬船。',48,'御定全唐詩/json/244.json','["南陵八月天，暮色遠峰前。楚竹青陽路，吳江赤馬船。", "籝金諸客貴，佩玉主人賢。終日應相逐，歸期定幾年。"]'),
('yuding-1','寄武陵李少府','韓翃','唐','御定全唐诗','yuding','','[]','小縣春山口，公孫吏隱時。楚歌催晚醉，蠻語入新詩。',48,'御定全唐詩/json/244.json','["小縣春山口，公孫吏隱時。楚歌催晚醉，蠻語入新詩。", "桂水遙相憶，花源暗有期。郢門千裏外，莫怪尺書遲。"]'),
('yuding-2','贈張建','韓翃','唐','御定全唐诗','yuding','','[]','結客平陵下，當年倚俠游。傳看轆轤劍，醉脫驌驦裘。',48,'御定全唐詩/json/244.json','["結客平陵下，當年倚俠游。傳看轆轤劍，醉脫驌驦裘。", "翠羽雙鬟妾，珠簾百尺樓。春風坐相待，晚日莫淹留。"]'),
('yuding-3','送監軍李判官','韓翃','唐','御定全唐诗','yuding','','[]','上客佩雙劍，東城喜再遊。舊從張博望，新事鄭長秋。',48,'御定全唐詩/json/244.json','["上客佩雙劍，東城喜再遊。舊從張博望，新事鄭長秋。", "踏水回金勒，看風試錦裘。知君不久住，漢將掃旄頭。"]'),
('yuding-4','送客歸廣平','韓翃','唐','御定全唐诗','yuding','','[]','家在趙邯鄲，歸心輒自歡。晚杯狐腋暖，春雪馬毛寒。',48,'御定全唐詩/json/244.json','["家在趙邯鄲，歸心輒自歡。晚杯狐腋暖，春雪馬毛寒。", "孟月途中破，輕冰水上殘。到時楊柳色，奈向故園看。"]'),
('yuding-5','送張儋水路歸北海','韓翃','唐','御定全唐诗','yuding','','[]','千里東歸客，孤心憶舊遊。片帆依白水，高枕臥青州。',48,'御定全唐詩/json/244.json','["千里東歸客，孤心憶舊遊。片帆依白水，高枕臥青州。", "柏寢寒蕪變，梧台宿雨收。知君心興遠，每上海邊樓。"]'),
('yuding-6','送故人歸魯','韓翃','唐','御定全唐诗','yuding','','[]','魯客多歸興，居人悵別情。雨餘衫袖冷，風急馬蹄輕。',48,'御定全唐詩/json/244.json','["魯客多歸興，居人悵別情。雨餘衫袖冷，風急馬蹄輕。", "秋草靈光殿，寒雲曲阜城。知君拜親後，少婦下機迎。"]'),
('yuding-7','送故人歸蜀','韓翃','唐','御定全唐诗','yuding','','[]','一騎西南遠，翩翩入劍門。客衣筒布潤，山舍荔枝繁。',48,'御定全唐詩/json/244.json','["一騎西南遠，翩翩入劍門。客衣筒布潤，山舍荔枝繁。", "古廟祠金馬，春江帶白黿。自應成旅逸，愛客有王孫。"]'),
('yuding-8','酬程延秋夜即事見贈','韓翃','唐','御定全唐诗','yuding','','[]','長簟迎風早，空城澹月華。星河秋一雁，砧杵夜千家。',48,'御定全唐詩/json/244.json','["長簟迎風早，空城澹月華。星河秋一雁，砧杵夜千家。", "節候看應晚，心期臥亦賒。向來吟秀句，不覺已鳴鴉。"]'),
('yuding-9','送郭贊府歸淮南','韓翃','唐','御定全唐诗','yuding','','[]','駿馬淮南客，歸時引望新。江聲六合暮，楚色萬家春。',48,'御定全唐詩/json/244.json','["駿馬淮南客，歸時引望新。江聲六合暮，楚色萬家春。", "白苧歌西曲，黃苞寄北人。不知心賞後，早晚見行塵。"]'),
('yuding-10','題龍興寺澹師房','韓翃','唐','御定全唐诗','yuding','','[]','雙林彼上人，詩興轉相親。竹裏經聲晚，門前山色春。',48,'御定全唐詩/json/244.json','["雙林彼上人，詩興轉相親。竹裏經聲晚，門前山色春。", "捲簾苔點淨，下箸藥苗新。記取無生理，歸來問此身。"]'),
('yuding-11','送客游江南','韓翃','唐','御定全唐诗','yuding','','[]','南使孤帆遠，東風任意吹。楚雲殊不斷，江鳥暫相隨。',48,'御定全唐詩/json/244.json','["南使孤帆遠，東風任意吹。楚雲殊不斷，江鳥暫相隨。", "月淨鴛鴦水，春生豆蔻枝。賞稱佳麗地，君去莫應知。"]'),
('yuding-12','送高員外赴淄青使幕','韓翃','唐','御定全唐诗','yuding','','[]','遠水流春色，回風送落暉。人趨雙節近，馬遞百花歸。',48,'御定全唐詩/json/244.json','["遠水流春色，回風送落暉。人趨雙節近，馬遞百花歸。", "山驛嘗官酒，關城度客衣。從來赤管筆，提向幕中稀。"]'),
('yuding-13','尋胡處士不遇','韓翃','唐','御定全唐诗','yuding','','[]','到來心自足，不見亦相親。說法思居士，忘機憶丈人。',48,'御定全唐詩/json/244.json','["到來心自足，不見亦相親。說法思居士，忘機憶丈人。", "微風吹藥案，晴日照茶巾。幽興殊未盡，東城飛暮塵。"]'),
('yuding-14','贈張道者','韓翃','唐','御定全唐诗','yuding','','[]','采藥三山罷，乘風五日歸。翦荷成舊屋，剉蘖染新衣。',48,'御定全唐詩/json/244.json','["采藥三山罷，乘風五日歸。翦荷成舊屋，剉蘖染新衣。", "玉粒指應久，丹砂驗不微。坐看青節引，要與白雲飛。"]'),
('yuding-15','題蘇許公林亭','韓翃','唐','御定全唐诗','yuding','','[]','平津東閣在，別是竹林期。萬葉秋聲裏，千家落照時。',48,'御定全唐詩/json/244.json','["平津東閣在，別是竹林期。萬葉秋聲裏，千家落照時。", "門隨深巷靜，窗過遠鐘遲。客舍苔生處，依依又賦詩。"]'),
('yuding-16','送元詵還江東','韓翃','唐','御定全唐诗','yuding','','[]','過江秋色在，詩興與歸心。客路隨楓岸，人家掃橘林。',48,'御定全唐詩/json/244.json','["過江秋色在，詩興與歸心。客路隨楓岸，人家掃橘林。", "潮聲當晝起，山翠近南深。幾日華陽洞，寒花引獨尋。"]'),
('yuding-17','送客游江南','韓翃','唐','御定全唐诗','yuding','','[]','桂水隨去遠，賞心知有餘。衣香楚山橘，手鱠湘波魚。',48,'御定全唐詩/json/244.json','["桂水隨去遠，賞心知有餘。衣香楚山橘，手鱠湘波魚。", "芳芷不共把，浮雲悵離居。遙想汨羅上，吊屈秋風初。"]'),
('yuding-18','送海州姚別駕','韓翃','唐','御定全唐诗','yuding','','[]','少年為長史，東去事諸侯。坐覺千閭靜，閑隨五馬遊。',48,'御定全唐詩/json/244.json','["少年為長史，東去事諸侯。坐覺千閭靜，閑隨五馬遊。", "行人楚國道，暮雪郁林州。他日知相憶，春風海上樓。"]'),
('yuding-19','送夏侯審','韓翃','唐','御定全唐诗','yuding','','[]','謝公鄰里在，日夕問佳期。春水人歸後，東田花盡時。',48,'御定全唐詩/json/244.json','["謝公鄰里在，日夕問佳期。春水人歸後，東田花盡時。", "下樓閑待月，行樂笑題詩。他日吳中路，千山入夢思。"]'),
('yuding-20','送趙評事赴洪州使幕','韓翃','唐','御定全唐诗','yuding','','[]','孤舟行遠近，一路過湘東。官屬張廷尉，身隨杜幼公。',48,'御定全唐詩/json/244.json','["孤舟行遠近，一路過湘東。官屬張廷尉，身隨杜幼公。", "公河映湘竹，水驛帶青楓。萬里思君處，秋江夜雨中。"]'),
('yuding-21','送李侍禦赴徐州行營','韓翃','唐','御定全唐诗','yuding','','[]','少年兼柱史，東至舊徐州。遠屬平津閣，前驅博望侯。',48,'御定全唐詩/json/244.json','["少年兼柱史，東至舊徐州。遠屬平津閣，前驅博望侯。", "向營淮水滿，吹角楚天秋。客夢依依處，寒山對白樓。"]'),
('yuding-22','送李秀才歸江南','韓翃','唐','御定全唐诗','yuding','','[]','過淮芳草歇，千里又東歸。野水吳山出，家林越鳥飛。',48,'御定全唐詩/json/244.json','["過淮芳草歇，千里又東歸。野水吳山出，家林越鳥飛。", "荷香隨去棹，梅雨點行衣。無數滄江客，如君達者稀。"]'),
('yuding-23','題僧房','韓翃','唐','御定全唐诗','yuding','','[]','披衣聞客至，關鎖此時開。鳴磬夕陽盡，捲簾秋色來。',48,'御定全唐詩/json/244.json','["披衣聞客至，關鎖此時開。鳴磬夕陽盡，捲簾秋色來。", "名香連竹徑，清梵出花台。身在心無住，他方到幾回。"]'),
('yuding-24','送壽州陳錄事','韓翃','唐','御定全唐诗','yuding','','[]','壽陽南渡口，斂笏見諸侯。五兩楚雲暮，千家淮水秋。',48,'御定全唐詩/json/244.json','["壽陽南渡口，斂笏見諸侯。五兩楚雲暮，千家淮水秋。", "開簾對芳草，送客上春洲。請問山中桂，王孫幾度游。"]'),
('yuding-25','送趙陸司兵歸使幕','韓翃','唐','御定全唐诗','yuding','','[]','客路青蕪遍，關城白日低。身趨雙節近，名共五雲齊。',48,'御定全唐詩/json/244.json','["客路青蕪遍，關城白日低。身趨雙節近，名共五雲齊。", "遠水公田上，春山郡舍西。無因得攜手，東望轉淒淒。"]'),
('yuding-26','送蔣員外端公歸淮南','韓翃','唐','御定全唐诗','yuding','','[]','淮南芳草色，日夕引歸船。禦史王元貺，郎官顧彥先。',48,'御定全唐詩/json/244.json','["淮南芳草色，日夕引歸船。禦史王元貺，郎官顧彥先。", "光風千日暖，寒食百花燃。惆悵佳期近，澄江與暮天。"]'),
('yuding-27','題慈仁寺竹院','韓翃','唐','御定全唐诗','yuding','','[]','千峰對古寺，何異到西林。幽磬蟬聲下，閑窗竹翠陰。',48,'御定全唐詩/json/244.json','["千峰對古寺，何異到西林。幽磬蟬聲下，閑窗竹翠陰。", "詩人謝客興，法侶遠公心。寂寂爐煙裏，香花欲暮深。"]'),
('yuding-28','贈鄆州馬使君','韓翃','唐','御定全唐诗','yuding','','[]','東方千萬騎，出望使君時。暮雪行看盡，春城到莫遲。',48,'御定全唐詩/json/244.json','["東方千萬騎，出望使君時。暮雪行看盡，春城到莫遲。", "路人趨墨幘，官柳度青絲。他日鈴齋內，知君亦賦詩。"]'),
('yuding-29','送張丞歸使幕','韓翃','唐','御定全唐诗','yuding','','[]','獨受主恩歸，當朝似者稀。玉壺分禦酒，金殿賜春衣。',48,'御定全唐詩/json/244.json','["獨受主恩歸，當朝似者稀。玉壺分禦酒，金殿賜春衣。", "拂席流鶯醉，鳴鞭駿馬肥。滿台簪白筆，捧手戀清暉。"]'),
('yuding-30','贈長洲何主簿','韓翃','唐','御定全唐诗','yuding','','[]','掛席逐歸流，依依望虎丘。殘春過楚縣，夜雨宿吳洲。',48,'御定全唐詩/json/244.json','["掛席逐歸流，依依望虎丘。殘春過楚縣，夜雨宿吳洲。", "野寺吟詩入，溪橋折筍遊。到官無一事，清靜有諸侯。"]'),
('yuding-31','送崔過歸淄青幕府','韓翃','唐','御定全唐诗','yuding','','[]','平陵車馬客，海上見旌旗。舊驛千山下，殘花一路時。',48,'御定全唐詩/json/244.json','["平陵車馬客，海上見旌旗。舊驛千山下，殘花一路時。", "春衣過水冷，暮雨出關遲。莫道青州客，迢迢在夢思。"]'),
('yuding-32','田倉曹東亭夏夜飲得春字','韓翃','唐','御定全唐诗','yuding','','[]','薛公門下人，公子又相親。玉佩迎初夜，金壺醉老春。',48,'御定全唐詩/json/244.json','["薛公門下人，公子又相親。玉佩迎初夜，金壺醉老春。", "葛衣香有露，羅幕靜無塵。更羨風流外，文章是一秦。"]'),
('yuding-33','贈王逖','韓翃','唐','御定全唐诗','yuding','','[]','端笏事龍樓，思閑輒告休。新調赭白馬，暫試黑貂裘。',48,'御定全唐詩/json/244.json','["端笏事龍樓，思閑輒告休。新調赭白馬，暫試黑貂裘。", "珠履迎佳客，金錢與莫愁。座中豪貴滿，誰道不風流。"]'),
('yuding-34','送深州吳司馬歸使幕','韓翃','唐','御定全唐诗','yuding','','[]','東門送遠客，車馬正紛紛。舊識張京兆，新隨劉領軍。',48,'御定全唐詩/json/244.json','["東門送遠客，車馬正紛紛。舊識張京兆，新隨劉領軍。", "行驄看暮雨，歸雁踏青雲。一去叢臺北，佳聲幾日聞。"]'),
('yuding-35','華亭夜宴庾侍禦宅','韓翃','唐','御定全唐诗','yuding','','[]','世故他年別，心期此夜同。千峰孤燭外，片雨一更中。',48,'御定全唐詩/json/244.json','["世故他年別，心期此夜同。千峰孤燭外，片雨一更中。", "酒客逢山簡，詩人得謝公。自憐驅匹馬，拂曙向關東。"]'),
('yuding-36','送客之上谷','韓翃','唐','御定全唐诗','yuding','','[]','北客悲秋色，田園憶去來。披衣朝易水，匹馬夕燕台。',48,'御定全唐詩/json/244.json','["北客悲秋色，田園憶去來。披衣朝易水，匹馬夕燕台。", "風翦荷花碎，霜迎栗罅開。賞心知不淺，累月故人杯。"]'),
('yuding-37','同中書劉舍人題青龍上房','韓翃','唐','御定全唐诗','yuding','','[]','西掖歸來後，東林靜者期。遠峰春雪裏，寒竹暮天時。',48,'御定全唐詩/json/244.json','["西掖歸來後，東林靜者期。遠峰春雪裏，寒竹暮天時。", "笑說金人偈，閑聽寶月詩。更憐茶興在，好出下方遲。"]'),
('yuding-38','宴吳王宅','韓翃','唐','御定全唐诗','yuding','','[]','玉管簫聲合，金杯酒色殷。聽歌吳季劄，縱飲漢中山。',48,'御定全唐詩/json/244.json','["玉管簫聲合，金杯酒色殷。聽歌吳季劄，縱飲漢中山。", "稱壽爭離席，留歡輒上關。莫言辭客醉，猶得曳裾還。"]'),
('yuding-39','題薦福寺衡岳暕師房','韓翃','唐','御定全唐诗','yuding','','[]','春城乞食還，高論此中閑。僧臘階前樹，禪心江上山。',48,'御定全唐詩/json/244.json','["春城乞食還，高論此中閑。僧臘階前樹，禪心江上山。", "疏簾看雪卷，深戶映花關。晚送門人出，鐘聲杳靄間。"]'),
('yuding-40','送戴迪赴鳳翔幕府','韓翃','唐','御定全唐诗','yuding','','[]','青春帶文綬，去事魏征西。上路金羈出，中人玉箸齊。',48,'御定全唐詩/json/244.json','["青春帶文綬，去事魏征西。上路金羈出，中人玉箸齊。", "當歌酒萬斛，看獵馬千蹄。自有從軍樂，何須怨解攜。"]'),
('yuding-41','送郢州郎使君','韓翃','唐','御定全唐诗','yuding','','[]','千人插羽迎，知是范宣城。暮雪楚山冷，春江漢水清。',48,'御定全唐詩/json/244.json','["千人插羽迎，知是范宣城。暮雪楚山冷，春江漢水清。", "紅鮮供客飯，翠竹引舟行。一別何時見，相思芳草生。"]'),
('yuding-42','送李中丞赴辰州','韓翃','唐','御定全唐诗','yuding','','[]','白羽逐青絲，翩翩南下時。巴人迎道路，蠻帥引旌旗。',48,'御定全唐詩/json/244.json','["白羽逐青絲，翩翩南下時。巴人迎道路，蠻帥引旌旗。", "暮雨山開少，秋江葉落遲。功成益地日，應見竹郎祠。"]'),
('yuding-43','送劉侍禦赴陝州','韓翃','唐','御定全唐诗','yuding','','[]','金羈映驌驦，後騎佩幹將。把酒春城晚，鳴鞭曉路長。',48,'御定全唐詩/json/244.json','["金羈映驌驦，後騎佩幹將。把酒春城晚，鳴鞭曉路長。", "帶冰新溜澀，間雪早梅香。明日懷賢處，依依禦史床。"]'),
('yuding-44','李中丞宅夜宴送丘侍禦赴江東便往辰州','韓翃','唐','御定全唐诗','yuding','','[]','積雪臨階夜，重裘對酒時。中丞違沈約，才子送丘遲。',48,'御定全唐詩/json/244.json','["積雪臨階夜，重裘對酒時。中丞違沈約，才子送丘遲。", "一路三江上，孤舟萬里期。辰州佳興在，他日寄新詩。"]'),
('yuding-45','送李侍禦歸宣州使幕','韓翃','唐','御定全唐诗','yuding','','[]','春草東江外，翩翩北路歸。官齊魏公子，身逐謝玄暉。',48,'御定全唐詩/json/244.json','["春草東江外，翩翩北路歸。官齊魏公子，身逐謝玄暉。", "山色隨行騎，鶯聲傍客衣。主人池上酌，攜手暮花飛。"]'),
('yuding-46','東城水亭宴李侍禦副使','韓翃','唐','御定全唐诗','yuding','','[]','東門留客處，沽酒用錢刀。秋水床下急，斜暉林外高。',48,'御定全唐詩/json/244.json','["東門留客處，沽酒用錢刀。秋水床下急，斜暉林外高。", "金羈絡騕褭，玉匣閉豪曹。去日隨戎幕，東風見伯勞。"]'),
('yuding-47','送秘書謝監赴江西使幕','韓翃','唐','御定全唐诗','yuding','','[]','謝監憶山程，辭家萬里行。寒衣傍楚色，孤枕宿潮聲。',48,'御定全唐詩/json/244.json','["謝監憶山程，辭家萬里行。寒衣傍楚色，孤枕宿潮聲。", "小寇不足問，新詩應漸清。府公相待日，引旆出江城。"]'),
('yuding-48','送江陵元司錄','韓翃','唐','御定全唐诗','yuding','','[]','新領州從事，曾為朝大夫。江城竹使待，山路橘官扶。',48,'御定全唐詩/json/244.json','["新領州從事，曾為朝大夫。江城竹使待，山路橘官扶。", "片雨三江道，殘秋五葉湖。能令詩思好，楚色與寒蕪。"]'),
('yuding-49','送李舍人攜家歸江東覲省','韓翃','唐','御定全唐诗','yuding','','[]','二十青宮吏，成名似者稀。承顏陸郎去，攜手謝娘歸。',48,'御定全唐詩/json/244.json','["二十青宮吏，成名似者稀。承顏陸郎去，攜手謝娘歸。", "夜月回孤燭，秋風試夾衣。扁舟楚水上，來往速如飛。"]'),
('yuding-50','送劉侍禦赴令公行營','韓翃','唐','御定全唐诗','yuding','','[]','東城躍紫騮，西路大刀頭。上客劉公幹，元戎郭細侯。',48,'御定全唐詩/json/244.json','["東城躍紫騮，西路大刀頭。上客劉公幹，元戎郭細侯。", "一軍偏許國，百戰又防秋。請問蕭關道，胡塵早晚收。"]'),
('yuding-51','送蘇州姚長史','韓翃','唐','御定全唐诗','yuding','','[]','江城驛路長，煙樹過雲陽。舟領青絲纜，人歌白玉郎。',48,'御定全唐詩/json/244.json','["江城驛路長，煙樹過雲陽。舟領青絲纜，人歌白玉郎。", "葛衣行柳翠，花簟宿荷香。別有心期處，湖光滿訟堂。"]'),
('yuding-52','送金華王明府','韓翃','唐','御定全唐诗','yuding','','[]','縣舍江雲裏，心閑境又偏。家貧陶令酒，月俸沈郎錢。',48,'御定全唐詩/json/244.json','["縣舍江雲裏，心閑境又偏。家貧陶令酒，月俸沈郎錢。", "黃蘖香山路，青楓暮雨天。時聞引車騎，竹外到銅泉。"]'),
('yuding-53','送田倉曹汴州覲省','韓翃','唐','御定全唐诗','yuding','','[]','拜慶承天寵，朝來辭漢宮。玉杯分湛露，金勒借追風。',48,'御定全唐詩/json/244.json','["拜慶承天寵，朝來辭漢宮。玉杯分湛露，金勒借追風。", "古驛秋山下，平蕪暮雨中。翩翩魏公子，人看渡關東。"]'),
('yuding-54','送張渚赴越州','韓翃','唐','御定全唐诗','yuding','','[]','白麵誰家郎，青驪照地光。桃花開綬色，蘇合借衣香。',48,'御定全唐詩/json/244.json','["白麵誰家郎，青驪照地光。桃花開綬色，蘇合借衣香。", "暮雪連峰近，春江海市長。風流似張緒，別後見垂楊。"]'),
('yuding-55','奉和元相公家園即事寄王相公','韓翃','唐','御定全唐诗','yuding','','[]','共列中台貴，能齊物外心。回車青閣晚，解帶碧茸深。',48,'御定全唐詩/json/244.json','["共列中台貴，能齊物外心。回車青閣晚，解帶碧茸深。", "寒水分畦入，晴花度竹尋。題詩更相憶，一字重千金。"]'),
('yuding-56','送道士侄歸池陽','韓翃','唐','御定全唐诗','yuding','','[]','銀角桃枝杖，東門贈別初。幽州尋馬客，灞岸送驢車。',48,'御定全唐詩/json/244.json','["銀角桃枝杖，東門贈別初。幽州尋馬客，灞岸送驢車。", "野飯秋山靜，行衣落照餘。燕南群從少，此去意何如。"]'),
('yuding-57','送劉長上歸城南別業','韓翃','唐','御定全唐诗','yuding','','[]','數刻是歸程，花間落照明。春衣香不散，駿馬汗猶輕。',48,'御定全唐詩/json/244.json','["數刻是歸程，花間落照明。春衣香不散，駿馬汗猶輕。", "南渡春流淺，西風片雨晴。朝還會相就，飯爾五侯鯖。"]'),
('yuding-58','贈張五諲歸濠州別業','韓翃','唐','御定全唐诗','yuding','','[]','常知罷官意，果與世人疏。複此涼風起，仍聞濠上居。',48,'御定全唐詩/json/244.json','["常知罷官意，果與世人疏。複此涼風起，仍聞濠上居。", "故山期采菊，秋水憶觀魚。一去蓬蒿徑，羨君閑有餘。"]'),
('yuding-59','送營城李少府','韓翃','唐','御定全唐诗','yuding','','[]','懷祿兼就養，更懷趨府心。晴山東裏近，春水北門深。',48,'御定全唐詩/json/244.json','["懷祿兼就養，更懷趨府心。晴山東裏近，春水北門深。", "新綬映芳草，舊家依遠林。還乘鄭小駟，躞蹀縣城陰。"]'),
('yuding-60','魯中送魯使君歸鄭州','韓翃','唐','御定全唐诗','yuding','','[]','城中金絡騎，出餞沈東陽。九月寒露白，六關秋草黃。',48,'御定全唐詩/json/244.json','["城中金絡騎，出餞沈東陽。九月寒露白，六關秋草黃。", "齊謳聽處妙，魯酒把來香。醉後著鞭去，梅山道路長。"]'),
('yuding-61','送夏侯校書歸上都','韓翃','唐','御定全唐诗','yuding','','[]','後輩傳佳句，高流愛美名。青春事賀監，黃卷問張生。',48,'御定全唐詩/json/244.json','["後輩傳佳句，高流愛美名。青春事賀監，黃卷問張生。", "暮雪重裘醉，寒山匹馬行。此回將詣闕，幾日諫書成。"]'),
('yuding-62','送李明府赴連州','韓翃','唐','御定全唐诗','yuding','','[]','萬里向南湘，孤舟入桂陽。諸侯迎上客，小吏拜官郎。',48,'御定全唐詩/json/244.json','["萬里向南湘，孤舟入桂陽。諸侯迎上客，小吏拜官郎。", "春服橦花細，初筵木槿芳。看承雨露速，不待荔枝香。"]'),
('yuding-63','送盧大理趙侍禦祭東嶽兼寄孟兗州','韓翃','唐','御定全唐诗','yuding','','[]','東嶽昔有事，兩臣朝望歸。驛亭開歲酒，齋舍著新衣。',48,'御定全唐詩/json/244.json','["東嶽昔有事，兩臣朝望歸。驛亭開歲酒，齋舍著新衣。", "上客鐘大理，主人陶武威。仍隨禦史馬，山路滿光輝。"]'),
('yuding-64','送皇甫大夫赴浙東','韓翃','唐','御定全唐诗','yuding','','[]','舟師分水國，漢將領秦官。麾下同心吏，軍中□□端。',48,'御定全唐詩/json/244.json','["舟師分水國，漢將領秦官。麾下同心吏，軍中□□端。", "吳門秋露濕，楚驛暮天寒。豪貴東山去，風流勝謝安。"]'),
('yuding-65','送韋秀才','韓翃','唐','御定全唐诗','yuding','','[]','東人相見罷，秋草獨歸時。幾日孫弘閣，當年謝脁詩。',48,'御定全唐詩/json/244.json','["東人相見罷，秋草獨歸時。幾日孫弘閣，當年謝脁詩。", "寒山葉落早，多雨路行遲。好憶金門步，功名自有期。"]'),
('yuding-0','送客一歸襄陽二歸潯陽','韓翃','唐','御定全唐诗','yuding','','[]','南驅匹馬會心期，東望扁舟愜夢思。熨斗山前春色早，',40,'御定全唐詩/json/245.json','["南驅匹馬會心期，東望扁舟愜夢思。熨斗山前春色早，", "兩地由來堪取興，三賢他日幸留詩。"]'),
('yuding-1','送故人赴江陵尋庾牧','韓翃','唐','御定全唐诗','yuding','','[]','主人持節拜荊州，走馬應從一路遊。斑竹岡連山雨暗，',40,'御定全唐詩/json/245.json','["主人持節拜荊州，走馬應從一路遊。斑竹岡連山雨暗，", "文體此時看又別，吾知小庾甚風流。"]'),
('yuding-2','送客水路歸陝','韓翃','唐','御定全唐诗','yuding','','[]','相風竿影曉來斜，渭水東流去不賒。枕上未醒秦地酒，',40,'御定全唐詩/json/245.json','["相風竿影曉來斜，渭水東流去不賒。枕上未醒秦地酒，", "好是吾賢佳賞地，行逢三月會連沙。"]'),
('yuding-3','送丹陽劉太真','韓翃','唐','御定全唐诗','yuding','','[]','長幹道上落花朝，羨爾當年賞事饒。下箸已憐鵝炙美，',40,'御定全唐詩/json/245.json','["長幹道上落花朝，羨爾當年賞事饒。下箸已憐鵝炙美，", "相訪不辭千里遠，西風好借木蘭橈。"]'),
('yuding-4','送客歸江州','韓翃','唐','御定全唐诗','yuding','','[]','東歸複得采真遊，江水迎君日夜流。客舍不離青雀舫，',40,'御定全唐詩/json/245.json','["東歸複得采真遊，江水迎君日夜流。客舍不離青雀舫，", "聞道泉明居止近，籃輿相訪為淹留。"]'),
('yuding-5','題張逸人園林','韓翃','唐','御定全唐诗','yuding','','[]','花源一曲映茅堂，清論閑階坐夕陽。麈尾手中毛已脫，',40,'御定全唐詩/json/245.json','["花源一曲映茅堂，清論閑階坐夕陽。麈尾手中毛已脫，", "更道小山宜助賞，呼兒舒簟醉岩芳。"]'),
('yuding-6','又題張逸人園林','韓翃','唐','御定全唐诗','yuding','','[]','藏頭不復見時人，愛此雲山奉養真。露色點衣孤嶼曉，',40,'御定全唐詩/json/245.json','["藏頭不復見時人，愛此雲山奉養真。露色點衣孤嶼曉，", "興罷歸來還對酌，茅簷掛著紫荷巾。"]'),
('yuding-7','送劉將軍','韓翃','唐','御定全唐诗','yuding','','[]','明光細甲照錏鍜，昨日承恩拜虎牙。膽大欲期姜伯約，',40,'御定全唐詩/json/245.json','["明光細甲照錏鍜，昨日承恩拜虎牙。膽大欲期姜伯約，", "闕下來時親伏奏，胡塵未盡不為家。"]'),
('yuding-8','送鄭員外','韓翃','唐','御定全唐诗','yuding','','[]','風流不減杜陵時，五十為郎未是遲。孺子亦知名下士，',40,'御定全唐詩/json/245.json','["風流不減杜陵時，五十為郎未是遲。孺子亦知名下士，", "要路眼青知己在，不應窮巷久低眉。"]'),
('yuding-9','寄徐州鄭使君','韓翃','唐','御定全唐诗','yuding','','[]','江城五馬楚雲邊，不羨雍容畫省年。才子舊稱何水部，',40,'御定全唐詩/json/245.json','["江城五馬楚雲邊，不羨雍容畫省年。才子舊稱何水部，", "雖臥郡齋千里隔，與君同見月初圓。"]'),
('yuding-10','送襄垣王君歸南陽別墅','韓翃','唐','御定全唐诗','yuding','','[]','都門霽後不飛塵，草色萋萋滿路春。雙兔坡東千室吏，',40,'御定全唐詩/json/245.json','["都門霽後不飛塵，草色萋萋滿路春。雙兔坡東千室吏，", "少婦比來多遠望，應知蟢子上羅巾。"]'),
('yuding-11','送王誕渤海使赴李太守行營','韓翃','唐','御定全唐诗','yuding','','[]','少年結客散黃金，中歲連兵掃綠林。渤海名王曾折首，',40,'御定全唐詩/json/245.json','["少年結客散黃金，中歲連兵掃綠林。渤海名王曾折首，", "喜見明時鐘太尉，功名一似舊淮陰。"]'),
('yuding-12','送王少府歸杭州','韓翃','唐','御定全唐诗','yuding','','[]','歸舟一路轉青蘋，更欲隨潮向富春。吳郡陸機稱地主，',40,'御定全唐詩/json/245.json','["歸舟一路轉青蘋，更欲隨潮向富春。吳郡陸機稱地主，", "早晚重過魚浦宿，遙憐佳句篋中新。"]'),
('yuding-13','贈王隨','韓翃','唐','御定全唐诗','yuding','','[]','青雲自致晚應遙，朱邸新婚樂事饒。飲罷更憐雙袖舞，',40,'御定全唐詩/json/245.json','["青雲自致晚應遙，朱邸新婚樂事饒。飲罷更憐雙袖舞，", "更說球場新雨歇，王孫今日定相邀。"]'),
('yuding-14','同題仙游觀','韓翃','唐','御定全唐诗','yuding','','[]','仙台下見五城樓，風物淒淒宿雨收。山色遙連秦樹晚，',40,'御定全唐詩/json/245.json','["仙台下見五城樓，風物淒淒宿雨收。山色遙連秦樹晚，", "何用別尋方外去，人間亦自有丹丘。"]'),
('yuding-15','訪王起居不遇留贈','韓翃','唐','御定全唐诗','yuding','','[]','雙龍闕下拜恩初，天子令君注起居。載筆已齊周右史，',40,'御定全唐詩/json/245.json','["雙龍闕下拜恩初，天子令君注起居。載筆已齊周右史，", "賀客自知來獨晚，青驪不見意何如。"]'),
('yuding-16','送劉評事赴廣州使幕','韓翃','唐','御定全唐诗','yuding','','[]','征南官屬似君稀，才子當今劉孝威。蠻府參軍趨傳舍，',40,'御定全唐詩/json/245.json','["征南官屬似君稀，才子當今劉孝威。蠻府參軍趨傳舍，", "為報蒼梧雲影道，明年早送客帆歸。"]'),
('yuding-17','送冷朝陽還上元','韓翃','唐','御定全唐诗','yuding','','[]','青絲dh引木蘭船，名遂身歸拜慶年。落日澄江烏榜外，',41,'御定全唐詩/json/245.json','["青絲dh引木蘭船，名遂身歸拜慶年。落日澄江烏榜外，", "別後依依寒食裏，共君攜手在東田。"]'),
('yuding-18','送高別駕歸汴州','韓翃','唐','御定全唐诗','yuding','','[]','信陵門下識君偏，駿馬輕裘正少年。寒雨送歸千裏外，',40,'御定全唐詩/json/245.json','["信陵門下識君偏，駿馬輕裘正少年。寒雨送歸千裏外，", "久客未知何計是，參差去借汶陽田。"]'),
('yuding-19','送康洗馬歸滑州','韓翃','唐','御定全唐诗','yuding','','[]','腰佩雕弓漢射聲，東歸銜命見雙旌。青絲玉勒康侯馬，',40,'御定全唐詩/json/245.json','["腰佩雕弓漢射聲，東歸銜命見雙旌。青絲玉勒康侯馬，", "懷君又隔千山遠，別後春風百草生。"]'),
('yuding-20','寄上田僕射','韓翃','唐','御定全唐诗','yuding','','[]','家封薛縣異諸田，報主榮親義兩全。僕射臨戎謝安石，',40,'御定全唐詩/json/245.json','["家封薛縣異諸田，報主榮親義兩全。僕射臨戎謝安石，", "應念一身留闕下，闔門遙寄魯西偏。"]'),
('yuding-21','送王光輔歸青州兼寄儲侍郎','韓翃','唐','御定全唐诗','yuding','','[]','幾回奏事建章宮，聖主偏知漢將功。身著紫衣趨闕下，',40,'御定全唐詩/json/245.json','["幾回奏事建章宮，聖主偏知漢將功。身著紫衣趨闕下，", "遠憶故人滄海別，當年好躍五花驄。"]'),
('yuding-22','宴楊駙馬山池','韓翃','唐','御定全唐诗','yuding','','[]','垂楊拂岸草茸茸，繡戶簾前花影重。鱠下玉盤紅縷細，',40,'御定全唐詩/json/245.json','["垂楊拂岸草茸茸，繡戶簾前花影重。鱠下玉盤紅縷細，", "落日泛舟同醉處，回潭百丈映千峰。"]'),
('yuding-23','送長史李少府入蜀','韓翃','唐','御定全唐诗','yuding','','[]','行行獨出故關遲，南望千山無盡期。見舞巴童應暫笑，',40,'御定全唐詩/json/245.json','["行行獨出故關遲，南望千山無盡期。見舞巴童應暫笑，", "別後此心君自見，山中何事不相思。"]'),
('yuding-24','送客還江東','韓翃','唐','御定全唐诗','yuding','','[]','不妨高臥順流歸，五兩行看掃翠微。鼯鼠夜喧孤枕近，',40,'御定全唐詩/json/245.json','["不妨高臥順流歸，五兩行看掃翠微。鼯鼠夜喧孤枕近，", "君到新林江口泊，吟詩應賞謝玄暉。"]'),
('yuding-25','寄令狐尚書','韓翃','唐','御定全唐诗','yuding','','[]','立身榮貴複何如，龍節紅旗從板輿。妙略多推霍驃騎，',40,'御定全唐詩/json/245.json','["立身榮貴複何如，龍節紅旗從板輿。妙略多推霍驃騎，", "他日感恩慚未報，舉家猶似涸池魚。"]'),
('yuding-26','扈從郊廟因呈兩省諸公','韓翃','唐','御定全唐诗','yuding','','[]','丹墀列士主恩同，廄馬翩翩出漢宮。奉引乘輿金仗裏，',40,'御定全唐詩/json/245.json','["丹墀列士主恩同，廄馬翩翩出漢宮。奉引乘輿金仗裏，", "明日駕回承雨露，齊將萬歲及春風。"]'),
('yuding-27','送端州馮使君','韓翃','唐','御定全唐诗','yuding','','[]','白皙風流似有須，一門豪貴領蒼梧。三峰亭暗橘邊宿，',40,'御定全唐詩/json/245.json','["白皙風流似有須，一門豪貴領蒼梧。三峰亭暗橘邊宿，", "懷君樂事不可見，鬃馬翩翩新虎符。"]'),
('yuding-28','送王府張參軍附學及第東歸','韓翃','唐','御定全唐诗','yuding','','[]','鄰家不識鬥雞翁，閉戶能齊隱者風。顧步曾為小山客，',40,'御定全唐詩/json/245.json','["鄰家不識鬥雞翁，閉戶能齊隱者風。顧步曾為小山客，", "寂寂故園行見在，暮天殘雪洛城東。"]'),
('yuding-29','送齊明府赴東陽','韓翃','唐','御定全唐诗','yuding','','[]','綠絲帆繂桂為檣，過盡淮山楚水長。萬里移家背春穀，',40,'御定全唐詩/json/245.json','["綠絲帆繂桂為檣，過盡淮山楚水長。萬里移家背春穀，", "別後心期如在眼，猿聲煙色樹蒼蒼。"]'),
('yuding-30','魯中送從事歸滎陽','韓翃','唐','御定全唐诗','yuding','','[]','故園衰草帶滎波，歲晚知如君思何。輕橐歸時魯縞薄，',40,'御定全唐詩/json/245.json','["故園衰草帶滎波，歲晚知如君思何。輕橐歸時魯縞薄，", "累路盡逢知己在，曾無對酒不高歌。"]'),
('yuding-31','兗州送李明府使蘇州便赴告期','韓翃','唐','御定全唐诗','yuding','','[]','莫言水國去迢迢，白馬吳門見不遙。楓樹林中經楚雨，',24,'御定全唐詩/json/245.json','["莫言水國去迢迢，白馬吳門見不遙。楓樹林中經楚雨，"]'),
('yuding-32','送田明府歸終南別業','韓翃','唐','御定全唐诗','yuding','','[]','故園此日多心賞，窗下泉流竹外雲。近館應逢沈道士，',40,'御定全唐詩/json/245.json','["故園此日多心賞，窗下泉流竹外雲。近館應逢沈道士，", "相勸早移丹鳳闕，不須常戀白鷗群。"]'),
('yuding-33','家兄自山南罷歸獻詩敘事','韓翃','唐','御定全唐诗','yuding','','[]','時輩已爭先，吾兄未著鞭。空嗟鑷須日，猶是屈腰年。',240,'御定全唐詩/json/245.json','["時輩已爭先，吾兄未著鞭。空嗟鑷須日，猶是屈腰年。", "不以殊方遠，仍論水地偏。襄橙隨客路，漢竹引歸船。", "雲木巴東峽，林泉峴北川。池餘騎馬處，宅似臥龍邊。", "夜簟千峰月，朝窗萬井煙。朱荷江女院，青稻楚人田。", "縣舍多瀟灑，城樓入醉眠。黃苞柑正熟，紅縷鱠仍鮮。", "坐厭牽絲倦，因從解綬旋。初辭五斗米，唯奉一囊錢。", "室好生虛白，書耽守太玄。櫪中嘶款段，階下引潺湲。", "落照淵明柳，春風叔夜弦。絳紗儒客帳，丹訣羽人篇。", "雅論承安石，新詩與惠連。興清湖見底，襟豁霧開天。", "魏闕心猶系，周才道豈捐。一丘無自逸，三府會招賢。"]'),
('yuding-34','奉送王相公縉赴幽州巡邊','韓翃','唐','御定全唐诗','yuding','','[]','黃閣開帷幄，丹墀侍冕旒。位高湯左相，權總漢諸侯。',72,'御定全唐詩/json/245.json','["黃閣開帷幄，丹墀侍冕旒。位高湯左相，權總漢諸侯。", "不改周南化，仍分趙北憂。雙旌過易水，千騎入幽州。", "塞草連天暮，邊風動地秋。無因隨遠道，結束佩吳鉤。"]'),
('yuding-35','寄贈虢州張參軍','韓翃','唐','御定全唐诗','yuding','','[]','三十事諸侯，賢豪冠北州。桃花迎駿馬，蘇合染輕裘。',144,'御定全唐詩/json/245.json','["三十事諸侯，賢豪冠北州。桃花迎駿馬，蘇合染輕裘。", "觀妓將軍第，題詩關尹樓。青林朝送客，綠嶼晚回舟。", "好栗分通子，名香贈莫愁。洗杯新酒熟，把燭故人留。", "百雉歸雲過，千峰宿雨收。蒹葭露下晚，菡萏水中秋。", "憶昨陪行樂，常時接獻酬。佳期雖霧散，惠問亦川流。", "開卷酲堪解，含毫思苦抽。無因達情意，西望日悠悠。"]'),
('yuding-36','送李中丞赴商州','韓翃','唐','御定全唐诗','yuding','','[]','五馬渭橋東，連嘶逐曉風。當年紫髯將，他日黑頭公。',72,'御定全唐詩/json/245.json','["五馬渭橋東，連嘶逐曉風。當年紫髯將，他日黑頭公。", "不異金吾寵，兼齊玉帳雄。閉營春雪下，吹角暮山空。", "香麝松陰裏，寒猿黛色中。郡齋多賞事，好與故人同。"]'),
('yuding-37','漢宮曲二首','韓翃','唐','御定全唐诗','yuding','','[]','駿馬繡障泥，紅塵撲四蹄。歸時何太晚，日照杏花西。',48,'御定全唐詩/json/245.json','["駿馬繡障泥，紅塵撲四蹄。歸時何太晚，日照杏花西。", "繡幕珊瑚鉤，春開翡翠樓。深情不肯道，嬌倚鈿箜篌。"]'),
('yuding-38','陪孟都督祭岳途中有贈','韓翃','唐','御定全唐诗','yuding','','[]','封疆七百里，祿秩二千石。擁節祠太山，寒天霜草白。',24,'御定全唐詩/json/245.json','["封疆七百里，祿秩二千石。擁節祠太山，寒天霜草白。"]'),
('yuding-39','宿甑山','韓翃','唐','御定全唐诗','yuding','','[]','山中今夜何人，闕下當年近臣。',28,'御定全唐詩/json/245.json','["山中今夜何人，闕下當年近臣。", "青瑣應須早去，白雲何用相親。"]'),
('yuding-40','別甑山','韓翃','唐','御定全唐诗','yuding','','[]','一身趨侍丹墀，西路翩翩去時。',28,'御定全唐詩/json/245.json','["一身趨侍丹墀，西路翩翩去時。", "惆悵青山綠水，何年更是來期。"]'),
('yuding-41','送陳明府赴淮南','韓翃','唐','御定全唐诗','yuding','','[]','年華近逼清明，落日微風送行。黃鳥綿蠻芳樹，',35,'御定全唐詩/json/245.json','["年華近逼清明，落日微風送行。黃鳥綿蠻芳樹，", "應渡淮南信宿，諸侯擁旆相迎。"]'),
('yuding-42','送客知鄂州','韓翃','唐','御定全唐诗','yuding','','[]','江口千家帶楚雲，江花亂點雪紛紛。',32,'御定全唐詩/json/245.json','["江口千家帶楚雲，江花亂點雪紛紛。", "春風落日誰相見，青翰舟中有鄂君。"]'),
('yuding-43','寒食','韓翃','唐','御定全唐诗','yuding','','[]','春城無處不飛花，寒食東風禦柳斜。',32,'御定全唐詩/json/245.json','["春城無處不飛花，寒食東風禦柳斜。", "日暮漢宮傳蠟燭，輕煙散入五侯家。"]'),
('yuding-44','羽林騎','韓翃','唐','御定全唐诗','yuding','','[]','駿馬牽來禦柳中，鳴鞭欲向渭橋東。',32,'御定全唐詩/json/245.json','["駿馬牽來禦柳中，鳴鞭欲向渭橋東。", "紅蹄亂蹋春城雪，花頷驕嘶上苑風。"]'),
('yuding-45','看調馬','韓翃','唐','御定全唐诗','yuding','','[]','鴛鴦赭白齒新齊，晚日花中散碧蹄。',32,'御定全唐詩/json/245.json','["鴛鴦赭白齒新齊，晚日花中散碧蹄。", "玉勒鬥回初噴沫，金鞭欲下不成嘶。"]'),
('yuding-46','寄贈衡州楊使君','韓翃','唐','御定全唐诗','yuding','','[]','湘竹斑斑湘水春，衡陽太守虎符新。',32,'御定全唐詩/json/245.json','["湘竹斑斑湘水春，衡陽太守虎符新。", "朝來笑向歸鴻道，早晚南飛見主人。"]'),
('yuding-47','宿石邑山中','韓翃','唐','御定全唐诗','yuding','','[]','浮雲不共此山齊，山靄蒼蒼望轉迷。',32,'御定全唐詩/json/245.json','["浮雲不共此山齊，山靄蒼蒼望轉迷。", "曉月暫飛高樹裏，秋河隔在數峰西。"]'),
('yuding-48','江南曲','韓翃','唐','御定全唐诗','yuding','','[]','長樂花枝雨點銷，江城日暮好相邀。',32,'御定全唐詩/json/245.json','["長樂花枝雨點銷，江城日暮好相邀。", "春樓不閉葳蕤鎖，綠水回通宛轉橋。"]'),
('yuding-49','贈張千牛','韓翃','唐','御定全唐诗','yuding','','[]','蓬萊闕下是天家，上路新回白鼻騧。急管晝催平樂酒，春衣夜宿杜陵花。',32,'御定全唐詩/json/245.json','["蓬萊闕下是天家，上路新回白鼻騧。急管晝催平樂酒，春衣夜宿杜陵花。"]'),
('yuding-50','漢宮曲二首','韓翃','唐','御定全唐诗','yuding','','[]','五柞宮中過臘看，萬年枝上雪花殘。',64,'御定全唐詩/json/245.json','["五柞宮中過臘看，萬年枝上雪花殘。", "綺窗夜閉玉堂靜，素綆朝穿金井寒。", "家在長陵小市中，珠簾繡戶對春風。", "君王昨日移仙仗，玉輦迎將入漢宮。"]'),
('yuding-51','贈李翼','韓翃','唐','御定全唐诗','yuding','','[]','王孫別舍擁朱輪，不羨空名樂此身。',32,'御定全唐詩/json/245.json','["王孫別舍擁朱輪，不羨空名樂此身。", "門外碧潭春洗馬，樓前紅燭夜迎人。"]'),
('yuding-52','少年行','韓翃','唐','御定全唐诗','yuding','','[]','千點斕斒玉勒驄，青絲結尾繡纏鬃。鳴鞭曉出章台路，葉葉春衣楊柳風。',32,'御定全唐詩/json/245.json','["千點斕斒玉勒驄，青絲結尾繡纏鬃。鳴鞭曉出章台路，葉葉春衣楊柳風。"]'),
('yuding-53','題玉真觀李秘書院','韓翃','唐','御定全唐诗','yuding','','[]','白雲斜日影深松，玉宇瑤壇知幾重。',32,'御定全唐詩/json/245.json','["白雲斜日影深松，玉宇瑤壇知幾重。", "把酒題詩人散後，華陽洞裏有疏鐘。"]'),
('yuding-54','送客之潞府','韓翃','唐','御定全唐诗','yuding','','[]','官柳青青匹馬嘶，回風暮雨入銅鞮。佳期別在春山裏，應是人參五葉齊。',32,'御定全唐詩/json/245.json','["官柳青青匹馬嘶，回風暮雨入銅鞮。佳期別在春山裏，應是人參五葉齊。"]'),
('yuding-55','送客貶五溪','韓翃','唐','御定全唐诗','yuding','','[]','南過猿聲一逐臣，回看秋草淚沾巾。',32,'御定全唐詩/json/245.json','["南過猿聲一逐臣，回看秋草淚沾巾。", "寒天暮雪空山裏，幾處蠻家是主人。"]'),
('yuding-56','送齊山人歸長白山','韓翃','唐','御定全唐诗','yuding','','[]','舊事仙人白兔公，掉頭歸去又乘風。',32,'御定全唐詩/json/245.json','["舊事仙人白兔公，掉頭歸去又乘風。", "柴門流水依然在，一路寒山萬木中。"]'),
('yuding-57','寄裴鄆州','韓翃','唐','御定全唐诗','yuding','','[]','烏紗靈壽對秋風，悵望浮雲濟水東。',32,'御定全唐詩/json/245.json','["烏紗靈壽對秋風，悵望浮雲濟水東。", "官樹陰陰鈴閣暮，州人轉憶白頭翁。"]'),
('yuding-58','梁城贈一二同幕','韓翃','唐','御定全唐诗','yuding','','[]','五營河畔列旌旗，吹角鳴鼙日暮時。',32,'御定全唐詩/json/245.json','["五營河畔列旌旗，吹角鳴鼙日暮時。", "曾是信陵門下客，雨回相吊不勝悲。"]'),
('yuding-59','河上寄故人','韓翃','唐','御定全唐诗','yuding','','[]','河流曉天，濮水清煙。日暖昆吾臺上，春深顓頊城邊。',45,'御定全唐詩/json/245.json','["河流曉天，濮水清煙。日暖昆吾臺上，春深顓頊城邊。", "鶯聲亂啁鵠□，花片細點龍泉。西望情人早至，"]'),
('yuding-60','留題甯川香蓋寺壁','韓翃','唐','御定全唐诗','yuding','','[]','愛遠登高塵眼開，為憐蕭寺上經台。山川誰識龍蛇蟄，',40,'御定全唐詩/json/245.json','["愛遠登高塵眼開，為憐蕭寺上經台。山川誰識龍蛇蟄，", "何人會得其中事，又被殘花落日催。"]'),
('yuding-61','寄柳氏','韓翃','唐','御定全唐诗','yuding','','[]','章台柳，章台柳，顏色青青今在否？縱使長條似舊垂，',24,'御定全唐詩/json/245.json','["章台柳，章台柳，顏色青青今在否？縱使長條似舊垂，"]'),
('yuding-0','海上寄蕭立','獨孤及','唐','御定全唐诗','yuding','','[]','朔風剪塞草，寒露日夜結。行行到瀛壖，歸思生暮節。',120,'御定全唐詩/json/246.json','["朔風剪塞草，寒露日夜結。行行到瀛壖，歸思生暮節。", "驛樓見萬里，延首望遼碣。遠海入大荒，平蕪際窮發。", "舊國在夢想，故人胡且越。契闊阻風期，荏苒成雨別。", "海西望京口，兩地各天末。索居動經秋，再笑知曷月。", "日南望中盡，唯見飛鳥滅。音塵未易得，何由慰饑渴。"]'),
('yuding-1','三月三日，自京到華陰，于水亭獨酌，寄裴六、薛八','獨孤及','唐','御定全唐诗','yuding','','[]','祗役匪遑息，經時客三秦。還家問節候，知到上巳辰。',144,'御定全唐詩/json/246.json','["祗役匪遑息，經時客三秦。還家問節候，知到上巳辰。", "山縣何所有，高城閉青春。和風不吾欺，桃杏滿四鄰。", "舊友適遠別，誰當接歡欣。呼兒命長瓢，獨酌湘吳醇。", "一酌一朗詠，既酣意亦申。言筌暫兩忘，霞月只相新。", "裴子塵表物，薛侯席上珍。寄書二傲吏，何日同車茵。", "詎肯使空名，終然羈此身。他年解桎梏，長作海上人。"]'),
('yuding-2','代書寄上裴六冀、劉二潁','獨孤及','唐','御定全唐诗','yuding','','[]','昔余馬首東，君在海北汭。盡屏簿領書，相與議岩穴。',240,'御定全唐詩/json/246.json','["昔余馬首東，君在海北汭。盡屏簿領書，相與議岩穴。", "載來詣佳境，每山有車轍。長嘯林木動，高歌唾壺缺。", "此辭月未周，虜馬嘶絳闕。猛虎踞大道，九州當中裂。", "聞君棄孤城，猶自握漢節。恥棲惡木影，忍與故山別。", "脫舄掛嶺雲，冏然若鳥逝。唯留潺湲水，分付練溪月。", "爾來大谷梨，白花再成雪。關梁限天險，歡樂竟兩絕。", "大盜近削平，三川今底寧。句芒布春令，屏翳收雷霆。", "伊洛日夜漲，鳴皋蘭杜青。鶱鶱兩黃鵠，何處遊青冥。", "疇昔切玉刃，應如新發硎。及時當樹勳，高懸景鐘銘。", "莫抱白雲意，徑往丹丘庭。功成儻長揖，然後謀滄溟。"]'),
('yuding-3','客舍月下對酒，醉後寄畢四耀','獨孤及','唐','御定全唐诗','yuding','','[]','鄉路風雪深，生事憂患迫。天長波瀾廣，高舉無六翮。',192,'御定全唐詩/json/246.json','["鄉路風雪深，生事憂患迫。天長波瀾廣，高舉無六翮。", "獨立寒夜移，幽境思彌積。霜月照膽淨，銀河入簷白。", "沽酒聊自勞，開樽坐簷隙。主人奏絲桐，能使高興劇。", "清機暫無累，獻酢更絡繹。慷慨葛天歌，愔愔廣陵陌。", "既醉萬事遺，耳熱心亦適。視身兀如泥，瞪目傲今昔。", "故人間城闕，音信兩脈脈。別時前盟在，寸景莫自擲。", "心與白日鬥，十無一滿百。寓形薪火內，甘作天地客。", "與物無親疏，鬥酒勝竹帛。何必用自苦，將貽古賢責。"]'),
('yuding-4','下弋陽江舟中代書寄裴侍禦','獨孤及','唐','御定全唐诗','yuding','','[]','故鄉隔西日，水去連長天。前路知幾許，但指天南邊。',144,'御定全唐詩/json/246.json','["故鄉隔西日，水去連長天。前路知幾許，但指天南邊。", "愴恨極浦外，隱映青山連。東風滿帆來，五兩如弓弦。", "遙羨繡衣客，冏然馬首先。得餐武昌魚，不顧潯陽田。", "屈指數別日，忽乎成兩年。百花已滿眼，春草漸碧鮮。", "豈是離居時，奈何於役牽。洞庭有深涉，曷日期歸旋。", "且作異鄉料，詎知攜手緣。離憂未易銷，莫道樽酒賢。"]'),
('yuding-5','癸卯歲赴南豐道中聞京師失守寄權士繇韓幼深','獨孤及','唐','御定全唐诗','yuding','','[]','種田不遇歲，策名不遭時。胡塵晦落日，西望泣路岐。',180,'御定全唐詩/json/246.json','["種田不遇歲，策名不遭時。胡塵晦落日，西望泣路岐。", "猛虎嘯北風，麇麚皆載馳。深泥架疲牛，踸踔余何之。", "詰屈白道轉，繚繞清溪隨。荒穀嘯山鬼，深林啼子規。", "長歎指故山，三奏歸來詞。不逢眼中人，調苦車逶遲。", "士繇松筠操，幼深瓊樹姿。別來平安否，何階一申眉。", "白雲失帝鄉，遠水恨天涯。昂藏雙威鳳，曷月還西枝。", "努力愛華髮，盛年振羽儀。但令迍難康，不負滄洲期。", "莫作新亭泣，徒使夷吾嗤。"]'),
('yuding-6','賈員外處見中書賈舍人巴陵詩集覽之懷舊代書寄贈','獨孤及','唐','御定全唐诗','yuding','','[]','海岸望青瑣，雲長天漫漫。十年不一展，知有關山難。',144,'御定全唐詩/json/246.json','["海岸望青瑣，雲長天漫漫。十年不一展，知有關山難。", "適逢阮始平，立馬問長安。取公詠懷詩，示我江海瀾。", "暫若窺武庫，森然矛戟寒。眼明遺頭風，心悅忘朝餐。", "大駕今返正，熊羆扈鳴鑾。公遊鳳凰沼，獻可在筆端。", "系越有長纓，封關只一丸。冏然翔寥廓，仰望慚羽翰。", "嘉會不我與，相思歲雲殫。唯當袖佳句，持比青琅玕。"]'),
('yuding-7','代書寄上李廣州','獨孤及','唐','御定全唐诗','yuding','','[]','皖水望番禺，迢迢青天末。鴻雁飛不到，音塵何由達。',144,'御定全唐詩/json/246.json','["皖水望番禺，迢迢青天末。鴻雁飛不到，音塵何由達。", "獨有輿人歌，隔雲聲喧聒。皆稱府君仁，百越賴全活。", "推誠魚鱉信，持正魑魅怛。疲民保中和，性足無夭閼。", "天子咨四岳，佇公濟方割。幾時複旋歸，入踐青瑣闥。", "賤子托明德，繚若松上葛。別離鄙吝生，結念思所豁。", "門欄關山阻，岐路天地闊。唯憑萬里書，持用慰饑渴。"]'),
('yuding-8','夏中酬于逖畢耀問病見贈','獨孤及','唐','御定全唐诗','yuding','','[]','救物智所昧，學仙願未從。行藏兩乖角，蹭蹬風波中。',168,'御定全唐詩/json/246.json','["救物智所昧，學仙願未從。行藏兩乖角，蹭蹬風波中。", "薄宦恥降志，臥痾非養蒙。閉關涉兩旬，羈思浩無窮。", "鸑鷟何處來，雙舞下碧空。離別隔雲雨，惠然此相逢。", "把手賀疾間，舉杯欣酒濃。新詩見久要，清論激深衷。", "高館舒夜簟，開門延微風。火雲赫嵯峨，日暮千萬峰。", "遙指故山笑，相看撫號鐘。聲和由心清，事感知氣同。", "出處未易料，且歌緩愁容。願君崇明德，歲暮如青松。"]'),
('yuding-9','酬梁二十宋中所贈兼留別梁少府','獨孤及','唐','御定全唐诗','yuding','','[]','少讀黃帝書，肯不笑機事。意猶負深衷，未免名跡累。',192,'御定全唐詩/json/246.json','["少讀黃帝書，肯不笑機事。意猶負深衷，未免名跡累。", "厭貧學幹祿，欲徇賓王利。甘為風波人，豈複江海意。", "擔簦平臺下，是日飲羈思。逢君道寸心，暫喜一交臂。", "緒言未及竟，離念已複至。甯陵望南丘，雲雨成兩地。", "途殊跡方間，河廣流且駛。暮帆望不及，覽贈心欲醉。", "愛君如金錫，昆弟皆茂異。奕赫連絲衣，榮養能錫類。", "君子道未長，深藏青雲器。巨鱗有縱時，今日不足議。", "唯當加餐飯，好我袖中字。別離動經年，莫道分首易。"]'),
('yuding-10','庚子歲避地至玉山，酬韓司馬所贈','獨孤及','唐','御定全唐诗','yuding','','[]','滄海疾風起，洪波駭恬鱗。已無濟川分，甘作乘桴人。',96,'御定全唐詩/json/246.json','["滄海疾風起，洪波駭恬鱗。已無濟川分，甘作乘桴人。", "揮手謝秣陵，舉帆指甌閩。安和風塵表，偶與瓊瑤親。", "共悲行路難，況逢江南春。故園忽如夢，返複知何辰。", "曠野豺虎滿，深山蘭蕙新。枉君灞陵什，回首徒酸辛。"]'),
('yuding-11','奉和李大夫同呂評事太行苦熱行兼寄院中諸公','獨孤及','唐','御定全唐诗','yuding','','[]','駟馬上太行，修途亙遼碣。王程無留駕，日昃未遑歇。',192,'御定全唐詩/json/246.json','["駟馬上太行，修途亙遼碣。王程無留駕，日昃未遑歇。", "請問此何時，恢台朱明月。長蛇稽天討，上將方北伐。", "明主命使臣，皇華得時傑。已忘羊腸險，豈憚濕風熱。", "搖策汗滂滄，登岸思紆結。炎雲如煙火，溪穀將恐竭。", "晝景赩可畏，涼飆何由發。山長飛鳥墮，目極行車絕。", "趙魏方俶擾，安危俟明哲。歸路豈不懷，飲冰有苦節。", "會同傳檄至，疑議立談決。況有阮元瑜，翩翩秉書劄。", "起予歌赤阪，永好逾白雪。誰念剖竹人，無因執羈絏。"]'),
('yuding-12','酬皇甫侍禦望天灊山見示之作','獨孤及','唐','御定全唐诗','yuding','','[]','早歲慕五嶽，嘗為塵機礙。孰知天柱峰，今與郡齋對。',264,'御定全唐詩/json/246.json','["早歲慕五嶽，嘗為塵機礙。孰知天柱峰，今與郡齋對。", "隱嶙抱元氣，氤氳含青靄。雲崖媚遠空，石壁寒古塞。", "漢皇南遊日，望秩此昭配。法駕到穀口，禮容振荒外。", "焚柴百神趨，執玉萬方會。天旋物順動，德布澤滂霈。", "講武威已耀，學仙功未艾。黃金竟何成，洪業遽淪昧。", "度世若一瞬，昨朝已千載。如今封禪壇，唯見雲雨晦。", "長望哀往古，勞生慚大塊。清暉幸相娛，幽獨知所賴。", "寒城春方正，初日明可愛。萬殊喜陽和，余亦荷時泰。", "山色日夜綠，下有清淺瀨。愧作拳僂人，沈迷簿書內。", "登臨歎拘限，出處悲老大。況聽郢中曲，複識湘南態。", "思免物累牽，敢令道機退。瞞然誦佳句，持此秋蘭佩。"]'),
('yuding-13','送陳兼應辟兼寄高適、賈至','獨孤及','唐','御定全唐诗','yuding','','[]','結綠處燕石，卞和不必知。所以王佐才，未能忘茅茨。',288,'御定全唐詩/json/246.json','["結綠處燕石，卞和不必知。所以王佐才，未能忘茅茨。", "罷官梁山外，獲稻楚水湄。適會傅岩人，虛舟濟川時。", "天網忽搖頓，公才難棄遺。鳳凰翔千仞，今始一鳴岐。", "上馬指國門，舉鞭謝書帷。預知大人賦，掩卻歸來詞。", "天子方在宥，朝廷張四維。料君能獻可，努力副疇咨。", "舊友滿皇州，高冠飛翠蕤。相逢絳闕下，應道軒車遲。", "高侯秉戎翰，策馬觀西夷。方從幕中事，參謀王者師。", "賈生去洛陽，焜耀琳琅姿。芳名動北步，逸韻淩南皮。", "肅肅舉鴻毛，冷然順風吹。波流有同異，由是限別離。", "漢塞隔隴底，秦川連鎬池。白雲日夜滿，道里安可思。", "夢想浩盈積，物華愁變衰。因君附錯刀，送遠益淒其。", "四海各橫絕，九霄應易期。不知故巢燕，決起棲何枝。"]'),
('yuding-14','送相裏郎中赴江西','獨孤及','唐','御定全唐诗','yuding','','[]','君把一尺詔，南遊濟滄浪。受恩忘險艱，不道歧路長。',216,'御定全唐詩/json/246.json','["君把一尺詔，南遊濟滄浪。受恩忘險艱，不道歧路長。", "戎狄方構患，休牛殊未遑。三秦千倉空，戰卒如餓狼。", "委輸資外府，諏謀寄賢良。有才當陳力，安得遂翱翔。", "豈不慎井賦，賦均人亦康。遙知軒車到，萬室安耕桑。", "火伏金氣騰，昊天欲蒼茫。寒蟬慘巴鄧，秋色愁沅湘。", "昨日攜手西，於今芸再黃。歡娛詎幾許，複向天一方。", "蹢躅話世故，惆悵舉離觴。共求數刻歡，戲謔君此堂。", "今日把手笑，少時各他鄉。身名同風波，聚散未易量。", "曷月還朝天，及時開智囊。前期儻猶闊，加飯勉自強。"]'),
('yuding-15','觀海','獨孤及','唐','御定全唐诗','yuding','','[]','北登渤澥島，回首秦東門。誰屍造物功，鑿此天池源。',120,'御定全唐詩/json/246.json','["北登渤澥島，回首秦東門。誰屍造物功，鑿此天池源。", "澒洞吞百谷，周流無四垠。廓然混茫際，望見天地根。", "白日自中吐，扶桑如可捫。超遙蓬萊峰，想像金台存。", "秦帝昔經此，登臨冀飛翻。揚旌百神會，望日群山奔。", "徐福竟何成，羨門徒空言。唯見石橋足，千年潮水痕。"]'),
('yuding-16','初晴抱琴登馬退山對酒望遠醉後作','獨孤及','唐','御定全唐诗','yuding','','[]','年長心易感，況為憂患纏。壯圖迫世故，行止兩茫然。',168,'御定全唐詩/json/246.json','["年長心易感，況為憂患纏。壯圖迫世故，行止兩茫然。", "王旅方伐叛，虎臣皆被堅。魯人著儒服，甘就南山田。", "挈榼上高磴，超遙望平川。滄江大如綖，隱映入遠天。", "荒服何所有，山花雪中然。寒泉得日景，吐溜鳴湔湔。", "舉酒勸白雲，唱歌慰頹年。微風度竹來，韻我號鐘弦。", "一彈一引滿，耳熱知心宣。曲終餘亦酣，起舞山水前。", "人生幾何時，太半百憂煎。今日羈愁破，始知濁酒賢。"]'),
('yuding-17','同徐侍郎五雲溪新庭重陽宴集作','獨孤及','唐','御定全唐诗','yuding','','[]','萬峰蒼翠色，雙溪清淺流。已符東山趣，況值江南秋。',96,'御定全唐詩/json/246.json','["萬峰蒼翠色，雙溪清淺流。已符東山趣，況值江南秋。", "白露天地肅，黃花門館幽。山公惜美景，肯為芳樽留。", "五馬照池塘，繁弦催獻酬。臨風孟嘉帽，乘興李膺舟。", "騁望傲千古，當歌遺四愁。豈令永和人，獨擅山陰遊。"]'),
('yuding-18','雨晴後陪王員外泛後湖得溪字','獨孤及','唐','御定全唐诗','yuding','','[]','遠山媚平楚，宿雨漲清溪。沿溯任舟楫，歡言無町畦。',36,'御定全唐詩/json/246.json','["遠山媚平楚，宿雨漲清溪。沿溯任舟楫，歡言無町畦。", "酒酣相視笑，心與白鷗齊。"]'),
('yuding-19','題思禪寺上方','獨孤及','唐','御定全唐诗','yuding','','[]','溪口聞法鼓，停橈登翠屏。攀雲到金界，合掌開禪扃。',120,'御定全唐詩/json/246.json','["溪口聞法鼓，停橈登翠屏。攀雲到金界，合掌開禪扃。", "鬱律眾山抱，空蒙花雨零。老僧指香樓，雲是不死庭。", "眇眇于越路，茫茫春草青。遠山噴百穀，繚繞馳東溟。", "目極道何在，境照心亦冥。騞然諸根空，破結如破瓶。", "下視三界狹，但聞五濁腥。山中有良藥，吾欲隳天形。"]'),
('yuding-20','季冬自嵩山赴洛道中作','獨孤及','唐','御定全唐诗','yuding','','[]','皇運偶中變，長蛇食中土。天蓋西北傾，眾星隕如雨。',216,'御定全唐詩/json/246.json','["皇運偶中變，長蛇食中土。天蓋西北傾，眾星隕如雨。", "胡塵動地起，千里聞戰鼓。死人成為阜，流血塗草莽。", "策馬何紛紛，捐軀抗豺虎。甘心赴國難，誰謂荼葉苦。", "天子初受命，省方造區宇。斬鯨安溟波，截鼇作天柱。", "三微複正統，五玉歸文祖。不圖漢官儀，今日忽再睹。", "升高望京邑，佳氣連海浦。寶鼎歊景雲，明堂舞幹羽。", "虎臣□激昂，□□□禦侮。腐儒著縫掖，何處議鄒魯。", "西上轘轅山，丘陵橫今古。和氣蒸萬物，臘月春靄吐。", "得為太平人，窮達不足數。他日遇封禪，著書繼三五。"]'),
('yuding-21','早發若峴驛望廬山','獨孤及','唐','御定全唐诗','yuding','','[]','雨罷山翠鮮，泠泠東風好。斷崖雲生處，是向峰頂道。',72,'御定全唐詩/json/246.json','["雨罷山翠鮮，泠泠東風好。斷崖雲生處，是向峰頂道。", "誰謂峰頂遠，跂予可瞻討。忘緣祛天機，脫屣恨不早。", "只恐歲雲暮，遂與空名老。心往跡未並，慚愧山上草。"]'),
('yuding-22','寒夜溪行舟中作','獨孤及','唐','御定全唐诗','yuding','','[]','日沉諸山昏，寂曆群動宿。孤舟獨不系，風水夜相逐。',96,'御定全唐詩/json/246.json','["日沉諸山昏，寂曆群動宿。孤舟獨不系，風水夜相逐。", "雲歸恒星白，霜下天地肅。月輪大如盤，金波入空穀。", "魏闕萬里道，羈念千慮束。倦飛思故巢，敢望桐與竹。", "沉吟登樓賦，中夜起三複。憂來無良方，歸候春酒熟。"]'),
('yuding-23','壬辰歲過舊居','獨孤及','唐','御定全唐诗','yuding','','[]','少年事遠遊，出入燕與秦。離居歲周天，猶作勞歌人。',96,'御定全唐詩/json/246.json','["少年事遠遊，出入燕與秦。離居歲周天，猶作勞歌人。", "負劍渡潁水，歸馬自知津。緣源到舊廬，攬涕尋荒榛。", "鄰里喜相勞，壺觴展殷勤。酒闌擊築語，及此離會因。", "丈夫隨世波，豈料百年身。今日負鄙願，多慚故山春。"]'),
('yuding-24','丙戌歲正月出洛陽書懷','獨孤及','唐','御定全唐诗','yuding','','[]','往歲衣褐見，受服金馬門。擬將忠與貞，來酬主人恩。',120,'御定全唐詩/json/246.json','["往歲衣褐見，受服金馬門。擬將忠與貞，來酬主人恩。", "天地暫雷雨，洪波生平原。窮鱗遂蹭蹬，夙昔事罕存。", "幸逢帝出震，授鉞清東藩。白日忽再中，萬方咸駿奔。", "王風從西來，春光滿乾坤。蟄蟲競飛動，餘亦辭籠樊。", "遭遇思自強，寵辱安足言。唯將四方志，回首謝故園。"]'),
('yuding-25','傷春懷歸','獨孤及','唐','御定全唐诗','yuding','','[]','誰謂鄉可望，望在天地涯。但有時命同，萬里共歲華。',96,'御定全唐詩/json/246.json','["誰謂鄉可望，望在天地涯。但有時命同，萬里共歲華。", "昨夜南山雨，殷雷坼萌芽。源桃不餘欺，先發秦人家。", "寂寂戶外掩，遲遲春日斜。源桃默無言，秦人獨長嗟。", "不惜中腸苦，但言會合賒。思歸吾誰訴，笑向南枝花。"]'),
('yuding-26','雜詩','獨孤及','唐','御定全唐诗','yuding','','[]','百花結成子，春物舍我去。流年惜不得，獨坐空閨暮。',48,'御定全唐詩/json/246.json','["百花結成子，春物舍我去。流年惜不得，獨坐空閨暮。", "心自有所待，甘為物華誤。未必千黃金，買得一人顧。"]'),
('yuding-27','山中春思','獨孤及','唐','御定全唐诗','yuding','','[]','獺祭川水大，人家春日長。獨謠晝不暮，搔首慚年芳。',108,'御定全唐詩/json/246.json','["獺祭川水大，人家春日長。獨謠晝不暮，搔首慚年芳。", "靡草知節換，含葩向新陽。不嫌三徑深，為我生池塘。", "亭午井灶閑，雀聲響空倉。花落沒屐齒，風動群木香。", "歸路雲水外，天涯杳茫茫。獨卷萬里心，深入山鳥行。", "芳景勿相迫，春愁未遽忘。"]'),
('yuding-0','雨後公超谷北原眺望寄高拾遺','獨孤及','唐','御定全唐诗','yuding','','[]','崖口雨足收，清光洗高天。虹蜺斂殘靄，山水含碧鮮。',48,'御定全唐詩/json/247.json','["崖口雨足收，清光洗高天。虹蜺斂殘靄，山水含碧鮮。", "遠空霞破露月輪，薄雲片片成魚鱗。五陵如薺渭如帶，"]'),
('yuding-1','自東都還濠州，奉酬王八諫議見贈','獨孤及','唐','御定全唐诗','yuding','','[]','關西仕時俱稚容，彪彪之鬢始相逢。天地變化縣城改，',88,'御定全唐詩/json/247.json','["關西仕時俱稚容，彪彪之鬢始相逢。天地變化縣城改，", "洛陽居守寄酂侯，君著貂冠參運籌。高閣連雲騎省夜，", "雲分雨散十五年，始得一笑樽酒前。未遑少留驟遠別，", "賴君贈我郢中曲，別後相思被管弦。"]'),
('yuding-2','官渡柳歌送李員外承恩往揚州覲省','獨孤及','唐','御定全唐诗','yuding','','[]','君不見官渡河兩岸，三月楊柳枝。千條萬條色，',21,'御定全唐詩/json/247.json','["君不見官渡河兩岸，三月楊柳枝。千條萬條色，"]'),
('yuding-3','東平蓬萊驛夜宴平盧楊判官醉後贈別姚太守置酒留宴','獨孤及','唐','御定全唐诗','yuding','','[]','驛樓漲海壖，秋月寒城邊。相見自不足，況逢主人賢。',70,'御定全唐詩/json/247.json','["驛樓漲海壖，秋月寒城邊。相見自不足，況逢主人賢。", "夜清酒濃人如玉，一鬥何啻直十千。木蘭為樽金為杯，", "固知別多相逢少，樂極哀至心嬋娟。少留莫辭醉，"]'),
('yuding-4','同岑郎中屯田韋員外花樹歌','獨孤及','唐','御定全唐诗','yuding','','[]','東風動地只花發，渭城桃李千樹雪。芳菲可愛不可留，',40,'御定全唐詩/json/247.json','["東風動地只花發，渭城桃李千樹雪。芳菲可愛不可留，", "君家自是成蹊處，況有庭花作主人。"]'),
('yuding-5','和李尚書畫射虎圖歌','獨孤及','唐','御定全唐诗','yuding','','[]','饑虎呀呀立當路，萬夫震恐百獸怒。彤弓金鏃當者誰，',72,'御定全唐詩/json/247.json','["饑虎呀呀立當路，萬夫震恐百獸怒。彤弓金鏃當者誰，", "時和年豐五兵已，白額未誅壯士恥。分銖遠邇懸彀中，", "殺氣滿堂觀者駭，颯若崖谷生長風。精微入神在毫末，"]'),
('yuding-6','和贈遠','獨孤及','唐','御定全唐诗','yuding','','[]','憶得去年春風至，中庭桃李映瑣窗。美人挾瑟對芳樹，',40,'御定全唐詩/json/247.json','["憶得去年春風至，中庭桃李映瑣窗。美人挾瑟對芳樹，", "借問離居恨深淺，只應獨有庭花知。"]'),
('yuding-7','和題藤架','獨孤及','唐','御定全唐诗','yuding','','[]','mH々葉成幄，璀璀花落架。花前離心苦，愁至無日夜。',49,'御定全唐詩/json/247.json','["mH々葉成幄，璀璀花落架。花前離心苦，愁至無日夜。", "人去藤花千里強，藤花無主為誰芳。相思曆亂何由盡，"]'),
('yuding-8','江上代書寄裴使君','獨孤及','唐','御定全唐诗','yuding','','[]','何地離念劇，江皋風雪時。艱難傷遠道，老大怯前期。',48,'御定全唐詩/json/247.json','["何地離念劇，江皋風雪時。艱難傷遠道，老大怯前期。", "疇昔行藏計，只將力命推。能令書信數，猶足緩相思。"]'),
('yuding-9','詣開悟禪師問心法次第寄韓郎中','獨孤及','唐','御定全唐诗','yuding','','[]','障深聞道晚，根鈍出塵難。濁劫相從慣，迷途自謂安。',48,'御定全唐詩/json/247.json','["障深聞道晚，根鈍出塵難。濁劫相從慣，迷途自謂安。", "得知身垢妄，始喜額珠完。欲識真如理，君嘗法味看。"]'),
('yuding-10','登後湖傷春懷京師故舊','獨孤及','唐','御定全唐诗','yuding','','[]','昨日看搖落，驚秋方怨咨。幾經開口笑，複及看花時。',48,'御定全唐詩/json/247.json','["昨日看搖落，驚秋方怨咨。幾經開口笑，複及看花時。", "世事空名束，生涯素發知。山山春草滿，何處不相思。"]'),
('yuding-11','暮春於山谷寺上方遇恩命加官賜服酬皇甫侍禦見賀之作','獨孤及','唐','御定全唐诗','yuding','','[]','天書到法堂，朽質被榮光。自笑無功德，殊恩謬激揚。',48,'御定全唐詩/json/247.json','["天書到法堂，朽質被榮光。自笑無功德，殊恩謬激揚。", "還登建禮署，猶忝會稽章。佳句慚相及，稱仁豈易當。"]'),
('yuding-12','答李滁州題庭前石竹花見寄','獨孤及','唐','御定全唐诗','yuding','','[]','殷疑曙霞染，巧類匣刀裁。不怕南風熱，能迎小暑開。',48,'御定全唐詩/json/247.json','["殷疑曙霞染，巧類匣刀裁。不怕南風熱，能迎小暑開。", "遊蜂憐色好，思婦感年催。覽贈添離恨，愁腸日幾回。"]'),
('yuding-13','得李滁州書以玉潭莊見托，因書春思，以詩代答','獨孤及','唐','御定全唐诗','yuding','','[]','春物行將老，懷君意詎堪。朱顏因酒強，白髮對花慚。',48,'御定全唐詩/json/247.json','["春物行將老，懷君意詎堪。朱顏因酒強，白髮對花慚。", "日日思瓊樹，書書話玉潭。知同百口累，曷日辦抽簪。"]'),
('yuding-14','答李滁州憶玉潭新居見寄','獨孤及','唐','御定全唐诗','yuding','','[]','從來招隱地，未有剖符人。山水能成癖，巢夷擬獨親。',48,'御定全唐詩/json/247.json','["從來招隱地，未有剖符人。山水能成癖，巢夷擬獨親。", "豬肝無足累，馬首敢辭勤。掃灑潭中月，他時望德鄰。"]'),
('yuding-15','將赴京答李紓贈別','獨孤及','唐','御定全唐诗','yuding','','[]','膠漆常投分，荊蠻各倦遊。帝鄉今獨往，溝水便分流。',48,'御定全唐詩/json/247.json','["膠漆常投分，荊蠻各倦遊。帝鄉今獨往，溝水便分流。", "甘作遠行客，深慚不系舟。思君帶將緩，豈直日三秋。"]'),
('yuding-16','和張大夫秋日有懷呈院中諸公','獨孤及','唐','御定全唐诗','yuding','','[]','至公無暇日，高閣閉秋天。肘印拘王事，籬花思長年。',48,'御定全唐詩/json/247.json','["至公無暇日，高閣閉秋天。肘印拘王事，籬花思長年。", "績成心不有，慮澹物猶牽。竊效泉魚躍，因聞郢曲妍。"]'),
('yuding-17','和大夫秋夜書情即事','獨孤及','唐','御定全唐诗','yuding','','[]','上略當分閫，高情善閉關。忘機群動息，無戰五兵閑。',48,'御定全唐詩/json/247.json','["上略當分閫，高情善閉關。忘機群動息，無戰五兵閑。", "鈴閣風傳漏，書窗月滿山。方知秋興作，非惜二毛斑。"]'),
('yuding-18','送虢州王錄事之任','獨孤及','唐','御定全唐诗','yuding','','[]','謂子文章達，當年羽翼高。一經俄白首，三命尚青袍。',48,'御定全唐詩/json/247.json','["謂子文章達，當年羽翼高。一經俄白首，三命尚青袍。", "未遇須藏器，安卑莫告勞。盤根倘相值，試用發硎刀。"]'),
('yuding-19','送長孫將軍拜歙州之任','獨孤及','唐','御定全唐诗','yuding','','[]','臨難敢橫行，遭時取盛名。五兵常典校，四十又專城。',48,'御定全唐詩/json/247.json','["臨難敢橫行，遭時取盛名。五兵常典校，四十又專城。", "浪逐樓船破，風從虎竹生。島夷今可料，系頸有長纓。"]'),
('yuding-20','送何員外使湖南','獨孤及','唐','御定全唐诗','yuding','','[]','夙昔皆黃綬，差池複瑣闈。上田無晚熟，逸翮果先飛。',48,'御定全唐詩/json/247.json','["夙昔皆黃綬，差池複瑣闈。上田無晚熟，逸翮果先飛。", "前路舟休系，故山雲不歸。王程倘未複，莫遣鯉書稀。"]'),
('yuding-21','送江陵全少卿赴府任','獨孤及','唐','御定全唐诗','yuding','','[]','塚司方慎選，劇縣得英髦。固是攀雲漸，何嗟趨府勞。',48,'御定全唐詩/json/247.json','["塚司方慎選，劇縣得英髦。固是攀雲漸，何嗟趨府勞。", "楚山迎驛路，漢水漲秋濤。鶱翥方茲始，看君六翮高。"]'),
('yuding-22','送虞秀才擢第歸長沙','獨孤及','唐','御定全唐诗','yuding','','[]','充賦名今遂，安親事不違。甲科文比玉，歸路錦為衣。',48,'御定全唐詩/json/247.json','["充賦名今遂，安親事不違。甲科文比玉，歸路錦為衣。", "海運同鶤化，風帆若鳥飛。知君到三徑，松菊有光輝。"]'),
('yuding-23','送陽翟張主簿之任','獨孤及','唐','御定全唐诗','yuding','','[]','舊聞陽翟縣，西接鳳高山。作吏同山隱，知君處劇閑。',48,'御定全唐詩/json/247.json','["舊聞陽翟縣，西接鳳高山。作吏同山隱，知君處劇閑。", "少年當效用，遠道豈辭艱。遲子揚名後，方期彩服還。"]'),
('yuding-24','送游員外赴淮西','獨孤及','唐','御定全唐诗','yuding','','[]','多君有奇略，投筆佐元戎。已佩郎官印，兼乘禦史驄。',48,'御定全唐詩/json/247.json','["多君有奇略，投筆佐元戎。已佩郎官印，兼乘禦史驄。", "使星隨驛騎，歸路有秋風。莫道無書劄，他年懷袖空。"]'),
('yuding-25','送馬鄭州','獨孤及','唐','御定全唐诗','yuding','','[]','使君朱兩轓，春日整東轅。芳草成皋路，青山涼水源。',48,'御定全唐詩/json/247.json','["使君朱兩轓，春日整東轅。芳草成皋路，青山涼水源。", "勉修循吏跡，以謝主人恩。當使仁風動，遙聽輿頌喧。"]'),
('yuding-26','送義烏韋明府','獨孤及','唐','御定全唐诗','yuding','','[]','妙年能致身，陳力複安親。不憚關山遠，寧辭簿領勤。',48,'御定全唐詩/json/247.json','["妙年能致身，陳力複安親。不憚關山遠，寧辭簿領勤。", "過江雲滿路，到縣海為鄰。每歎違心賞，吳門正早春。"]'),
('yuding-27','送陳王府張長史還京','獨孤及','唐','御定全唐诗','yuding','','[]','論齒弟兄列，為邦前後差。十年方一見，此別複何嗟。',48,'御定全唐詩/json/247.json','["論齒弟兄列，為邦前後差。十年方一見，此別複何嗟。", "極目故關道，傷心南浦花。少時相憶處，招手望行車。"]'),
('yuding-28','水西館泛舟送王員外','獨孤及','唐','御定全唐诗','yuding','','[]','單醪敢獻酢，曲沼荷經過。泛覽親魚鳥，夤緣涉芰荷。',48,'御定全唐詩/json/247.json','["單醪敢獻酢，曲沼荷經過。泛覽親魚鳥，夤緣涉芰荷。", "劇談增惠愛，美景借清和。明日汀洲草，依依奈別何。"]'),
('yuding-29','李卿東池夜宴得池字','獨孤及','唐','御定全唐诗','yuding','','[]','政成機不擾，心愜宴忘疲。去燭延高月，傾罍就小池。',48,'御定全唐詩/json/247.json','["政成機不擾，心愜宴忘疲。去燭延高月，傾罍就小池。", "舞盤回雪動，弦奏躍魚隨。自是山公興，誰令下士知。"]'),
('yuding-30','九月九日李蘇州東樓宴','獨孤及','唐','御定全唐诗','yuding','','[]','是菊花開日，當君乘興秋。風前孟嘉帽，月下庾公樓。',48,'御定全唐詩/json/247.json','["是菊花開日，當君乘興秋。風前孟嘉帽，月下庾公樓。", "酒解留征客，歌能破別愁。醉歸無以贈，只奉萬年酬。"]'),
('yuding-31','蕭文學山池宴集','獨孤及','唐','御定全唐诗','yuding','','[]','檀欒千畝綠，知是辟疆園。遠岫當庭戶，諸花覆水源。',48,'御定全唐詩/json/247.json','["檀欒千畝綠，知是辟疆園。遠岫當庭戶，諸花覆水源。", "主人邀盡醉，林鳥助狂言。莫問愁多少，今皆付酒樽。"]'),
('yuding-32','與韓侍禦同尋李七舍人不遇，題壁留贈','獨孤及','唐','御定全唐诗','yuding','','[]','三徑何寂寂，主人山上山。亭空簷月在，水落釣磯閑。',48,'御定全唐詩/json/247.json','["三徑何寂寂，主人山上山。亭空簷月在，水落釣磯閑。", "藥院雞犬靜，酒壚苔蘚班。知君少機事，當待暮雲還。"]'),
('yuding-33','喜辱韓十四郎中書兼封近詩示代書題贈','獨孤及','唐','御定全唐诗','yuding','','[]','各牽于役間遊遨，獨坐相思正郁陶。長跪讀書心暫緩，',40,'御定全唐詩/json/247.json','["各牽于役間遊遨，獨坐相思正郁陶。長跪讀書心暫緩，", "所歎在官成遠別，徒言岏水才容舠。"]'),
('yuding-34','早發龍沮館舟中寄東海徐司倉鄭司戶','獨孤及','唐','御定全唐诗','yuding','','[]','沙禽相呼曙色分，漁浦鳴桹十裏聞。正當秋風渡楚水，',40,'御定全唐詩/json/247.json','["沙禽相呼曙色分，漁浦鳴桹十裏聞。正當秋風渡楚水，", "停艫目送北歸翼，惜無瑤華持寄君。"]'),
('yuding-35','酬常郿縣見贈','獨孤及','唐','御定全唐诗','yuding','','[]','愛君修政若修身，鰥寡來歸乳雉馴。堂上五弦銷暇日，',40,'御定全唐詩/json/247.json','["愛君修政若修身，鰥寡來歸乳雉馴。堂上五弦銷暇日，", "辭後讀君懷縣作，定知三歲字猶新。"]'),
('yuding-36','登山谷寺上方答皇甫侍禦臥疾闕陪車騎之後','獨孤及','唐','御定全唐诗','yuding','','[]','梵宮香閣攀霞上，天柱孤峰指掌看。漢主馬蹤成蔓草，',40,'御定全唐詩/json/247.json','["梵宮香閣攀霞上，天柱孤峰指掌看。漢主馬蹤成蔓草，", "不見戴逵心莫展，賴將新贈比琅玕。"]'),
('yuding-37','答皇甫十六侍禦北歸留別作','獨孤及','唐','御定全唐诗','yuding','','[]','正當楚客傷春地，豈是騷人道別時。俱徇空名嗟欲老，',40,'御定全唐詩/json/247.json','["正當楚客傷春地，豈是騷人道別時。俱徇空名嗟欲老，", "明日相望隔雲水，解顏唯有袖中詩。"]'),
('yuding-38','答李滁州見寄','獨孤及','唐','御定全唐诗','yuding','','[]','相逢遽歎別離牽，三見江皋蕙草鮮。白髮俱生歡未再，',40,'御定全唐詩/json/247.json','["相逢遽歎別離牽，三見江皋蕙草鮮。白髮俱生歡未再，", "終日望君休汝騎，愧無堪報起予篇。"]'),
('yuding-39','得柳員外書封寄近詩書中兼報新主行營兵馬因代書戲答','獨孤及','唐','御定全唐诗','yuding','','[]','郎官作掾心非好，儒服臨戎政已聞。說劍嘗宗漆園吏。',64,'御定全唐詩/json/247.json','["郎官作掾心非好，儒服臨戎政已聞。說劍嘗宗漆園吏。", "戒嚴應笑棘門軍。遙知抵掌論皇道，時複吟詩向白雲。", "百越待君言即敘，相思不敢愴離群。"]'),
('yuding-40','同皇甫侍禦齋中春望見示之作','獨孤及','唐','御定全唐诗','yuding','','[]','望遠思歸心易傷，況將衰鬢偶年光。時攀芳樹愁花盡，',40,'御定全唐詩/json/247.json','["望遠思歸心易傷，況將衰鬢偶年光。時攀芳樹愁花盡，", "因君贈我江楓詠，春思如今未易量。"]'),
('yuding-41','傷春贈遠','獨孤及','唐','御定全唐诗','yuding','','[]','去水流年日並馳，年光客思兩相隨。咨嗟斑鬢今承弁，',40,'御定全唐詩/json/247.json','["去水流年日並馳，年光客思兩相隨。咨嗟斑鬢今承弁，", "憶君何啻同瓊樹，但向春風送別離。"]'),
('yuding-42','奉和中書常舍人晚秋集賢院即事寄贈徐薛二侍禦','獨孤及','唐','御定全唐诗','yuding','','[]','漢家金馬署，帝座紫微郎。圖籍淩群玉，歌詩冠柏梁。',144,'御定全唐詩/json/247.json','["漢家金馬署，帝座紫微郎。圖籍淩群玉，歌詩冠柏梁。", "陰陰萬年樹，肅肅五經堂。揮翰忘朝食，研精待夕陽。", "晴空露盤迥，秋月瑣窗涼。遠興生斑鬢，高情寄縹囊。", "葳蕤雙鸑鷟，夙昔並翱翔。汲塚同刊謬，蓬山共補亡。", "差池摧羽翮，流落限江湘。禁省一分袂，昊天三雨霜。", "石渠遺跡滿，水國暮雲長。早晚朝宣室，歸時道路光。"]'),
('yuding-43','江甯酬鄭縣劉少府兄贈別作','獨孤及','唐','御定全唐诗','yuding','','[]','往年脫縫掖，接武仕關西。結綬腰章並，趨階手板齊。',96,'御定全唐詩/json/247.json','["往年脫縫掖，接武仕關西。結綬腰章並，趨階手板齊。", "仙山不用買，朋酒日相攜。抵掌誇潭壑，忘情向組珪。", "事遷時既往，年長跡逾暌。何為青雲器，猶嗟濁水泥。", "役牽方遠別，道在或先迷。莫見良田晚，遭時亦杖藜。"]'),
('yuding-44','送李賓客荊南迎親','獨孤及','唐','御定全唐诗','yuding','','[]','宗室劉中壘，文場謝客兒。當為天北斗，曾使海西陲。',72,'御定全唐詩/json/247.json','["宗室劉中壘，文場謝客兒。當為天北斗，曾使海西陲。", "毛節精誠著，銅樓羽翼施。還申供帳別，言赴倚門期。", "恩渥沾行李，晨昏在路岐。君親兩報遂，不敢議傷離。"]'),
('yuding-45','題玉潭','獨孤及','唐','御定全唐诗','yuding','','[]','碧玉徒強名，冰壺難比德。唯當寂照心，可並奫淪色。',24,'御定全唐詩/json/247.json','["碧玉徒強名，冰壺難比德。唯當寂照心，可並奫淪色。"]'),
('yuding-46','海上懷華中舊游寄鄭縣劉少府造、渭南王少府崟','獨孤及','唐','御定全唐诗','yuding','','[]','涼風臺上三峰月，不夜城邊萬里沙。',32,'御定全唐詩/json/247.json','["涼風臺上三峰月，不夜城邊萬里沙。", "離別莫言關塞遠，夢魂長在子真家。"]'),
('yuding-47','和虞部韋郎中尋楊駙馬不遇','獨孤及','唐','御定全唐诗','yuding','','[]','金屋瓊台蕭史家，暮春三月渭州花。',32,'御定全唐詩/json/247.json','["金屋瓊台蕭史家，暮春三月渭州花。", "到君仙洞不相見，謂已吹簫乘早霞。"]'),
('yuding-48','李張惶甫閻權等數公並有送別之作見寄因答','獨孤及','唐','御定全唐诗','yuding','','[]','洞庭正波蘋葉衰，豈是秦吳遠別時。',32,'御定全唐詩/json/247.json','["洞庭正波蘋葉衰，豈是秦吳遠別時。", "謝君篋中綺端贈，何以報之長相思。"]'),
('yuding-49','將還越留別豫章諸公','獨孤及','唐','御定全唐诗','yuding','','[]','客鳥倦飛思舊林，裴徊猶戀眾花陰。',32,'御定全唐詩/json/247.json','["客鳥倦飛思舊林，裴徊猶戀眾花陰。", "他時相憶雙航葦，莫問吳江深不深。"]'),
('yuding-50','送別荊南張判官','獨孤及','唐','御定全唐诗','yuding','','[]','輶車駱馬往從誰，夢浦蘭台日更遲。',32,'御定全唐詩/json/247.json','["輶車駱馬往從誰，夢浦蘭台日更遲。", "欲識桃花最多處，前程問取武陵兒。"]'),
('yuding-51','陪王員外北樓宴待月','獨孤及','唐','御定全唐诗','yuding','','[]','勸酒論心夜不疲，含情有待問誰思。',32,'御定全唐詩/json/247.json','["勸酒論心夜不疲，含情有待問誰思。", "佇看晴月澄澄影，來照江樓酩酊時。"]'),
('yuding-52','垂花塢醉後戲題','獨孤及','唐','御定全唐诗','yuding','','[]','紫蔓青條拂酒壺，落花時與竹風俱。',32,'御定全唐詩/json/247.json','["紫蔓青條拂酒壺，落花時與竹風俱。", "歸時自負花前醉，笑向鰷魚問樂無。"]'),
('yuding-0','題劉相公三湘圖','郎士元','唐','御定全唐诗','yuding','','[]','昔別醉衡霍，邇來憶南州。今朝平津邸，兼得瀟湘遊。',96,'御定全唐詩/json/248.json','["昔別醉衡霍，邇來憶南州。今朝平津邸，兼得瀟湘遊。", "稍辨郢門樹，依然芳杜洲。微明三巴峽，咫尺萬里流。", "飛鳥不知倦，遠帆生暮愁。涔陽指天末，北渚空悠悠。", "枕上見漁父，坐中常狎鷗。誰言魏闕下，自有東山幽。"]'),
('yuding-1','長安逢故人','郎士元','唐','御定全唐诗','yuding','','[]','數年音信斷，不意在長安。馬上相逢久，人中欲認難。',48,'御定全唐詩/json/248.json','["數年音信斷，不意在長安。馬上相逢久，人中欲認難。", "一官今懶道，雙鬢竟羞看。莫問生涯事，只應持釣竿。"]'),
('yuding-2','送韋湛判官','郎士元','唐','御定全唐诗','yuding','','[]','高閣晴江上，重陽古戍間。聊因送歸客，更此望鄉山。',48,'御定全唐詩/json/248.json','["高閣晴江上，重陽古戍間。聊因送歸客，更此望鄉山。", "惜別心能醉，經秋鬢自斑。臨流興不盡，惆悵水雲間。"]'),
('yuding-3','送長沙韋明府','郎士元','唐','御定全唐诗','yuding','','[]','秋入長沙縣，蕭條旅宦心。煙波連桂水，官舍映楓林。',48,'御定全唐詩/json/248.json','["秋入長沙縣，蕭條旅宦心。煙波連桂水，官舍映楓林。", "雲日楚天暮，沙汀白露深。遙知訟堂裏，佳政在鳴琴。"]'),
('yuding-4','送孫願','郎士元','唐','御定全唐诗','yuding','','[]','悠然富春客，憶與暮潮歸。擢第人多羨，如君獨步稀。',48,'御定全唐詩/json/248.json','["悠然富春客，憶與暮潮歸。擢第人多羨，如君獨步稀。", "亂流江渡淺，遠色海山微。若訪新安路，嚴陵有釣磯。"]'),
('yuding-5','送林宗配雷州','郎士元','唐','御定全唐诗','yuding','','[]','昨日三峰尉，今朝萬里人。平生任孤直，豈是不防身。',48,'御定全唐詩/json/248.json','["昨日三峰尉，今朝萬里人。平生任孤直，豈是不防身。", "海霧多為瘴，山雷乍作鄰。遙憐北戶月，與子獨相親。"]'),
('yuding-6','送洪州李別駕之任','郎士元','唐','御定全唐诗','yuding','','[]','南去秋江遠，孤舟興自多。能將流水引，更入洞庭波。',48,'御定全唐詩/json/248.json','["南去秋江遠，孤舟興自多。能將流水引，更入洞庭波。", "夏口帆初上，潯陽雁正過。知音在霄漢，佐郡豈蹉跎。"]'),
('yuding-7','送楊中丞和蕃','郎士元','唐','御定全唐诗','yuding','','[]','錦車登隴日，邊草正萋萋。舊好尋君長，新愁聽鼓鼙。',48,'御定全唐詩/json/248.json','["錦車登隴日，邊草正萋萋。舊好尋君長，新愁聽鼓鼙。", "河源飛鳥外，雪嶺大荒西。漢壘今猶在，遙知路不迷。"]'),
('yuding-8','送李將軍赴定州','郎士元','唐','御定全唐诗','yuding','','[]','雙旌漢飛將，萬里授橫戈。春色臨邊盡，黃雲出塞多。',48,'御定全唐詩/json/248.json','["雙旌漢飛將，萬里授橫戈。春色臨邊盡，黃雲出塞多。", "鼓鼙悲絕漠，烽戍隔長河。莫斷陰山路，天驕已請和。"]'),
('yuding-9','關羽祠送高員外還荊州','郎士元','唐','御定全唐诗','yuding','','[]','將軍稟天姿，義勇冠今昔。走馬百戰場，一劍萬人敵。',72,'御定全唐詩/json/248.json','["將軍稟天姿，義勇冠今昔。走馬百戰場，一劍萬人敵。", "雖為感恩者，竟是思歸客。流落荊巫間，裴回故鄉隔。", "離筵對祠宇，灑酒暮天碧。去去勿複言，銜悲向陳跡。"]'),
('yuding-10','送張南史','郎士元','唐','御定全唐诗','yuding','','[]','雨餘深巷靜，獨酌送殘春。車馬雖嫌僻，鶯花不棄貧。',48,'御定全唐詩/json/248.json','["雨餘深巷靜，獨酌送殘春。車馬雖嫌僻，鶯花不棄貧。", "蟲絲粘戶網，鼠跡印床塵。借問山陽會，如今有幾人。"]'),
('yuding-11','送奚賈歸吳','郎士元','唐','御定全唐诗','yuding','','[]','東南富春渚，曾是謝公遊。今日奚生去，新安江正秋。',48,'御定全唐詩/json/248.json','["東南富春渚，曾是謝公遊。今日奚生去，新安江正秋。", "水清迎過客，霜葉落行舟。遙想赤亭下，聞猿應夜愁。"]'),
('yuding-12','送陸員外赴潮州','郎士元','唐','御定全唐诗','yuding','','[]','含香臺上客，剖竹海邊州。楚地多歸信，閩溪足亂流。',36,'御定全唐詩/json/248.json','["含香臺上客，剖竹海邊州。楚地多歸信，閩溪足亂流。", "今朝永嘉興，重見謝公遊。"]'),
('yuding-13','送裴補闕入河南幕','郎士元','唐','御定全唐诗','yuding','','[]','皎然青瑣客，何事動行軒。苦節酬知己，清吟去掖垣。',48,'御定全唐詩/json/248.json','["皎然青瑣客，何事動行軒。苦節酬知己，清吟去掖垣。", "秋城臨海樹，寒月上營門。鄒魯詩書國，應無鼙鼓喧。"]'),
('yuding-14','送韓司直路出延陵','郎士元','唐','御定全唐诗','yuding','','[]','游吳還適越，來往任風波。複送王孫去，其如春草何。',48,'御定全唐詩/json/248.json','["游吳還適越，來往任風波。複送王孫去，其如春草何。", "岸明殘雪在，潮滿夕陽多。季子留遺廟，停舟試一過。"]'),
('yuding-15','盩厔縣鄭礒宅送錢大','郎士元','唐','御定全唐诗','yuding','','[]','暮蟬不可聽，落葉豈堪聞。共是悲秋客，那知此路分。',48,'御定全唐詩/json/248.json','["暮蟬不可聽，落葉豈堪聞。共是悲秋客，那知此路分。", "荒城背流水，遠雁入寒雲。陶令門前菊，餘花可贈君。"]'),
('yuding-16','送元詵還丹陽別業','郎士元','唐','御定全唐诗','yuding','','[]','已知成傲吏，複見解朝衣。應向丹陽郭，秋山獨掩扉。',48,'御定全唐詩/json/248.json','["已知成傲吏，複見解朝衣。應向丹陽郭，秋山獨掩扉。", "草堂連古寺，江日動晴暉。一別滄洲遠，蘭橈幾歲歸。"]'),
('yuding-17','送崔侍禦往容州宣慰','郎士元','唐','御定全唐诗','yuding','','[]','秦原獨立望湘川，擊隼南飛向楚天。奉詔不言空問俗，',40,'御定全唐詩/json/248.json','["秦原獨立望湘川，擊隼南飛向楚天。奉詔不言空問俗，", "疇昔常聞陸賈說，故人今日豈徒然。"]'),
('yuding-18','朱方南郭留別皇甫冉','郎士元','唐','御定全唐诗','yuding','','[]','縈回楓葉岸，留滯木蘭橈。吳岫新經雨，江天正落潮。',48,'御定全唐詩/json/248.json','["縈回楓葉岸，留滯木蘭橈。吳岫新經雨，江天正落潮。", "故人勞見愛，行客自無憀。若問前程事，孤雲入剡遙。"]'),
('yuding-19','贈張五諲歸濠州別業','郎士元','唐','御定全唐诗','yuding','','[]','常知罷官意，果與世人疏。複此涼風起，仍聞濠上居。',48,'御定全唐詩/json/248.json','["常知罷官意，果與世人疏。複此涼風起，仍聞濠上居。", "故山期采菊，秋水憶觀魚。一去蓬蒿徑，羨君閑有餘。"]'),
('yuding-20','送王司馬赴潤州','郎士元','唐','御定全唐诗','yuding','','[]','暫屈文為吏，聊將祿代耕。金陵且不遠，山水複多名。',48,'御定全唐詩/json/248.json','["暫屈文為吏，聊將祿代耕。金陵且不遠，山水複多名。", "楚塞因高出，寒潮入夜生。離心逐春草，直到建康城。"]'),
('yuding-21','留盧秦卿','郎士元','唐','御定全唐诗','yuding','','[]','知有前期在，歡如此夜中。無將故人酒，不及古淳風。',24,'御定全唐詩/json/248.json','["知有前期在，歡如此夜中。無將故人酒，不及古淳風。"]'),
('yuding-22','贈強山人','郎士元','唐','御定全唐诗','yuding','','[]','或掉輕舟或杖藜，尋常適意釣前溪。',32,'御定全唐詩/json/248.json','["或掉輕舟或杖藜，尋常適意釣前溪。", "草堂竹徑在何處，落日孤煙寒渚西。"]'),
('yuding-23','贈韋司直','郎士元','唐','御定全唐诗','yuding','','[]','聞君感歎二毛初，舊友相依萬里餘。烽火有時驚暫定，',40,'御定全唐詩/json/248.json','["聞君感歎二毛初，舊友相依萬里餘。烽火有時驚暫定，", "昨日風光還入戶，登山臨水意何如。"]'),
('yuding-24','石城館酬王將軍','郎士元','唐','御定全唐诗','yuding','','[]','誰能繡衣客，肯駐木蘭舟。連雁沙邊至，孤城江上秋。',48,'御定全唐詩/json/248.json','["誰能繡衣客，肯駐木蘭舟。連雁沙邊至，孤城江上秋。", "歸帆背南浦，楚塞入西樓。何處看離思，滄波日夜流。"]'),
('yuding-25','酬王季友題半日村別業兼呈李明府','郎士元','唐','御定全唐诗','yuding','','[]','村映寒原日已斜，煙生密竹早歸鴉。長溪南路當群岫，',40,'御定全唐詩/json/248.json','["村映寒原日已斜，煙生密竹早歸鴉。長溪南路當群岫，", "欲待主人林上月，還思潘嶽縣中花。"]'),
('yuding-26','酬二十八秀才見寄','郎士元','唐','御定全唐诗','yuding','','[]','昨夜山月好，故人果相思。清光到枕上，嫋嫋涼風時。',36,'御定全唐詩/json/248.json','["昨夜山月好，故人果相思。清光到枕上，嫋嫋涼風時。", "永意能在我，惜無攜手期。"]'),
('yuding-27','冬夕寄青龍寺源公','郎士元','唐','御定全唐诗','yuding','','[]','斂屨入寒竹，安禪過漏聲。高松殘子落，深井凍痕生。',48,'御定全唐詩/json/248.json','["斂屨入寒竹，安禪過漏聲。高松殘子落，深井凍痕生。", "罷磬風枝動，懸燈雪屋明。何當招我宿，乘月上方行。"]'),
('yuding-28','塞下曲','郎士元','唐','御定全唐诗','yuding','','[]','寶刀塞下兒，身經百戰曾百勝，壯心竟未嫖姚知。',46,'御定全唐詩/json/248.json','["寶刀塞下兒，身經百戰曾百勝，壯心竟未嫖姚知。", "白草山頭日初沒，黃沙戍下悲歌發。蕭條夜靜邊風吹，"]'),
('yuding-29','柏林寺南望','郎士元','唐','御定全唐诗','yuding','','[]','溪上遙聞精舍鐘，泊舟微徑度深松。',32,'御定全唐詩/json/248.json','["溪上遙聞精舍鐘，泊舟微徑度深松。", "青山霽後雲猶在，畫出東南四五峰。"]'),
('yuding-30','宿杜判官江樓','郎士元','唐','御定全唐诗','yuding','','[]','適楚豈吾願，思歸秋向深。故人江樓月，永夜千里心。',48,'御定全唐詩/json/248.json','["適楚豈吾願，思歸秋向深。故人江樓月，永夜千里心。", "葉落覺鄉夢，鳥啼驚越吟。寥寥更何有，斷續空城砧。"]'),
('yuding-31','春宴王補闕城東別業','郎士元','唐','御定全唐诗','yuding','','[]','柳陌乍隨州勢轉，花源忽傍竹陰開。能將瀑水清人境，',40,'御定全唐詩/json/248.json','["柳陌乍隨州勢轉，花源忽傍竹陰開。能將瀑水清人境，", "地主同聲複同舍，留歡不畏夕陽催。"]'),
('yuding-32','郢城西樓吟','郎士元','唐','御定全唐诗','yuding','','[]','連山盡處水縈回，山上戍門臨水開。朱欄直下一百丈，',40,'御定全唐詩/json/248.json','["連山盡處水縈回，山上戍門臨水開。朱欄直下一百丈，", "沙洲楓岸無來客，草綠花紅山鳥鳴。"]'),
('yuding-33','聽鄰家吹笙','郎士元','唐','御定全唐诗','yuding','','[]','鳳吹聲如隔彩霞，不知牆外是誰家。',32,'御定全唐詩/json/248.json','["鳳吹聲如隔彩霞，不知牆外是誰家。", "重門深鎖無尋處，疑有碧桃千樹花。"]'),
('yuding-34','登丹陽北樓','郎士元','唐','御定全唐诗','yuding','','[]','寒皋那可望，旅望又初還。迢遞高樓上，蕭條曠野閑。',48,'御定全唐詩/json/248.json','["寒皋那可望，旅望又初還。迢遞高樓上，蕭條曠野閑。", "暮晴依遠水，秋興屬連山。浮客時相見，霜凋動翠顏。"]'),
('yuding-35','題精舍寺','郎士元','唐','御定全唐诗','yuding','','[]','石林精舍武溪東，夜扣禪關謁遠公。月在上方諸品靜，',40,'御定全唐詩/json/248.json','["石林精舍武溪東，夜扣禪關謁遠公。月在上方諸品靜，", "惟有雙峰最高頂，此心期與故人同。"]'),
('yuding-36','雙林寺謁傅大士','郎士元','唐','御定全唐诗','yuding','','[]','草露經前代，津梁及後人。此方今示滅，何國更分身。',48,'御定全唐詩/json/248.json','["草露經前代，津梁及後人。此方今示滅，何國更分身。", "月色空知夜，松陰不記春。猶憐下生日，應在一微塵。"]'),
('yuding-37','題尹真人祠','郎士元','唐','御定全唐诗','yuding','','[]','窅窅雲旗去不還，陰陰祠宇閉空山。',32,'御定全唐詩/json/248.json','["窅窅雲旗去不還，陰陰祠宇閉空山。", "我來始悟丹青妙，稽首如逢冰雪顏。"]'),
('yuding-38','山中即事','郎士元','唐','御定全唐诗','yuding','','[]','入穀多春興，乘舟棹碧潯。山雲昨夜雨，溪水曉來深。',24,'御定全唐詩/json/248.json','["入穀多春興，乘舟棹碧潯。山雲昨夜雨，溪水曉來深。"]'),
('yuding-39','湘夫人二首','郎士元','唐','御定全唐诗','yuding','','[]','蛾眉對湘水，遙哭蒼梧山。萬乘既已歿，孤舟誰忍還。',72,'御定全唐詩/json/248.json','["蛾眉對湘水，遙哭蒼梧山。萬乘既已歿，孤舟誰忍還。", "至今楚竹上，猶有淚痕斑。", "南有涔陽路，渺渺多新愁。桂酒神降時，回風江上秋。", "彩雲忽無處，碧水空安流。"]'),
('yuding-40','蓋少府新除江南尉問風俗','郎士元','唐','御定全唐诗','yuding','','[]','聞君作尉向江潭，吳越風煙到自諳。客路尋常隨竹影，',40,'御定全唐詩/json/248.json','["聞君作尉向江潭，吳越風煙到自諳。客路尋常隨竹影，", "惟有夜猿啼海樹，思鄉望國意難堪。"]'),
('yuding-41','春宴張舍人宅','郎士元','唐','御定全唐诗','yuding','','[]','懶尋芳草徑，來接侍臣筵。山色知殘雨，牆陰覺暮天。',48,'御定全唐詩/json/248.json','["懶尋芳草徑，來接侍臣筵。山色知殘雨，牆陰覺暮天。", "鶯啼漢宮柳，花隔杜陵煙。地與東城接，春光醉目前。"]'),
('yuding-42','寄李袁州桑落酒','郎士元','唐','御定全唐诗','yuding','','[]','色比瓊漿猶嫩，香同甘露仍春。',28,'御定全唐詩/json/248.json','["色比瓊漿猶嫩，香同甘露仍春。", "十千提攜一鬥，遠送瀟湘故人。"]'),
('yuding-43','贈萬生下第還吳）','郎士元','唐','御定全唐诗','yuding','','[]','直道多不偶，美才應息機。灞陵春欲暮，雲海獨言歸。',48,'御定全唐詩/json/248.json','["直道多不偶，美才應息機。灞陵春欲暮，雲海獨言歸。", "為客成白首，入門嗟布衣。蓴羹若可憶，慚出掩柴扉。"]'),
('yuding-44','送大德講時河東徐明府招','郎士元','唐','御定全唐诗','yuding','','[]','遠近作人天，王城指日邊。宰君迎說法，童子伴隨緣。',48,'御定全唐詩/json/248.json','["遠近作人天，王城指日邊。宰君迎說法，童子伴隨緣。", "到處花為雨，行時杖出泉。今宵松月下，開閣想安禪。"]'),
('yuding-45','赴無錫別靈一上人','郎士元','唐','御定全唐诗','yuding','','[]','高僧本姓竺，開士舊名林。一入春山裏，千峰不可尋。',48,'御定全唐詩/json/248.json','["高僧本姓竺，開士舊名林。一入春山裏，千峰不可尋。", "新年芳草遍，度日白雲深。欲問微官去，懸知訝此心。"]'),
('yuding-46','送粲上人兼寄梁鎮員外','郎士元','唐','御定全唐诗','yuding','','[]','季月還鄉獨未能，林行溪宿厭層冰。尺素欲傳三署客，',40,'御定全唐詩/json/248.json','["季月還鄉獨未能，林行溪宿厭層冰。尺素欲傳三署客，", "借問從來香積寺，何時攜手更同登。"]'),
('yuding-47','送韋逸人歸鐘山','郎士元','唐','御定全唐诗','yuding','','[]','逸人歸路遠，弟子出山迎。服藥顏猶駐，耽書癖已成。',48,'御定全唐詩/json/248.json','["逸人歸路遠，弟子出山迎。服藥顏猶駐，耽書癖已成。", "柴扉多歲月，藜杖見公卿。更作儒林傳，應須載姓名。"]'),
('yuding-48','登無錫北樓','郎士元','唐','御定全唐诗','yuding','','[]','秋興因危堞，歸心過遠山。風霜征雁早，江海旅人還。',48,'御定全唐詩/json/248.json','["秋興因危堞，歸心過遠山。風霜征雁早，江海旅人還。", "驛樹寒仍密，漁舟晚更閑。仲宣何所賦，只欲滯柴關。"]'),
('yuding-49','和王相公題中書叢竹寄上元相公','郎士元','唐','御定全唐诗','yuding','','[]','多時仙掖裏，色並翠琅玕。幽意含煙月，清陰庇蕙蘭。',48,'御定全唐詩/json/248.json','["多時仙掖裏，色並翠琅玕。幽意含煙月，清陰庇蕙蘭。", "枝繁宜露重，葉老愛天寒。竟日雙鸞止，孤吟為一看。"]'),
('yuding-50','酬蕭二十七侍禦初秋言懷','郎士元','唐','御定全唐诗','yuding','','[]','楚客秋多興，江林月漸生。細枝涼葉動，極浦早鴻聲。',48,'御定全唐詩/json/248.json','["楚客秋多興，江林月漸生。細枝涼葉動，極浦早鴻聲。", "勝賞睽前夕，新詩報遠情。曲高慚和者，惆悵閉寒城。"]'),
('yuding-51','奉和杜相公益昌路作','郎士元','唐','御定全唐诗','yuding','','[]','春半梁山正落花，台衡受律向天涯。南去猿聲傍雙節，',40,'御定全唐詩/json/248.json','["春半梁山正落花，台衡受律向天涯。南去猿聲傍雙節，", "已見廟謨能喻蜀，新文更喜報金華。"]'),
('yuding-52','賦得長洲苑送李惠','郎士元','唐','御定全唐诗','yuding','','[]','草深那可訪，地久阻相傳。散漫三秋雨，疏蕪萬里煙。',48,'御定全唐詩/json/248.json','["草深那可訪，地久阻相傳。散漫三秋雨，疏蕪萬里煙。", "都迷采蘭處，強記館娃年。客有游吳者，臨風思眇然。"]'),
('yuding-53','別房士清','郎士元','唐','御定全唐诗','yuding','','[]','世路還相見，偏堪淚滿衣。那能郢門別，獨向鄴城歸。',48,'御定全唐詩/json/248.json','["世路還相見，偏堪淚滿衣。那能郢門別，獨向鄴城歸。", "平楚看蓬轉，連山望鳥飛。蒼蒼歲陰暮，況複惜馳暉。"]'),
('yuding-54','送彭偃房由赴朝因寄錢大郎中李十七舍人','郎士元','唐','御定全唐诗','yuding','','[]','衰病已經年，西峰望楚天。風光欺鬢髮，秋色換山川。',48,'御定全唐詩/json/248.json','["衰病已經年，西峰望楚天。風光欺鬢髮，秋色換山川。", "寂寞浮雲外，支離漢水邊。平生故人遠，君去話潸然。"]'),
('yuding-55','送李遂之越','郎士元','唐','御定全唐诗','yuding','','[]','未習風波事，初為東越遊。露沾湖草晚，月照海山秋。',48,'御定全唐詩/json/248.json','["未習風波事，初為東越遊。露沾湖草晚，月照海山秋。", "梅市門何處，蘭亭水向流。西興待潮信，落日滿孤舟。"]'),
('yuding-56','送鄭正則徐州行營','郎士元','唐','御定全唐诗','yuding','','[]','從軍非隴頭，師在古徐州。氣勁三河卒，功全萬戶侯。',48,'御定全唐詩/json/248.json','["從軍非隴頭，師在古徐州。氣勁三河卒，功全萬戶侯。", "元戎閫外略，才子握中籌。莫聽關山曲，還生塞上愁。"]'),
('yuding-57','送錢拾遺歸兼寄劉校書','郎士元','唐','御定全唐诗','yuding','','[]','墟落歲陰暮，桑榆煙景昏。蟬聲靜空館，雨色隔秋原。',48,'御定全唐詩/json/248.json','["墟落歲陰暮，桑榆煙景昏。蟬聲靜空館，雨色隔秋原。", "歸客不可望，悠然林外村。終當報芸閣，攜手醉柴門。"]'),
('yuding-58','送郴縣裴明府之任兼充宣慰','郎士元','唐','御定全唐诗','yuding','','[]','白蘋楚水三湘遠，芳草秦城二月初。連雁北飛看欲盡，',40,'御定全唐詩/json/248.json','["白蘋楚水三湘遠，芳草秦城二月初。連雁北飛看欲盡，", "別後天涯何所寄，故交惟有袖中書。"]'),
('yuding-59','送李敖湖南書記','郎士元','唐','御定全唐诗','yuding','','[]','憐君才與阮家同，掌記能資亞相雄。入楚豈忘看淚竹，',40,'御定全唐詩/json/248.json','["憐君才與阮家同，掌記能資亞相雄。入楚豈忘看淚竹，", "莫信衡湘書不到，年年秋雁過巴東。"]'),
('yuding-60','送麹司直','郎士元','唐','御定全唐诗','yuding','','[]','曙雪蒼蒼兼曙雲，朔風煙雁不堪聞。',32,'御定全唐詩/json/248.json','["曙雪蒼蒼兼曙雲，朔風煙雁不堪聞。", "貧交此別無他贈，唯有青山遠送君。"]'),
('yuding-61','送別','郎士元','唐','御定全唐诗','yuding','','[]','穆陵關上秋雲起，安陸城邊遠行子。',32,'御定全唐詩/json/248.json','["穆陵關上秋雲起，安陸城邊遠行子。", "薄暮寒蟬三兩聲，回頭故鄉千萬里。"]'),
('yuding-62','咸陽西樓別竇審','郎士元','唐','御定全唐诗','yuding','','[]','西樓迥起寒原上，霽日遙分萬井間。小苑城隅連渭水，',40,'御定全唐詩/json/248.json','["西樓迥起寒原上，霽日遙分萬井間。小苑城隅連渭水，", "時命如今猶未偶，辭君擬欲拂衣還。"]'),
('yuding-63','聞蟬寄友人','郎士元','唐','御定全唐诗','yuding','','[]','昨日始聞鶯，今朝蟬又鳴。朱顏向華髮，定是幾年程。',48,'御定全唐詩/json/248.json','["昨日始聞鶯，今朝蟬又鳴。朱顏向華髮，定是幾年程。", "故國白雲遠，閒居青草生。因垂數行淚，書寄十年兄。"]'),
('yuding-64','送李騎曹之靈武甯侍','郎士元','唐','御定全唐诗','yuding','','[]','一歲一歸寧，涼天數騎行。河來當塞曲，山遠與沙平。',48,'御定全唐詩/json/248.json','["一歲一歸寧，涼天數騎行。河來當塞曲，山遠與沙平。", "縱獵旗風卷，聽笳帳月生。新鴻引寒色，回日滿京城。"]'),
('yuding-65','馮翊西樓','郎士元','唐','御定全唐诗','yuding','','[]','城上西樓倚暮天，樓中歸望正淒然。近郭亂山橫古渡，',40,'御定全唐詩/json/248.json','["城上西樓倚暮天，樓中歸望正淒然。近郭亂山橫古渡，", "陶令好文常對酒，相招一和白雲篇。"]'),
('yuding-66','郢城秋望','郎士元','唐','御定全唐诗','yuding','','[]','白首思歸歸不得，空山聞雁雁聲哀。',32,'御定全唐詩/json/248.json','["白首思歸歸不得，空山聞雁雁聲哀。", "高城落日望西北，又見秋風逐水來。"]'),
('yuding-67','夜泊湘江','郎士元','唐','御定全唐诗','yuding','','[]','湘山木落洞庭波，湘水連雲秋雁多。',32,'御定全唐詩/json/248.json','["湘山木落洞庭波，湘水連雲秋雁多。", "寂寞舟中誰借問，月明只自聽漁歌。"]'),
('yuding-68','留別常著','郎士元','唐','御定全唐诗','yuding','','[]','歲晏蒼郊蓬轉時，遊人相見說歸期。',32,'御定全唐詩/json/248.json','["歲晏蒼郊蓬轉時，遊人相見說歸期。", "宓君堂上能留客，明日還家應未遲。"]'),
('yuding-69','送張光歸吳','郎士元','唐','御定全唐诗','yuding','','[]','看取庭蕪白露新，勸君不用久風塵。',32,'御定全唐詩/json/248.json','["看取庭蕪白露新，勸君不用久風塵。", "秋來多見長安客，解愛鱸魚能幾人。"]'),
('yuding-70','聞吹楊葉者二首','郎士元','唐','御定全唐诗','yuding','','[]','妙吹楊葉動悲笳，胡馬迎風起恨賒。',64,'御定全唐詩/json/248.json','["妙吹楊葉動悲笳，胡馬迎風起恨賒。", "若是雁門寒月夜，此時應卷盡驚沙。", "天生一藝更無倫，寥亮幽音妙入神。", "吹向別離攀折處，當應合有斷腸人。"]'),
('yuding-0','潤州南郭留別','皇甫冉','唐','御定全唐诗','yuding','','[]','縈回楓葉岸，留滯木蘭橈。吳岫新經雨，江天正落潮。',48,'御定全唐詩/json/249.json','["縈回楓葉岸，留滯木蘭橈。吳岫新經雨，江天正落潮。", "故人勞見愛，行客自無聊。君問前程事，孤雲入剡遙。"]'),
('yuding-1','祭張公洞二首','皇甫冉','唐','御定全唐诗','yuding','','[]','堯心知稼穡，精意繞山川。風雨神祇應，笙鏞詔命傳。',96,'御定全唐詩/json/249.json','["堯心知稼穡，精意繞山川。風雨神祇應，笙鏞詔命傳。", "沐蘭祇掃地，酌桂佇靈仙。拂霧陳金策，焚香拜玉筵。", "雲開小有洞，日出大羅天。三鳥隨王母，雙童翊子先。", "何時種桃核，幾度看桑田。倏忽煙霞散，空岩騎吏旋。"]'),
('yuding-2','臨平道贈同舟人','皇甫冉','唐','御定全唐诗','yuding','','[]','遠山誰辨江南北，長路空隨樹淺深。',32,'御定全唐詩/json/249.json','["遠山誰辨江南北，長路空隨樹淺深。", "流蕩飄颻此何極，唯應行客共知心。"]'),
('yuding-3','巫山峽','皇甫冉','唐','御定全唐诗','yuding','','[]','巫峽見巴東，迢迢出半空。雲藏神女館，雨到楚王宮。',48,'御定全唐詩/json/249.json','["巫峽見巴東，迢迢出半空。雲藏神女館，雨到楚王宮。", "朝暮泉聲落，寒暄樹色同。清猿不可聽，偏在九秋中。"]'),
('yuding-4','長安路','皇甫冉','唐','御定全唐诗','yuding','','[]','長安九城路，戚裏五侯家。結束趨平樂，聯翩抵狹斜。',48,'御定全唐詩/json/249.json','["長安九城路，戚裏五侯家。結束趨平樂，聯翩抵狹斜。", "高樓臨遠水，複道出繁花。唯見相如宅，蓬門度歲華。"]'),
('yuding-5','送朱逸人','皇甫冉','唐','御定全唐诗','yuding','','[]','時人多不見，出入五湖間。寄酒全吾道，移家愛遠山。',48,'御定全唐詩/json/249.json','["時人多不見，出入五湖間。寄酒全吾道，移家愛遠山。", "更看秋草暮，欲共白雲還。雖在風塵裏，陶潛身自閑。"]'),
('yuding-6','西陵寄靈一上人','皇甫冉','唐','御定全唐诗','yuding','','[]','西陵遇風處，自古是通津。終日空江上，雲山若待人。',48,'御定全唐詩/json/249.json','["西陵遇風處，自古是通津。終日空江上，雲山若待人。", "汀洲寒事早，魚鳥興情新。回望山陰路，心中有所親。"]'),
('yuding-7','赴無錫寄別靈一淨虛二上人雲門所居','皇甫冉','唐','御定全唐诗','yuding','','[]','高僧本姓竺，開士舊名林。一入春山裏，千峰不可尋。',48,'御定全唐詩/json/249.json','["高僧本姓竺，開士舊名林。一入春山裏，千峰不可尋。", "新年芳草遍，終日白雲深。欲徇微官去，懸知訝此心。"]'),
('yuding-8','舟中送李八','皇甫冉','唐','御定全唐诗','yuding','','[]','詞客金門未有媒，游吳適越任舟回。',32,'御定全唐詩/json/249.json','["詞客金門未有媒，游吳適越任舟回。", "遠水迢迢分手去，天邊山色待人來。"]'),
('yuding-9','與張補闕王鍊師自徐方清路同舟南下於臺頭寺留別趙員外裴補闕同賦雜題一首','皇甫冉','唐','御定全唐诗','yuding','','[]','朝朝春事晚，泛泛行舟遠。淮海思無窮，悠揚煙景中。',84,'御定全唐詩/json/249.json','["朝朝春事晚，泛泛行舟遠。淮海思無窮，悠揚煙景中。", "幸將仙子去，複與故人同。高枕隨流水，輕帆任遠風。", "鐘聲野寺迥，草色故城空。送別高臺上，裴回共惆悵。", "懸知白日斜，定是猶相望。"]'),
('yuding-10','酬張二仲彝','皇甫冉','唐','御定全唐诗','yuding','','[]','吳洲見芳草，楚客動歸心。屈宋鄉山古，荊衡煙雨深。',72,'御定全唐詩/json/249.json','["吳洲見芳草，楚客動歸心。屈宋鄉山古，荊衡煙雨深。", "艱難十載別，羈旅四愁侵。澧月通沅水，湘雲入桂林。", "已看生白髮，當為乏黃金。江海時相見，唯聞梁甫吟。"]'),
('yuding-11','三月三日義興李明府後亭泛舟','皇甫冉','唐','御定全唐诗','yuding','','[]','江南煙景複如何，聞道新亭更可過。處處藝蘭春浦綠，',40,'御定全唐詩/json/249.json','["江南煙景複如何，聞道新亭更可過。處處藝蘭春浦綠，", "更使輕橈徐轉去，微風落日水增波。"]'),
('yuding-12','少室山韋煉師升仙歌','皇甫冉','唐','御定全唐诗','yuding','','[]','紅霞紫氣晝氳氳，絳節青幢迎少君。',32,'御定全唐詩/json/249.json','["紅霞紫氣晝氳氳，絳節青幢迎少君。", "忽從林下升天去，空使時人禮白雲。"]'),
('yuding-13','獨孤中丞筵陪餞韋君赴升州','皇甫冉','唐','御定全唐诗','yuding','','[]','中司龍節貴，上客虎符新。地控吳襟帶，才高漢縉紳。',48,'御定全唐詩/json/249.json','["中司龍節貴，上客虎符新。地控吳襟帶，才高漢縉紳。", "泛舟應度臘，入境便行春。處處歌來暮，長江建業人。"]'),
('yuding-14','送王緒剡中','皇甫冉','唐','御定全唐诗','yuding','','[]','不見關山去，何時到剡中。已聞成竹木，更道長兒童。',48,'御定全唐詩/json/249.json','["不見關山去，何時到剡中。已聞成竹木，更道長兒童。", "籬落雲常聚，村墟水自通。朝朝憶玄度，非是對清風。"]'),
('yuding-15','酬李郎中侍禦秋夜登福州城樓見寄','皇甫冉','唐','御定全唐诗','yuding','','[]','辛勤萬里道，蕭索九秋殘。月照閩中夜，天凝海上寒。',48,'御定全唐詩/json/249.json','["辛勤萬里道，蕭索九秋殘。月照閩中夜，天凝海上寒。", "王程無地遠，主意在人安。遙寄登樓作，空知行路難。"]'),
('yuding-16','同李司直諸公暑夜南餘館','皇甫冉','唐','御定全唐诗','yuding','','[]','何處多明月，津亭暑夜深。煙霞不可望，雲樹更沉沉。',48,'御定全唐詩/json/249.json','["何處多明月，津亭暑夜深。煙霞不可望，雲樹更沉沉。", "好是吳中隱，仍為洛下吟。微官朝複夕，牽強亦何心。"]'),
('yuding-17','贈普門上人','皇甫冉','唐','御定全唐诗','yuding','','[]','支公身欲老，長在沃州多。慧力堪傳教，禪功久伏魔。',48,'御定全唐詩/json/249.json','["支公身欲老，長在沃州多。慧力堪傳教，禪功久伏魔。", "山雲隨坐夏，江草伴頭陀。借問回心後，賢愚去幾何。"]'),
('yuding-18','與諸公同登無錫北樓','皇甫冉','唐','御定全唐诗','yuding','','[]','秋興因危堞，歸心過遠山。風霜征雁早，江海旅人閑。',48,'御定全唐詩/json/249.json','["秋興因危堞，歸心過遠山。風霜征雁早，江海旅人閑。", "驛樹寒仍密，漁舟晚自還。仲宣何所賦，只歎在荊蠻。"]'),
('yuding-19','同李蘇州傷美人','皇甫冉','唐','御定全唐诗','yuding','','[]','玉佩石榴裙，當年嫁使君。專房猶見寵，傾國眾皆聞。',48,'御定全唐詩/json/249.json','["玉佩石榴裙，當年嫁使君。專房猶見寵，傾國眾皆聞。", "歌舞常無對，幽明忽此分。陽臺千萬里，何處作朝雲。"]'),
('yuding-20','送李錄事赴饒州','皇甫冉','唐','御定全唐诗','yuding','','[]','北人南去雪紛紛，雁叫汀沙不可聞。積水長天隨遠客，',40,'御定全唐詩/json/249.json','["北人南去雪紛紛，雁叫汀沙不可聞。積水長天隨遠客，", "借問督郵才弱冠，府中年少不如君。"]'),
('yuding-21','同諸公有懷絕句','皇甫冉','唐','御定全唐诗','yuding','','[]','舊國迷江樹，他鄉近海門。移家南渡久，童稚解方言。',24,'御定全唐詩/json/249.json','["舊國迷江樹，他鄉近海門。移家南渡久，童稚解方言。"]'),
('yuding-22','題魏仲光淮山所居','皇甫冉','唐','御定全唐诗','yuding','','[]','人群不相見，乃在白雲間。問我將何適，羨君今獨閑。',48,'御定全唐詩/json/249.json','["人群不相見，乃在白雲間。問我將何適，羨君今獨閑。", "朝朝汲淮水，暮暮上龜山。幸已安貧定，當從鬢髮斑。"]'),
('yuding-23','送鄭判官赴徐州','皇甫冉','唐','御定全唐诗','yuding','','[]','從軍非隴頭，師在古徐州。氣勁三河卒，功多萬里侯。',48,'御定全唐詩/json/249.json','["從軍非隴頭，師在古徐州。氣勁三河卒，功多萬里侯。", "元戎閫外令，才子幄中籌。莫聽關山曲，還生出塞愁。"]'),
('yuding-24','送顧萇往新安','皇甫冉','唐','御定全唐诗','yuding','','[]','由來山水客，複道向新安。半是乘潮便，全非行路難。',48,'御定全唐詩/json/249.json','["由來山水客，複道向新安。半是乘潮便，全非行路難。", "晨裝林月在，野飯浦沙寒。嚴子千年後，何人釣舊灘。"]'),
('yuding-25','秋夜有懷高三十五兼呈空和尚','皇甫冉','唐','御定全唐诗','yuding','','[]','晚節聞君趨道深，結茅栽樹近東林。大師幾度曾摩頂，',40,'御定全唐詩/json/249.json','["晚節聞君趨道深，結茅栽樹近東林。大師幾度曾摩頂，", "不見支公與玄度，相思擁膝坐長吟。"]'),
('yuding-26','途中送權三兄弟','皇甫冉','唐','御定全唐诗','yuding','','[]','淮海風濤起，江關憂思長。同悲鵲繞樹，獨作雁隨陽。',48,'御定全唐詩/json/249.json','["淮海風濤起，江關憂思長。同悲鵲繞樹，獨作雁隨陽。", "山晚雲初雪，汀寒月照霜。由來濯纓處，漁父愛滄浪。"]'),
('yuding-27','送裴闡','皇甫冉','唐','御定全唐诗','yuding','','[]','道向毗陵豈是歸，客中誰與換春衣。',32,'御定全唐詩/json/249.json','["道向毗陵豈是歸，客中誰與換春衣。", "今夜孤舟行近遠，子荊零雨正霏霏。"]'),
('yuding-28','雜言湖山歌送許鳴謙','皇甫冉','唐','御定全唐诗','yuding','','[]','湖中之山兮波上青，桂颯颯兮雨冥冥。君歸兮春早，',76,'御定全唐詩/json/249.json','["湖中之山兮波上青，桂颯颯兮雨冥冥。君歸兮春早，", "東嶺西峰兮同白雲，雞鳴犬吠兮時相聞。", "幽芳媚景兮當嘉月，踐石捫蘿兮恣超忽。", "空山寂寂兮潁陽人，旦夕孤雲隨一身。"]'),
('yuding-29','雜言迎神詞二首：迎神','皇甫冉','唐','御定全唐诗','yuding','','[]','啟庭戶，列芳鮮；目眇眇，心綿綿，因風托雨降瓊筵。',40,'御定全唐詩/json/249.json','["啟庭戶，列芳鮮；目眇眇，心綿綿，因風托雨降瓊筵。", "紛下拜，屢加籩，人心望歲祈豐年。"]'),
('yuding-30','雜言迎神詞二首：送神','皇甫冉','唐','御定全唐诗','yuding','','[]','露沾衣，月隱壁；氣淒淒，人寂寂，風回雨度虛瑤席。',40,'御定全唐詩/json/249.json','["露沾衣，月隱壁；氣淒淒，人寂寂，風回雨度虛瑤席。", "來無聲，去無跡，神心降和福遠客。"]'),
('yuding-31','屏風上各賦一物得攜琴客','皇甫冉','唐','御定全唐诗','yuding','','[]','不是向空林，應當就磐石。白雲知隱處，芳草迷行跡。',36,'御定全唐詩/json/249.json','["不是向空林，應當就磐石。白雲知隱處，芳草迷行跡。", "如何祗役心，見爾攜琴客。"]'),
('yuding-32','江草歌送盧判官','皇甫冉','唐','御定全唐诗','yuding','','[]','江皋兮春早，江上兮芳草。雜蘼蕪兮杜蘅，',65,'御定全唐詩/json/249.json','["江皋兮春早，江上兮芳草。雜蘼蕪兮杜蘅，", "目眇眇兮增愁，步遲遲兮堪搴。澧之浦兮湘之濱，", "新月能分裛露時，夕陽照見連天處。問君行邁將何之，"]'),
('yuding-33','題畫帳二首：山水','皇甫冉','唐','御定全唐诗','yuding','','[]','桂水饒楓杉，荊南足煙雨。猶疑黛色中，複是雒陽岨。',24,'御定全唐詩/json/249.json','["桂水饒楓杉，荊南足煙雨。猶疑黛色中，複是雒陽岨。"]'),
('yuding-34','題畫帳二首：遠帆','皇甫冉','唐','御定全唐诗','yuding','','[]','朝見巴江客，暮見巴江客。雲帆儻暫停，中路陽臺夕。',24,'御定全唐詩/json/249.json','["朝見巴江客，暮見巴江客。雲帆儻暫停，中路陽臺夕。"]'),
('yuding-35','落第後東遊留別','皇甫冉','唐','御定全唐诗','yuding','','[]','功成方自得，何事學幹求。果以浮名誤，深貽達士羞。',48,'御定全唐詩/json/249.json','["功成方自得，何事學幹求。果以浮名誤，深貽達士羞。", "九江連漲海，萬里任虛舟。歲晚同懷客，相思波上鷗。"]'),
('yuding-36','雜言月洲歌送趙冽還襄陽','皇甫冉','唐','御定全唐诗','yuding','','[]','漢之廣矣中有洲，洲如月兮水環流。流聒聒兮湍與瀨，',70,'御定全唐詩/json/249.json','["漢之廣矣中有洲，洲如月兮水環流。流聒聒兮湍與瀨，", "萬山飛雨一川來，巴客歸船傍洲去。歸人不可遲，", "家住洲頭定近遠，朝泛輕橈暮當返。不能隨爾臥芳洲，"]'),
('yuding-37','寄劉八山中','皇甫冉','唐','御定全唐诗','yuding','','[]','東皋若近遠，苦雨隔還期。閏歲風霜晚，山田收穫遲。',48,'御定全唐詩/json/249.json','["東皋若近遠，苦雨隔還期。閏歲風霜晚，山田收穫遲。", "茅簷燕去後，樵路菊黃時。平子遊都久，知君坐見嗤。"]'),
('yuding-38','答張諲、劉方平兼呈賀蘭廣','皇甫冉','唐','御定全唐诗','yuding','','[]','野性難馴狎，荒郊自閉門。心閑同海鳥，日夕戀山村。',72,'御定全唐詩/json/249.json','["野性難馴狎，荒郊自閉門。心閑同海鳥，日夕戀山村。", "屢枉瓊瑤贈，如今道術存。遠峰時振策，春雨耐香源。", "複有故人在，甯聞盧鵲喧。青青草色綠，終是待王孫。"]'),
('yuding-39','灃水送鄭豐鄠縣讀書','皇甫冉','唐','御定全唐诗','yuding','','[]','麥秋中夏涼風起，送君西郊及灃水。孤煙遠樹動離心，',40,'御定全唐詩/json/249.json','["麥秋中夏涼風起，送君西郊及灃水。孤煙遠樹動離心，", "上古全經皆在口，秦人如見濟南生。"]'),
('yuding-40','九日寄鄭豐','皇甫冉','唐','御定全唐诗','yuding','','[]','重陽秋已晚，千里信仍稀。何處登高望，知君正憶歸。',48,'御定全唐詩/json/249.json','["重陽秋已晚，千里信仍稀。何處登高望，知君正憶歸。", "還當采時菊，定未授寒衣。欲識離居恨，郊園正掩扉。"]'),
('yuding-41','酬包評事壁畫山水見寄','皇甫冉','唐','御定全唐诗','yuding','','[]','一官知所傲，本意在雲泉。濡翰生新興，群峰忽眼前。',84,'御定全唐詩/json/249.json','["一官知所傲，本意在雲泉。濡翰生新興，群峰忽眼前。", "黛中分遠近，筆下起風煙。岩翠深樵路，湖光出釣船。", "寒侵赤城頂，日照武陵川。若覽名山志，仍聞招隱篇。", "遂令江海客，惆悵憶閒田。"]'),
('yuding-42','渡汝水向太和山','皇甫冉','唐','御定全唐诗','yuding','','[]','落日事搴陟，西南投一峰。誠知秋水淺，但怯無人蹤。',24,'御定全唐詩/json/249.json','["落日事搴陟，西南投一峰。誠知秋水淺，但怯無人蹤。"]'),
('yuding-43','秋怨','皇甫冉','唐','御定全唐诗','yuding','','[]','長信多秋氣，昭陽借月華。那堪閉永巷，聞道選良家。',24,'御定全唐詩/json/249.json','["長信多秋氣，昭陽借月華。那堪閉永巷，聞道選良家。"]'),
('yuding-44','贈鄭山人','皇甫冉','唐','御定全唐诗','yuding','','[]','白首滄洲客，陶然得此生。龐公采藥去，萊氏與妻行。',120,'御定全唐詩/json/249.json','["白首滄洲客，陶然得此生。龐公采藥去，萊氏與妻行。", "乍見還州裏，全非隱姓名。枉帆臨海嶠，貰酒秣陵城。", "伐木吳山曉，持竿越水清。家人恣貧賤，物外任衰榮。", "忽爾辭林壑，高歌至上京。避喧心已慣，念遠夢頻成。", "石路寒花發，江田臘雪明。玄纁倘有命，何以遂躬耕。"]'),
('yuding-45','劉方平西齋對雪','皇甫冉','唐','御定全唐诗','yuding','','[]','對酒閑齋晚，開軒臘雪時。花飄疑節候，色淨潤簾帷。',48,'御定全唐詩/json/249.json','["對酒閑齋晚，開軒臘雪時。花飄疑節候，色淨潤簾帷。", "委樹寒枝弱，縈空去雁遲。自然堪訪戴，無複四愁詩。"]'),
('yuding-46','福先寺尋湛然寺主不見','皇甫冉','唐','御定全唐诗','yuding','','[]','寂然空佇立，往往報疏鐘。高館誰留客，東南二室峰。',48,'御定全唐詩/json/249.json','["寂然空佇立，往往報疏鐘。高館誰留客，東南二室峰。", "川原通霽色，田野變春容。惆悵層城暮，猶言歸路逢。"]'),
('yuding-47','河南鄭少尹城南亭送鄭判官還河東','皇甫冉','唐','御定全唐诗','yuding','','[]','使臣懷餞席，亞尹有前溪。客是仙舟裏，途從御苑西。',72,'御定全唐詩/json/249.json','["使臣懷餞席，亞尹有前溪。客是仙舟裏，途從御苑西。", "泉聲喧暗竹，草色引長堤。故絳青山在，新田綠樹齊。", "天秋聞別鵠，關曉待鳴雞。應歎沈冥者，年年津路迷。"]'),
('yuding-48','登玄元廟','皇甫冉','唐','御定全唐诗','yuding','','[]','古廟川原迥，重門禁籞連。海童紛翠蓋，羽客事瓊筵。',72,'御定全唐詩/json/249.json','["古廟川原迥，重門禁籞連。海童紛翠蓋，羽客事瓊筵。", "禦路分疏柳，離宮出苑田。興新無向背，望久辨山川。", "物外將遺老，區中誓絕緣。函關若遠近，紫氣獨依然。"]'),
('yuding-49','冬夜集賦得寒漏','皇甫冉','唐','御定全唐诗','yuding','','[]','清冬洛陽客，寒漏建章台。出禁因風徹，縈窗共月來。',60,'御定全唐詩/json/249.json','["清冬洛陽客，寒漏建章台。出禁因風徹，縈窗共月來。", "偏將殘瀨雜，乍與遠鴻哀。遙夜重城警，流年滴水催。", "閑齋堪坐聽，況有故人杯。"]'),
('yuding-50','玄元觀送李源李風還奉先華陰','皇甫冉','唐','御定全唐诗','yuding','','[]','此去那知道路遙，寒原紫府上迢迢。莫辭別酒和瓊液，',40,'御定全唐詩/json/249.json','["此去那知道路遙，寒原紫府上迢迢。莫辭別酒和瓊液，", "華山秦塞長相憶，無使音塵頓寂寥。"]'),
('yuding-51','劉方平壁畫山','皇甫冉','唐','御定全唐诗','yuding','','[]','墨妙無前，性生筆先。回溪已失，遠嶂猶連。',40,'御定全唐詩/json/249.json','["墨妙無前，性生筆先。回溪已失，遠嶂猶連。", "側徑樵客，長林野煙。青峰之外，何處雲天。"]'),
('yuding-52','登山歌','皇甫冉','唐','御定全唐诗','yuding','','[]','青山前，青山後，登高望兩處，兩處今何有。',32,'御定全唐詩/json/249.json','["青山前，青山後，登高望兩處，兩處今何有。", "煙景滿川原，離人堪白首。"]'),
('yuding-53','和鄭少尹祭中嶽寺北訪蕭居士越上方','皇甫冉','唐','御定全唐诗','yuding','','[]','肅寺祠靈境，尋真到隱居。夤緣幽谷遠，蕭散白雲餘。',96,'御定全唐詩/json/249.json','["肅寺祠靈境，尋真到隱居。夤緣幽谷遠，蕭散白雲餘。", "晚節持僧律，他年著道書。海邊曾狎鳥，濠上正觀魚。", "寂靜求無相，淳和睹太初。一峰綿歲月，萬性任盈虛。", "籬隔溪鐘度，窗臨澗木疏。謝公懷舊壑，回駕複何如。"]'),
('yuding-54','秋夜寄所思','皇甫冉','唐','御定全唐诗','yuding','','[]','寂寞坐遙夜，清風何處來。天高散騎省，月冷建章台。',48,'御定全唐詩/json/249.json','["寂寞坐遙夜，清風何處來。天高散騎省，月冷建章台。", "鄰笛哀聲急，城砧朔氣催。芙蓉已委絕，誰複可為媒。"]'),
('yuding-55','賦得郢路悲猿','皇甫冉','唐','御定全唐诗','yuding','','[]','悲猿何處發，郢路第三聲。遠客知秋暮，空山益夜清。',48,'御定全唐詩/json/249.json','["悲猿何處發，郢路第三聲。遠客知秋暮，空山益夜清。", "啾啾深眾木，噭噭入孤城。坐覺盈心耳，翛然適楚情。"]'),
('yuding-56','雜言無錫惠山寺流泉歌','皇甫冉','唐','御定全唐诗','yuding','','[]','寺有泉兮泉在山，鏘金鳴玉兮長潺潺。作潭鏡兮澄寺內，',113,'御定全唐詩/json/249.json','["寺有泉兮泉在山，鏘金鳴玉兮長潺潺。作潭鏡兮澄寺內，", "處處縈回石磴喧，朝朝盥漱山僧老。僧自老，松自新。", "流活活，無冬春。任疏鑿兮與汲引，若有意兮山中人。", "偏依佛界通仙境，明滅玲瓏媚林嶺。宛如太室臨九潭，", "且複遲回猶未去，此心只為靈泉留。"]'),
('yuding-57','清明日青龍寺上方賦得多字','皇甫冉','唐','御定全唐诗','yuding','','[]','上方偏可適，季月況堪過。遠近水聲至，東西山色多。',48,'御定全唐詩/json/249.json','["上方偏可適，季月況堪過。遠近水聲至，東西山色多。", "夕陽留徑草，新葉變庭柯。已度清明節，春秋如客何。"]'),
('yuding-58','與張諲宿劉八城東莊','皇甫冉','唐','御定全唐诗','yuding','','[]','人閑當歲暮，田野尚逢迎。萊子多嘉慶，陶公得此生。',48,'御定全唐詩/json/249.json','["人閑當歲暮，田野尚逢迎。萊子多嘉慶，陶公得此生。", "寒蕪連古渡，雲樹近嚴城。雞黍無辭薄，貧交但貴情。"]'),
('yuding-59','寄劉方平','皇甫冉','唐','御定全唐诗','yuding','','[]','坐憶山中人，窮棲事南畝。煙霞相親外，墟落今何有。',72,'御定全唐詩/json/249.json','["坐憶山中人，窮棲事南畝。煙霞相親外，墟落今何有。", "潘郎作賦年，陶令辭官後。達生遺自適，良願固無負。", "田取潁水流，樹入陽城口。歲暮憂思盈，離居不堪久。"]'),
('yuding-60','曾東遊以詩寄之','皇甫冉','唐','御定全唐诗','yuding','','[]','出郭離言多，回車始知遠。寂然層城暮，更念前山轉。',216,'御定全唐詩/json/249.json','["出郭離言多，回車始知遠。寂然層城暮，更念前山轉。", "總轡越成皋，浮舟背梁苑。朝朝勞延首，往往若在眼。", "落日孤雲還，邊愁迷楚關。如何漵花發，複對遊子顏。", "古寺杉栝裏，連檣洲渚間。煙生海西岸，雲見吳南山。", "驚風掃蘆荻，翻浪連天白。正是揚帆時，偏逢江上客。", "由來許佳句，況乃愜所適。嵯峨天姥峰，翠色春更碧。", "氣淒湖上雨，月淨剡中夕。釣艇或相逢，江蘺又堪摘。", "迢迢始寧墅，蕪沒謝公宅。朱槿列摧墉，蒼苔遍幽石。", "顧予任疏懶，期爾振羽翮。滄洲未可行，須售金門策。"]'),
('yuding-61','適荊州途次南陽贈何明府','皇甫冉','唐','御定全唐诗','yuding','','[]','千里獨遊日，有懷誰與同。言過細陽令，一遇朗陵公。',96,'御定全唐詩/json/249.json','["千里獨遊日，有懷誰與同。言過細陽令，一遇朗陵公。", "清節邁多士，斯文傳古風。閭閻知俗變，原野識年豐。", "吾道方在此，前程殊未窮。江天經峴北，客思滿巴東。", "夢渚夕愁遠，山丘晴望通。應嗟出處異，流蕩楚雲中。"]'),
('yuding-62','秋夜戲題劉方平壁','皇甫冉','唐','御定全唐诗','yuding','','[]','鴻悲月白時將謝，正可招尋惜遙夜。',32,'御定全唐詩/json/249.json','["鴻悲月白時將謝，正可招尋惜遙夜。", "翠帳蘭房曲且深，寧知戶外清霜下。"]'),
('yuding-63','問正上人疾','皇甫冉','唐','御定全唐诗','yuding','','[]','醫王猶有疾，妙理競難窮。餌藥應隨病，觀身轉悟空。',48,'御定全唐詩/json/249.json','["醫王猶有疾，妙理競難窮。餌藥應隨病，觀身轉悟空。", "地閑花欲雨，窗冷竹生風。幾日東林去，門人待遠公。"]'),
('yuding-64','山中五詠：門柳','皇甫冉','唐','御定全唐诗','yuding','','[]','接影武昌城，分行漢南道。何事閑門外，空對青山老。',24,'御定全唐詩/json/249.json','["接影武昌城，分行漢南道。何事閑門外，空對青山老。"]'),
('yuding-65','山中五詠：遠山','皇甫冉','唐','御定全唐诗','yuding','','[]','少室盡西峰，鳴皋隱南面。柴門縱複關，終日窗中見。',24,'御定全唐詩/json/249.json','["少室盡西峰，鳴皋隱南面。柴門縱複關，終日窗中見。"]'),
('yuding-66','山中五詠：南澗','皇甫冉','唐','御定全唐诗','yuding','','[]','上路各乘軒，高明盡鳴玉。甯知澗下人，自愛輕波淥。',24,'御定全唐詩/json/249.json','["上路各乘軒，高明盡鳴玉。甯知澗下人，自愛輕波淥。"]'),
('yuding-67','山中五詠：春早','皇甫冉','唐','御定全唐诗','yuding','','[]','草遍潁陽山，花開武陵水。春色既已同，人心亦相似。',24,'御定全唐詩/json/249.json','["草遍潁陽山，花開武陵水。春色既已同，人心亦相似。"]'),
('yuding-68','山中五詠：山館','皇甫冉','唐','御定全唐诗','yuding','','[]','山館長寂寂，閑雲朝夕來。空庭複何有，落日照青苔。',24,'御定全唐詩/json/249.json','["山館長寂寂，閑雲朝夕來。空庭複何有，落日照青苔。"]'),
('yuding-69','送竇十九叔向赴京','皇甫冉','唐','御定全唐诗','yuding','','[]','冰結楊柳津，從吳去入秦。徒雲還上國，誰為作中人。',48,'御定全唐詩/json/249.json','["冰結楊柳津，從吳去入秦。徒雲還上國，誰為作中人。", "驛樹同霜霰，漁舟伴苦辛。相如求一謁，詞賦遠隨身。"]'),
('yuding-70','登石城戍望海寄諸暨嚴少府','皇甫冉','唐','御定全唐诗','yuding','','[]','平明登古戍，徙倚待寒潮。江海方回合，雲林自寂寥。',48,'御定全唐詩/json/249.json','["平明登古戍，徙倚待寒潮。江海方回合，雲林自寂寥。", "詎能知遠近，徒見蕩煙霄。即此滄洲路，嗟君久折腰。"]'),
('yuding-71','和樊潤州秋日登城樓','皇甫冉','唐','御定全唐诗','yuding','','[]','露冕臨平楚，寒城帶早霜。時同借河內，人是臥淮陽。',48,'御定全唐詩/json/249.json','["露冕臨平楚，寒城帶早霜。時同借河內，人是臥淮陽。", "積水澄天塹，連山入帝鄉。因高欲見下，非是愛秋光。"]'),
('yuding-72','寄江東李判官','皇甫冉','唐','御定全唐诗','yuding','','[]','遠懷不可道，曆稔倦離憂。洛下聞新雁，江南想暮秋。',96,'御定全唐詩/json/249.json','["遠懷不可道，曆稔倦離憂。洛下聞新雁，江南想暮秋。", "澄清佐八使，綱紀案諸侯。地識吳平久，才當晉用求。", "時賢幾殂謝，摛藻繼風流。更有西陵作，還成北固遊。", "歸途限尺牘，王事在扁舟。山色臨湖盡，猿聲入夢愁。"]'),
('yuding-73','送蔣評事往福州','皇甫冉','唐','御定全唐诗','yuding','','[]','江上春常早，閩中客去稀。登山怨迢遞，臨水惜芳菲。',48,'御定全唐詩/json/249.json','["江上春常早，閩中客去稀。登山怨迢遞，臨水惜芳菲。", "煙樹何時盡，風帆幾日歸。還看複命處，盛府有光輝。"]'),
('yuding-74','送從弟豫貶遠州','皇甫冉','唐','御定全唐诗','yuding','','[]','何事成遷客，思歸不見鄉。游吳經萬里，吊屈過三湘。',72,'御定全唐詩/json/249.json','["何事成遷客，思歸不見鄉。游吳經萬里，吊屈過三湘。", "水與荊巫接，山通鄢郢長。名嗟黃綬系，才是白眉良。", "獨結南枝恨，應思北雁行。憂來沽楚酒，玄鬢莫凝霜。"]'),
('yuding-75','送錢唐路少府赴制舉','皇甫冉','唐','御定全唐诗','yuding','','[]','公車待詔赴長安，客裏新正阻舊歡。遲日未能銷野雪，',40,'御定全唐詩/json/249.json','["公車待詔赴長安，客裏新正阻舊歡。遲日未能銷野雪，", "共許郤詵工射策，恩榮請向一枝看。"]'),
('yuding-76','賦得荊溪夜湍送蔣逸人歸義興山','皇甫冉','唐','御定全唐诗','yuding','','[]','驚湍流不極，夜度識雲岑。長帶溪沙淺，時因山雨深。',60,'御定全唐詩/json/249.json','["驚湍流不極，夜度識雲岑。長帶溪沙淺，時因山雨深。", "方同七裏路，更遂五湖心。揭厲朝將夕，潺湲古至今。", "花源君若許，雖遠亦相尋。"]'),
('yuding-77','送孔黨赴舉','皇甫冉','唐','御定全唐诗','yuding','','[]','入貢列諸生，詩書業早成。家承孔聖後，身有魯儒名。',48,'御定全唐詩/json/249.json','["入貢列諸生，詩書業早成。家承孔聖後，身有魯儒名。", "楚水通滎浦，春山擁漢京。愛君方弱冠，為賦少年行。"]'),
('yuding-78','齊郎中筵賦得的的帆向浦留別','皇甫冉','唐','御定全唐诗','yuding','','[]','一帆何處去，正在望中微。浦迥搖空色，汀回見落暉。',48,'御定全唐詩/json/249.json','["一帆何處去，正在望中微。浦迥搖空色，汀回見落暉。", "每爭高鳥度，能送遠人歸。偏似南浮客，悠揚無所依。"]'),
('yuding-79','送陸鴻漸棲霞寺採茶','皇甫冉','唐','御定全唐诗','yuding','','[]','採茶非采菉，遠遠上層崖。布葉春風暖，盈筐白日斜。',48,'御定全唐詩/json/249.json','["採茶非采菉，遠遠上層崖。布葉春風暖，盈筐白日斜。", "舊知山寺路，時宿野人家。借問王孫草，何時泛碗花。"]'),
('yuding-80','泊丹陽與諸人同舟至馬林溪遇雨','皇甫冉','唐','御定全唐诗','yuding','','[]','雲林不可望，溪水更悠悠。共載人皆客，離家春是秋。',48,'御定全唐詩/json/249.json','["雲林不可望，溪水更悠悠。共載人皆客，離家春是秋。", "遠山方對枕，細雨莫回舟。來往南徐路，多為芳草留。"]'),
('yuding-81','太常魏博士遠出賊庭江外相逢因敘其事','皇甫冉','唐','御定全唐诗','yuding','','[]','烽火驚戎塞，豺狼犯帝畿。川原無稼穡，日月翳光輝。',144,'御定全唐詩/json/249.json','["烽火驚戎塞，豺狼犯帝畿。川原無稼穡，日月翳光輝。", "裏社枌榆毀，宮城騎吏非。群生被慘毒，雜虜耀輕肥。", "多士從芳餌，唯君識禍機。心同合浦葉，命寄首陽薇。", "恥作纖鱗喣，方隨高鳥飛。山經商嶺出，水泛漢池歸。", "離別霜凝鬢，逢迎淚迸衣。京華長路絕，江海故人稀。", "秉節身常苦，求仁志不違。只應窮野外，耕種且相依。"]'),
('yuding-82','送包佶賦得天津橋','皇甫冉','唐','御定全唐诗','yuding','','[]','洛陽歲暮作征客，□□□□□□□。相望依然一水間，',48,'御定全唐詩/json/249.json','["洛陽歲暮作征客，□□□□□□□。相望依然一水間，", "豈無朝夕軒車度，其奈相逢非所親。鞏樹甘陵愁遠道，"]'),
('yuding-83','上禮部楊侍郎','皇甫冉','唐','御定全唐诗','yuding','','[]','郢匠掄材日，轅輪必盡呈。敢言當一干，徒欲隸諸生。',144,'御定全唐詩/json/249.json','["郢匠掄材日，轅輪必盡呈。敢言當一干，徒欲隸諸生。", "末學慚鄒魯，深仁錄弟兄。餘波知可挹，弱植更求榮。", "績愧他年敗，功期此日成。方因舊桃李，猶冀載飛鳴。", "道淺猶懷分，時移但自驚。關門驚暮節，林壑廢春耕。", "十裏嵩峰近，千秋潁水清。煙花迷戍穀，墟落接陽城。", "渺默思鄉夢，遲回知己情。勞歌終此曲，還是苦辛行。"]'),
('yuding-84','宿嚴維宅送包七','皇甫冉','唐','御定全唐诗','yuding','','[]','江湖同避地，分手自依依。盡室今為客，經秋空念歸。',72,'御定全唐詩/json/249.json','["江湖同避地，分手自依依。盡室今為客，經秋空念歸。", "歲儲無別墅，寒服羨鄰機。草色村橋晚，蟬聲江樹稀。", "夜涼宜共醉，時難惜相違。何事隨陽侶，汀洲忽背飛。"]'),
('yuding-85','同張侍禦詠興甯寺經藏院海石榴花','皇甫冉','唐','御定全唐诗','yuding','','[]','嫩葉生初茂，殘花少更鮮。結根龍藏側，故欲並青蓮。',24,'御定全唐詩/json/249.json','["嫩葉生初茂，殘花少更鮮。結根龍藏側，故欲並青蓮。"]'),
('yuding-86','崔十四宅各賦一物得簷柳','皇甫冉','唐','御定全唐诗','yuding','','[]','官渡老風煙，潯陽媚雲日。漢將營前見，胡笳曲中出。',36,'御定全唐詩/json/249.json','["官渡老風煙，潯陽媚雲日。漢將營前見，胡笳曲中出。", "複在此簷端，垂陰仲長室。"]'),
('yuding-87','送段明府','皇甫冉','唐','御定全唐诗','yuding','','[]','遙夜此何其，霜空殘杳靄。方嗟異鄉別，暫是同公會。',60,'御定全唐詩/json/249.json','["遙夜此何其，霜空殘杳靄。方嗟異鄉別，暫是同公會。", "海林秋更疏，野水寒猶大。離人轉吳岫，旅雁從燕塞。", "日夕望前期，勞心白雲外。"]'),
('yuding-88','送王司直','皇甫冉','唐','御定全唐诗','yuding','','[]','西塞雲山遠，東風道路長。人心勝潮水，相送過潯陽。',24,'御定全唐詩/json/249.json','["西塞雲山遠，東風道路長。人心勝潮水，相送過潯陽。"]'),
('yuding-89','婕妤春怨','皇甫冉','唐','御定全唐诗','yuding','','[]','花枝出建章，鳳管發昭陽。借問承恩者，雙蛾幾許長。',24,'御定全唐詩/json/249.json','["花枝出建章，鳳管發昭陽。借問承恩者，雙蛾幾許長。"]'),
('yuding-90','送魏十六還蘇州','皇甫冉','唐','御定全唐诗','yuding','','[]','秋夜深深北送君，陰蟲切切不堪聞。',32,'御定全唐詩/json/249.json','["秋夜深深北送君，陰蟲切切不堪聞。", "歸舟明日毗陵道，回首姑蘇是白雲。"]'),
('yuding-91','婕妤怨','皇甫冉','唐','御定全唐诗','yuding','','[]','由來詠團扇，今已值秋風。事逐時皆往，恩無日再中。',48,'御定全唐詩/json/249.json','["由來詠團扇，今已值秋風。事逐時皆往，恩無日再中。", "早鴻聞上苑，寒露下深宮。顏色年年謝，相如賦豈工。"]'),
('yuding-92','送客','皇甫冉','唐','御定全唐诗','yuding','','[]','旗鼓軍威重，關山客路賒。待封甘度隴，回首不思家。',48,'御定全唐詩/json/249.json','["旗鼓軍威重，關山客路賒。待封甘度隴，回首不思家。", "城下春山路，營中瀚海沙。河源雖萬里，音信寄來查。"]'),
('yuding-93','秋日東郊作','皇甫冉','唐','御定全唐诗','yuding','','[]','閑看秋水心無事，臥對寒鬆手自栽。廬岳高僧留偈別，',40,'御定全唐詩/json/249.json','["閑看秋水心無事，臥對寒鬆手自栽。廬岳高僧留偈別，", "淺薄將何稱獻納，臨岐終日自遲回。"]'),
('yuding-94','秋夜宿嚴維宅','皇甫冉','唐','御定全唐诗','yuding','','[]','昔聞玄度宅，門向會稽峰。君住東湖下，清風繼舊蹤。',48,'御定全唐詩/json/249.json','["昔聞玄度宅，門向會稽峰。君住東湖下，清風繼舊蹤。", "秋深臨水月，夜半隔山鐘。世故多離別，良宵詎可逢。"]'),
('yuding-95','見諸姬學玉台體','皇甫冉','唐','御定全唐诗','yuding','','[]','豔唱召燕姬，清弦待盧女。由來道姓秦，誰不知家楚。',60,'御定全唐詩/json/249.json','["豔唱召燕姬，清弦待盧女。由來道姓秦，誰不知家楚。", "傳杯見目成，結帶明心許。寧辭玉輦迎，自堪金屋貯。", "朝朝作行雲，襄王迷處所。"]'),
('yuding-96','酬張二倉曹揚子所居見寄兼呈韓郎中','皇甫冉','唐','御定全唐诗','yuding','','[]','孤雲獨鶴自悠悠，別後經年尚泊舟。漁父置詞相借問，',40,'御定全唐詩/json/249.json','["孤雲獨鶴自悠悠，別後經年尚泊舟。漁父置詞相借問，", "莫怪杜門頻乞假，不堪扶病拜龍樓。"]'),
('yuding-97','送安律師','皇甫冉','唐','御定全唐诗','yuding','','[]','出家童子歲，愛此雪山人。長路經千里，孤雲伴一身。',48,'御定全唐詩/json/249.json','["出家童子歲，愛此雪山人。長路經千里，孤雲伴一身。", "水中應見月，草上豈傷春。永日空林下，心將何物親。"]'),
('yuding-98','題盧十一所居','皇甫冉','唐','御定全唐诗','yuding','','[]','春風來幾日，先入辟疆園。身外無餘事，閑吟晝閉門。',24,'御定全唐詩/json/249.json','["春風來幾日，先入辟疆園。身外無餘事，閑吟晝閉門。"]'),
('yuding-99','送陸澧郭鄖','皇甫冉','唐','御定全唐诗','yuding','','[]','才見吳洲百草春，已聞燕雁一聲新。',32,'御定全唐詩/json/249.json','["才見吳洲百草春，已聞燕雁一聲新。", "秋風何處催年急，偏逐山行水宿人。"]'),
('yuding-100','山中橫雲','皇甫冉','唐','御定全唐诗','yuding','','[]','湘水風日滿，楚山朝夕空。連峰雖已見，猶念長雲中。',24,'御定全唐詩/json/249.json','["湘水風日滿，楚山朝夕空。連峰雖已見，猶念長雲中。"]'),
('yuding-101','題裴二十一新園','皇甫冉','唐','御定全唐诗','yuding','','[]','東郭訪先生，西郊尋隱路。久為江南客，自有雲陽樹。',84,'御定全唐詩/json/249.json','["東郭訪先生，西郊尋隱路。久為江南客，自有雲陽樹。", "已得閒園心，不知公府步。開門白日晚，倚杖青山暮。", "果熟任霜封，籬疏從水度。窮年無牽綴，往事惜淪誤。", "唯見耦耕人，朝朝自來去。"]'),
('yuding-102','寄高雲','皇甫冉','唐','御定全唐诗','yuding','','[]','南徐風日好，悵望毗陵道。毗陵有故人，一見恨無因。',84,'御定全唐詩/json/249.json','["南徐風日好，悵望毗陵道。毗陵有故人，一見恨無因。", "獨戀青山久，唯令白髮新。每嫌持手板，時見著頭巾。", "煙景臨寒食，農桑接仲春。家貧仍嗜酒，生事今何有。", "芳草遍江南，勞心憶攜手。"]'),
('yuding-0','溫泉即事','皇甫冉','唐','御定全唐诗','yuding','','[]','天仗星辰轉，霜冬景氣和。樹含溫液潤，山入繚垣多。',48,'御定全唐詩/json/250.json','["天仗星辰轉，霜冬景氣和。樹含溫液潤，山入繚垣多。", "丞相金錢賜，平陽玉輦過。魯儒求一謁，無路獨如何。"]'),
('yuding-1','送張南史','皇甫冉','唐','御定全唐诗','yuding','','[]','馬卿工詞賦，位下年將暮。謝客愛雲山，家貧身不閑。',72,'御定全唐詩/json/250.json','["馬卿工詞賦，位下年將暮。謝客愛雲山，家貧身不閑。", "風波杳未極，幾處逢相識。富貴人皆變，誰能念貧賤。", "岸有經霜草，林有故年枝。俱應待春色，獨使客心悲。"]'),
('yuding-2','廬山歌送至弘法師兼呈薛江州','皇甫冉','唐','御定全唐诗','yuding','','[]','釋子去兮訪名山，禪舟容與兮住仍前。猿啾啾兮怨月，',48,'御定全唐詩/json/250.json','["釋子去兮訪名山，禪舟容與兮住仍前。猿啾啾兮怨月，", "連湘接楚饒桂花，事久年深無杏樹。使君愛人兼愛山，"]'),
('yuding-3','送薛秀才','皇甫冉','唐','御定全唐诗','yuding','','[]','雖是尋山客，還同慢世人。讀書惟務靜，無褐不憂貧。',48,'御定全唐詩/json/250.json','["雖是尋山客，還同慢世人。讀書惟務靜，無褐不憂貧。", "野色春冬樹，雞聲遠近鄰。郤公即吾友，合與爾相親。"]'),
('yuding-4','使往壽州淮路寄劉長卿','皇甫冉','唐','御定全唐诗','yuding','','[]','榛草荒涼村落空，驅馳卒歲亦何功。蒹葭曙色蒼蒼遠，',40,'御定全唐詩/json/250.json','["榛草荒涼村落空，驅馳卒歲亦何功。蒹葭曙色蒼蒼遠，", "日夕煙霜那可道，壽陽西去水無窮。"]'),
('yuding-5','酬李司兵直夜見寄','皇甫冉','唐','御定全唐诗','yuding','','[]','江城聞鼓角，旅宿複何如。寒月此宵半，春風舊歲餘。',48,'御定全唐詩/json/250.json','["江城聞鼓角，旅宿複何如。寒月此宵半，春風舊歲餘。", "徒雲資薄祿，未必勝閒居。見欲扁舟去，誰能畏簡書。"]'),
('yuding-6','送薛判官之越','皇甫冉','唐','御定全唐诗','yuding','','[]','時難自多務，職小亦求賢。道路無辭遠，雲山並在前。',36,'御定全唐詩/json/250.json','["時難自多務，職小亦求賢。道路無辭遠，雲山並在前。", "樟亭待潮處，已是越人煙。"]'),
('yuding-7','同溫丹徒登萬歲樓','皇甫冉','唐','御定全唐诗','yuding','','[]','高樓獨立思依依，極浦遙山合翠微。江客不堪頻北顧，',40,'御定全唐詩/json/250.json','["高樓獨立思依依，極浦遙山合翠微。江客不堪頻北顧，", "聞道王師猶轉戰，誰能談笑解重圍。"]'),
('yuding-8','賦得簷燕','皇甫冉','唐','御定全唐诗','yuding','','[]','拂水競何忙，傍簷如有意。翻風去每遠，帶雨歸偏駛。',36,'御定全唐詩/json/250.json','["拂水競何忙，傍簷如有意。翻風去每遠，帶雨歸偏駛。", "令君裁杏梁，更欲年年去。"]'),
('yuding-9','送李萬州赴饒州覲省','皇甫冉','唐','御定全唐诗','yuding','','[]','前程觀拜慶，舊館惜招攜。荀氏風流遠，胡家清白齊。',72,'御定全唐詩/json/250.json','["前程觀拜慶，舊館惜招攜。荀氏風流遠，胡家清白齊。", "川回吳岫失，塞闊楚雲低。舉目親魚鳥，驚心怯鼓鼙。", "人稀漁浦外，灘淺定山西。無限青青草，王孫去不迷。"]'),
('yuding-10','送鄒判官赴河南','皇甫冉','唐','御定全唐诗','yuding','','[]','看君發原隰，四牡去皇皇。始罷滄江吏，還隨粉署郎。',72,'御定全唐詩/json/250.json','["看君發原隰，四牡去皇皇。始罷滄江吏，還隨粉署郎。", "海沂軍未息，河畔歲仍荒。徵稅人全少，榛蕪虜近亡。", "所行知宋遠，相隔歎淮長。早晚裁書寄，銀鉤佇八行。"]'),
('yuding-11','宿淮陰南樓酬常伯能','皇甫冉','唐','御定全唐诗','yuding','','[]','淮陰日落上南樓，喬木荒城古渡頭。浦外野風初入戶，',40,'御定全唐詩/json/250.json','["淮陰日落上南樓，喬木荒城古渡頭。浦外野風初入戶，", "佇立分宵絕來客，煩君步屐忽相求。"]'),
('yuding-12','送歸中丞使新羅','皇甫冉','唐','御定全唐诗','yuding','','[]','詔使殊方遠，朝儀舊典行。浮天無盡處，望日計前程。',72,'御定全唐詩/json/250.json','["詔使殊方遠，朝儀舊典行。浮天無盡處，望日計前程。", "暫喜孤山出，長愁積水平。野風飄疊鼓，海雨濕危旌。", "異俗知文教，通儒有令名。還將大戴禮，方外授諸生。"]'),
('yuding-13','小江懷靈一上人','皇甫冉','唐','御定全唐诗','yuding','','[]','江上年年春早，津頭日日人行。',28,'御定全唐詩/json/250.json','["江上年年春早，津頭日日人行。", "借問山陰遠近，猶聞薄暮鐘聲。"]'),
('yuding-14','送唐別駕赴郢州','皇甫冉','唐','御定全唐诗','yuding','','[]','莫歎辭家遠，方看佐郡榮。長林通楚塞，高嶺見秦城。',48,'御定全唐詩/json/250.json','["莫歎辭家遠，方看佐郡榮。長林通楚塞，高嶺見秦城。", "雪向嶢關下，人從郢路迎。翩翩駿馬去，自是少年行。"]'),
('yuding-15','送魏中丞還河北','皇甫冉','唐','御定全唐诗','yuding','','[]','甯知貴公子，本是魯諸生。上國風塵舊，中司印綬榮。',36,'御定全唐詩/json/250.json','["甯知貴公子，本是魯諸生。上國風塵舊，中司印綬榮。", "辛勤戎旅事，雪下護羌營。"]'),
('yuding-16','送李使君赴邵州','皇甫冉','唐','御定全唐诗','yuding','','[]','出送東方騎，行安南楚人。城池春足雨，風俗夜迎神。',48,'御定全唐詩/json/250.json','["出送東方騎，行安南楚人。城池春足雨，風俗夜迎神。", "郢路逢歸客，湘川問去津。爭看使君度，皂蓋雪中新。"]'),
('yuding-17','寄振上人無礙寺所居','皇甫冉','唐','御定全唐诗','yuding','','[]','戀親時見在人群，多在東山就白雲。',32,'御定全唐詩/json/250.json','["戀親時見在人群，多在東山就白雲。", "獨坐焚香誦經處，深山古寺雪紛紛。"]'),
('yuding-18','酬李補闕','皇甫冉','唐','御定全唐诗','yuding','','[]','十年歸客但心傷，三徑無人已自荒。夕宿靈台伴煙月，',40,'御定全唐詩/json/250.json','["十年歸客但心傷，三徑無人已自荒。夕宿靈台伴煙月，", "縱有諫書猶未獻，春風拂地日空長。"]'),
('yuding-19','故齊王贈承天皇帝挽歌','皇甫冉','唐','御定全唐诗','yuding','','[]','禮盛追崇日，人知友悌恩。舊居從代邸，新隴入文園。',48,'御定全唐詩/json/250.json','["禮盛追崇日，人知友悌恩。舊居從代邸，新隴入文園。", "鴻寶仙書秘，龍旗帝服尊。蒼蒼松裏月，萬古此高原。"]'),
('yuding-20','贈恭順皇后挽歌','皇甫冉','唐','御定全唐诗','yuding','','[]','徂謝年方久，哀榮事獨稀。雖殊百兩迓，同是九泉歸。',48,'御定全唐詩/json/250.json','["徂謝年方久，哀榮事獨稀。雖殊百兩迓，同是九泉歸。", "詔使歸金策，神人送玉衣。空山竟不從，寧肯學湘妃。"]'),
('yuding-21','病中對石竹花','皇甫冉','唐','御定全唐诗','yuding','','[]','散點空階下，閑凝細雨中。那能久相伴，嗟爾殢秋風。',24,'御定全唐詩/json/250.json','["散點空階下，閑凝細雨中。那能久相伴，嗟爾殢秋風。"]'),
('yuding-22','寄鄭二侍禦歸新鄭無礙寺所居','皇甫冉','唐','御定全唐诗','yuding','','[]','何事休官早，歸來作鄭人。雲山隨伴侶，伏臘見鄉親。',48,'御定全唐詩/json/250.json','["何事休官早，歸來作鄭人。雲山隨伴侶，伏臘見鄉親。", "南畝無三徑，東林寄一身。誰當便靜者，莫使甑生塵。"]'),
('yuding-23','送廬山人歸林慮山','皇甫冉','唐','御定全唐诗','yuding','','[]','無論行遠近，歸向舊煙林。寥落人家少，青冥鳥道深。',48,'御定全唐詩/json/250.json','["無論行遠近，歸向舊煙林。寥落人家少，青冥鳥道深。", "白雲長滿目，芳草自知心。山色連東海，相思何處尋。"]'),
('yuding-24','送榮別駕赴華州','皇甫冉','唐','御定全唐诗','yuding','','[]','直到群峰下，應無累日程。高車入郡舍，流水出關城。',48,'御定全唐詩/json/250.json','["直到群峰下，應無累日程。高車入郡舍，流水出關城。", "草色田家迥，槐陰府吏迎。還將海沂詠，籍甚漢公卿。"]'),
('yuding-25','送常大夫加散騎常侍赴朔方','皇甫冉','唐','御定全唐诗','yuding','','[]','故壘煙塵後，新軍河塞間。金貂寵漢將，玉節度蕭關。',48,'御定全唐詩/json/250.json','["故壘煙塵後，新軍河塞間。金貂寵漢將，玉節度蕭關。", "澶漫沙中雪，依稀漢口山。人知竇車騎，計日勒銘還。"]'),
('yuding-26','送王翁信還剡中舊居','皇甫冉','唐','御定全唐诗','yuding','','[]','海岸耕殘雪，溪沙釣夕陽。客中何所有，春草漸看長。',24,'御定全唐詩/json/250.json','["海岸耕殘雪，溪沙釣夕陽。客中何所有，春草漸看長。"]');
